INSERT INTO public.questions VALUES ('d27eec9f-8a59-4aad-ae5d-a2dded32e1a1', '91b576e0-3358-4249-bc84-e6d5e9eaeb68', 'checkbox', 'Questions 21–22', NULL, '<p>Choose <strong>TWO</strong> correct answers.</p>
<p>Which <strong>TWO</strong> of the following statements are true of the ‘claque’ in France?</p>
', 'multiple_choice_many', 'null', '[{"option": "As a practice in France, it first appeared in the 16th century.", "correct": true}, {"option": "It did not become a widespread practice within France.", "correct": false}, {"option": "The cost of hire depended on the fame of the client.", "correct": false}, {"option": "Claqueurs were divided into different categories.", "correct": true}, {"option": "The practice did not extend beyond France to other countries.", "correct": false}]', 'null', 'null', '[{"content": "<p data-path-to-node=\"1\"><strong data-path-to-node=\"1\" data-index-in-node=\"0\">21. As a practice in France, it first appeared in the 16th century.</strong></p>\n<ul data-path-to-node=\"2\">\n<li>\n<p data-path-to-node=\"2,0,0\"><strong data-path-to-node=\"2,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 5, dòng 1–3.</p>\n</li>\n<li>\n<p data-path-to-node=\"2,1,0\"><strong data-path-to-node=\"2,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “16th-century French poet Jean Daurat is credited with <strong data-path-to-node=\"2,1,0\" data-index-in-node=\"66\">bringing back the Roman practice</strong> of hiring professional applauders. In France, this group became known as a ‘claque’.”</p>\n</li>\n<li>\n<p data-path-to-node=\"2,2,0\"><strong data-path-to-node=\"2,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc xác nhận rằng hình thức thuê người vỗ tay chuyên nghiệp (claque) bắt đầu xuất hiện trở lại tại Pháp vào thế kỷ 16 nhờ công của nhà thơ Jean Daurat. Đây là mốc thời gian đầu tiên mà hoạt động này được ghi nhận tại quốc gia này.</p>\n</li>\n</ul>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">22. Claqueurs were divided into different categories.</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 5, dòng 9–13.</p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “The claque also underwent a kind of <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"48\">classification</strong>: the <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"68\">rieurs</strong> (laughers)… the <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"93\">pleureurs</strong> (criers)… the <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"119\">commissaires</strong> (officers)…”</p>\n</li>\n<li>\n<p data-path-to-node=\"4,2,0\"><strong data-path-to-node=\"4,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Những người vỗ tay thuê (claqueurs) không chỉ làm một nhiệm vụ duy nhất mà được phân loại thành nhiều nhóm chuyên biệt: nhóm chuyên cười lớn (rieurs), nhóm giả vờ khóc (pleureurs) hay nhóm chuyên ghi nhớ tác phẩm để điều hướng sự chú ý của khán giả (commissaires). Điều này khớp hoàn toàn với ý “được chia thành các danh mục/loại khác nhau” trong câu hỏi.</p>\n</li>\n</ul>\n"}]', 1);
INSERT INTO public.questions VALUES ('10508e44-d812-44aa-96bf-01bbeda50562', '91b576e0-3358-4249-bc84-e6d5e9eaeb68', 'fillup', 'Questions 23–26', '<p>Complete the sentences. Write <strong>ONE WORD ONLY</strong> from the text for each answer.</p>
<p>In the 18th century, people could show their superiority by understanding when either {silence} or applause was appropriate.</p>
<p>Performers in the 18th century, in particular those singing in the {opera}, no longer had a meaningful dialogue with their audiences.</p>
<p>In the 19th century, applause was no longer offered as a {reward} to performers.</p>
<p>Nowadays our expressions of approval are seen as {permanent} in comparison to the applause of the past.</p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"1\"><strong data-path-to-node=\"1\" data-index-in-node=\"0\">23. silence</strong></p>\n<ul data-path-to-node=\"2\">\n<li>\n<p data-path-to-node=\"2,0,0\"><strong data-path-to-node=\"2,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 6, dòng 3–5.</p>\n</li>\n<li>\n<p data-path-to-node=\"2,1,0\"><strong data-path-to-node=\"2,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Knowing when to maintain <strong data-path-to-node=\"2,1,0\" data-index-in-node=\"37\">silence</strong>, as well as when to clap, became a mark of sophistication, a kind of code for audiences to learn.”</p>\n</li>\n<li>\n<p data-path-to-node=\"2,2,0\"><strong data-path-to-node=\"2,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Trong thế kỷ 18, việc hiểu rõ các quy tắc ứng xử — cụ thể là biết lúc nào nên giữ sự im lặng và lúc nào nên vỗ tay — được xem là minh chứng cho sự tinh tế và vị thế của khán giả. Cụm “show their superiority” trong câu hỏi tương ứng với “mark of sophistication” trong bài.</p>\n</li>\n</ul>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">24. opera</strong></p>\n<ul data-path-to-node=\"4\">\n<li>\n<p data-path-to-node=\"4,0,0\"><strong data-path-to-node=\"4,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 6, dòng 6–8.</p>\n</li>\n<li>\n<p data-path-to-node=\"4,1,0\"><strong data-path-to-node=\"4,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Applause became much less of a true dialogue with an audience, especially so with <strong data-path-to-node=\"4,1,0\" data-index-in-node=\"94\">opera</strong>, where the singers saw it as part of a basic transaction with the crowd.”</p>\n</li>\n<li>\n<p data-path-to-node=\"4,2,0\"><strong data-path-to-node=\"4,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả nhấn mạnh rằng sự tương tác thực sự giữa nghệ sĩ và khán giả đã giảm dần, đặc biệt là trong loại hình nhạc kịch (<strong data-path-to-node=\"4,2,0\" data-index-in-node=\"133\">opera</strong>). Ở đó, các ca sĩ coi tiếng vỗ tay chỉ là một phần của sự trao đổi cơ bản thay vì là một cuộc đối thoại tinh thần.</p>\n</li>\n</ul>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">25. reward</strong></p>\n<ul data-path-to-node=\"6\">\n<li>\n<p data-path-to-node=\"6,0,0\"><strong data-path-to-node=\"6,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 6, câu cuối.</p>\n</li>\n<li>\n<p data-path-to-node=\"6,1,0\"><strong data-path-to-node=\"6,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…applause had become standardized and institutionalized, and had become an expectation rather than the <strong data-path-to-node=\"6,1,0\" data-index-in-node=\"117\">reward</strong> it used to be.”</p>\n</li>\n<li>\n<p data-path-to-node=\"6,2,0\"><strong data-path-to-node=\"6,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Bước sang thế kỷ 19, tiếng vỗ tay đã trở thành một quy chuẩn và là điều mặc định phải có. Nó không còn mang ý nghĩa là một phần thưởng dành cho sự nỗ lực hay tài năng của nghệ sĩ như trong quá khứ.</p>\n</li>\n</ul>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">26. permanent</strong></p>\n<ul data-path-to-node=\"8\">\n<li>\n<p data-path-to-node=\"8,0,0\"><strong data-path-to-node=\"8,0,0\" data-index-in-node=\"0\">Vị trí:</strong> Đoạn 7, câu cuối.</p>\n</li>\n<li>\n<p data-path-to-node=\"8,1,0\"><strong data-path-to-node=\"8,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…our kind of applause matters more now, in many ways, because it is no longer momentary and short-lived, but is far more <strong data-path-to-node=\"8,1,0\" data-index-in-node=\"135\">permanent</strong> instead.”</p>\n</li>\n<li>\n<p data-path-to-node=\"8,2,0\"><strong data-path-to-node=\"8,2,0\" data-index-in-node=\"0\">Giải thích:</strong> Trong thời đại kỹ thuật số, các hình thức tán thưởng trực tuyến được coi là có sức nặng hơn vì chúng mang tính lâu dài và vĩnh viễn. Điều này đối lập hoàn toàn với tiếng vỗ tay truyền thống vốn chỉ vang lên nhất thời rồi biến mất.</p>\n</li>\n</ul>\n<p data-path-to-node=\"9\">\n"}]', 2);
INSERT INTO public.questions VALUES ('c6f7d0f1-965d-4435-a741-8030b356468b', 'ca611357-30cd-4347-aaed-ba35fd9d4cab', 'matrix', 'Questions 27–31', '', '<p><span class="citation-8681">Which paragraph contains the following information?</span></p>
<p><span class="citation-8681">Write the correct letter, </span><strong data-path-to-node="8" data-index-in-node="139"><span class="citation-8681">A–H</span></strong><span class="citation-8681 citation-end-8681">, in boxes 27–31 on your answer sheet.</span></p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "simple", "matrixItems": [{"itemText": "The fact that there may be too much information to cope with", "correctCategoryLetter": "F"}, {"itemText": "The relevance of generating repeat business", "correctCategoryLetter": "A"}, {"itemText": "An example of personalised marketing", "correctCategoryLetter": "B"}, {"itemText": "An illustration of a situation where commissioning new information research might not be advisable", "correctCategoryLetter": "H"}, {"itemText": "How the greater wealth of customers enables them to select from a broader range of products", "correctCategoryLetter": "D"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}, {"categoryText": "H", "categoryLetter": "H"}]}', '[{"content": "<p data-path-to-node=\"4\"><strong class=\"\" data-path-to-node=\"4\" data-index-in-node=\"0\">27. The fact that there may be too much information to cope with — {F}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong class=\"\" data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> “…</span><span class=\"\">a packaged-goods product controller is </span><strong class=\"\" data-path-to-node=\"5,0,0\" data-index-in-node=\"54\">bombarded with one million to one billion new numbers</strong><span class=\"\"> each week.</span><span class=\"\"> …</span><span class=\"\">‘Running out of information is not a problem,</span><span class=\"\"> but </span><strong class=\"\" data-path-to-node=\"5,0,0\" data-index-in-node=\"172\">drowning in it</strong><span class=\"\"> is.</span><span class=\"\">‘”</span></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong class=\"\" data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Đoạn F mô tả tình trạng quá tải thông tin (too much information),</span><span class=\"\"> nơi người quản lý bị “tấn công” bởi hàng tỷ con số.</span></p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong class=\"\" data-path-to-node=\"6\" data-index-in-node=\"0\">28. The relevance of generating repeat business — {A}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong class=\"\" data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> “…</span><span class=\"\">customers must see value in </span><strong class=\"\" data-path-to-node=\"7,0,0\" data-index-in-node=\"43\">returning continually to the stores</strong><span class=\"\"> where they shop…</span><span class=\"\">“</span></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong class=\"\" data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> “Returning continually” (quay lại liên tục) chính là việc tạo ra các giao dịch lặp lại (repeat business),</span><span class=\"\"> thay vì chỉ bán được một lần duy nhất.</span></p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong class=\"\" data-path-to-node=\"8\" data-index-in-node=\"0\">29. An example of personalised marketing — {B}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong class=\"\" data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> “…</span><span class=\"\">Channel [V] encourages its viewers to sign up for text messages and email alerts that tell them when </span><strong class=\"\" data-path-to-node=\"9,0,0\" data-index-in-node=\"116\">their favourite artists and songs</strong><span class=\"\"> are about to be broadcast.</span><span class=\"\">“</span></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong class=\"\" data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Đây là ví dụ về marketing cá nhân hóa (personalized),</span><span class=\"\"> dựa trên sở thích cụ thể của từng khách hàng để gửi thông báo.</span></p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong class=\"\" data-path-to-node=\"10\" data-index-in-node=\"0\">30. An illustration of a situation where commissioning new research might not be advisable — {H}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong class=\"\" data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> “…</span><span class=\"\">it would be </span><strong class=\"\" data-path-to-node=\"11,0,0\" data-index-in-node=\"27\">foolish to spend $30,000</strong><span class=\"\"> for additional information that would increase the profit to only $525,</span><span class=\"\">000 [from $500,</span><span class=\"\">000].</span><span class=\"\">“</span></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong class=\"\" data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Đoạn H đưa ra ví dụ về chi phí nghiên cứu ($30k) cao hơn lợi nhuận tăng thêm ($25k),</span><span class=\"\"> do đó việc thực hiện nghiên cứu là không nên (not advisable).</span></p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong class=\"\" data-path-to-node=\"12\" data-index-in-node=\"0\">31. How the greater wealth of customers enables them to select from a broader range — {D}</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong class=\"\" data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> “As </span><strong class=\"\" data-path-to-node=\"13,0,0\" data-index-in-node=\"15\">household incomes increase</strong><span class=\"\">,</span> <strong class=\"\" data-path-to-node=\"13,0,0\" data-index-in-node=\"43\">choice widens</strong><span class=\"\"> and buyers become better at discriminating…</span><span class=\"\">“</span></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Thu nhập hộ gia đình tăng (greater wealth) dẫn đến sự lựa chọn mở rộng (broader range/choice widens).</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('873ea750-1b69-4995-80ec-aa4e03a817e5', '74e02f7d-c30a-456e-9520-be5078b82771', 'fillup', 'Questions 9-13', '<p data-path-to-node="7">Complete the notes below.</p>
<p data-path-to-node="7">Choose <strong data-path-to-node="7" data-index-in-node="33">ONE WORD ONLY</strong> from the passage for each answer.</p>
<p data-path-to-node="8"><span style="font-size: 14pt;"><strong data-path-to-node="8" data-index-in-node="0">How hooks changed after Europeans arrived</strong></span></p>
<p data-path-to-node="9"><strong data-path-to-node="9" data-index-in-node="0">After 1700s</strong></p>
<ul data-path-to-node="10">
<li>
<p data-path-to-node="10,0,0">They abandoned their previous hooks.</p>
</li>
<li>
<p data-path-to-node="10,1,0">Some valued hooks are made into {jewelry}</p>
</li>
</ul>
<p data-path-to-node="11"><strong data-path-to-node="11" data-index-in-node="0">After 1800s</strong></p>
<ul data-path-to-node="12">
<li>
<p data-path-to-node="12,0,0">Mass production makes production cheaper and Maoris import more.</p>
</li>
<li>
<p data-path-to-node="12,1,0">The difficulty associated with the material like {nails} and other metals makes the hooks production less.</p>
</li>
</ul>
<p data-path-to-node="13"><strong data-path-to-node="13" data-index-in-node="0">After 1900s</strong></p>
<ul data-path-to-node="14">
<li>
<p data-path-to-node="14,0,0">Some {collectors} were again interested in hooks.</p>
</li>
<li>
<p data-path-to-node="14,1,0">Many hooks are {fake} which can be identified easily.</p>
</li>
</ul>
<p data-path-to-node="15"><strong data-path-to-node="15" data-index-in-node="0">Conclusion</strong></p>
<ul data-path-to-node="16">
<li>
<p data-path-to-node="16,0,0">We can find the hooks’ design of old times today on {boats}</p>
</li>
</ul>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">9. jewelry — {Some valued hooks are made into jewelry}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 5):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">“…crafting hooks that were later taken into luxury markets and sold as <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"93\">jewelry</strong>, blurring the line between utility and art.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Những chiếc lưỡi câu làm từ vật liệu quý hiếm (như ngà voi hay đá ngọc bích) đã được đưa vào thị trường xa xỉ và bán như đồ trang sức (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"147\">jewelry</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">10. nails — {The difficulty associated with the material like nails… makes the hooks production less}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 6):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">“…the production of traditional Māori hooks declined due to the <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"86\">nails</strong> and other metallic materials required, which were difficult to manipulate…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc sản xuất lưỡi câu truyền thống bị giảm sút (less) do các vật liệu kim loại như đinh (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"102\">nails</strong>) rất khó để chế tác nếu không có dụng cụ chuyên dụng.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">11. collectors — {Some collectors were again interested in hooks}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 6):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">“…interest in Pacific culture grew, and <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"62\">collectors</strong> began to seek out original Māori fishing hooks once again.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Vào đầu những năm 1900, những nhà sưu tập (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"55\">collectors</strong>) bắt đầu quan tâm và tìm kiếm lại những chiếc lưỡi câu Māori nguyên bản.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">12. fake — {Many hooks are fake which can be identified easily}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 6):</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"20\">“Unfortunately, the demand also led to a wave of imitations—many of the hooks appearing on the market today are <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"132\">fake</strong>, though they can usually be <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"165\">identified by their inconsistent design</strong>…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Do nhu cầu cao nên xuất hiện nhiều hàng nhái, hàng giả (<strong data-path-to-node=\"11,1,0\" data-index-in-node=\"68\">fake</strong>), nhưng chúng có thể được nhận biết dễ dàng qua sự thiếu nhất quán trong thiết kế và chất liệu.</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">13. boats — {We can find the hooks’ design of old times today on boats}</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 7):</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"20\">“…many hooks found on <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"44\">boats</strong> in New Zealand today still bear a striking resemblance to the ancient forms…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Một minh chứng cho sự trường tồn của thiết kế Māori là ngày nay trên các con tàu/thuyền (<strong data-path-to-node=\"13,1,0\" data-index-in-node=\"101\">boats</strong>), người ta vẫn thấy những chiếc lưỡi câu mang hình dáng giống hệt các mẫu cổ xưa.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('9330a119-4221-4bac-9e19-61b8d3905fc9', 'ca611357-30cd-4347-aaed-ba35fd9d4cab', 'radio', 'Questions 32–36', '', '<p id="p-rc_c04c5eb7f956289a-175" data-path-to-node="13,0,0"><span class="citation-8676">Choose </span><strong data-path-to-node="13,0,0" data-index-in-node="0"><span class="citation-8676">YES</span></strong><span class="citation-8676 citation-end-8676"> if the statement agrees with the claims of the writer,</span><strong data-path-to-node="13,1,0" data-index-in-node="0"><span class="citation-8675">NO</span></strong><span class="citation-8675 citation-end-8675"> if the statement contradic</span>ts the claims of the writer,<strong data-path-to-node="13,2,0" data-index-in-node="0">NOT GIVEN</strong> if it is impossible to say what the writer thinks about this</p>', 'yes_no_not_given', '[{"correct": 1, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "The majority of marketing statistics are gathered by government agencies."}, {"correct": 2, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "The move from an industrial to an information-based economy has happened more quickly in New Zealand than in Australia."}, {"correct": 0, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Employees sometimes hide information that gives a poor impression of them."}, {"correct": 0, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Managers frequently fail to make good use of the information they receive."}, {"correct": 0, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Marketing information has to be used to be valuable."}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">32. The majority of marketing statistics are gathered by government agencies. — {NO}</strong></p>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong data-path-to-node=\"17,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “While some of the information… is gathered by government bodies… <strong data-path-to-node=\"17,0,0\" data-index-in-node=\"81\">most of it is purposefully gathered by marketing organisations</strong>…” (Đoạn C)</p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong data-path-to-node=\"17,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc nói “phần lớn” (most) do các tổ chức marketing thu thập, không phải do cơ quan chính phủ.</p>\n</li>\n</ul>\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">33. The move to an information economy happened more quickly in NZ than in Australia. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"19\">\n<li>\n<p data-path-to-node=\"19,0,0\"><strong data-path-to-node=\"19,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “the United States and, by observation, developed countries such as <strong data-path-to-node=\"19,0,0\" data-index-in-node=\"79\">Australia, New Zealand and Singapore</strong> are moving from industrial to information-based economies.” (Đoạn E)</p>\n</li>\n<li>\n<p data-path-to-node=\"19,1,0\"><strong data-path-to-node=\"19,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc liệt kê cả hai nước đang chuyển đổi, nhưng <strong data-path-to-node=\"19,1,0\" data-index-in-node=\"63\">không có sự so sánh</strong> nào về tốc độ nhanh hay chậm giữa chúng.</p>\n</li>\n</ul>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">34. Employees sometimes hide information that gives a poor impression of them. — {YES}</strong></p>\n<ul data-path-to-node=\"21\">\n<li>\n<p data-path-to-node=\"21,0,0\"><strong data-path-to-node=\"21,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “…subordinates may <strong data-path-to-node=\"21,0,0\" data-index-in-node=\"32\">withhold information</strong> they believe will <strong data-path-to-node=\"21,0,0\" data-index-in-node=\"71\">reflect badly on their performance</strong>…” (Đoạn F)</p>\n</li>\n<li>\n<p data-path-to-node=\"21,1,0\"><strong data-path-to-node=\"21,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Subordinates” (cấp dưới/nhân viên) giấu thông tin ảnh hưởng xấu đến thành tích của họ.</p>\n</li>\n</ul>\n<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">35. Managers frequently fail to make good use of the information they receive. — {YES}</strong></p>\n<ul data-path-to-node=\"23\">\n<li>\n<p data-path-to-node=\"23,0,0\"><strong data-path-to-node=\"23,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Although marketing organisations have greater capacity… they <strong data-path-to-node=\"23,0,0\" data-index-in-node=\"75\">often do not use it well</strong>.” (Đoạn F)</p>\n</li>\n<li>\n<p data-path-to-node=\"23,1,0\"><strong data-path-to-node=\"23,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Often do not use it well” khớp với “frequently fail to make good use”.</p>\n</li>\n</ul>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">36. Marketing information has to be used to be valuable. — {YES}</strong></p>\n<ul data-path-to-node=\"25\">\n<li>\n<p data-path-to-node=\"25,0,0\"><strong data-path-to-node=\"25,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “By itself, information is valueless – <strong data-path-to-node=\"25,0,0\" data-index-in-node=\"50\">its value comes from its use</strong>.” (Đoạn H)</p>\n</li>\n<li>\n<p data-path-to-node=\"25,1,0\"><strong data-path-to-node=\"25,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Thông tin chỉ có giá trị khi được sử dụng.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('c8ee884b-c74e-4642-a0a9-fb7d82348f7e', 'ca611357-30cd-4347-aaed-ba35fd9d4cab', 'fillup', 'Questions 37–40', '<p>Complete the flow-chart below.</p>
<p>Choose <strong>NO MORE THAN TWO WORDS</strong> from the passage for each answer.</p>
<p>Write your answers in boxes 37–40 on your answer sheet.</p>
<p style="text-align: center;" data-path-to-node="18"><span style="font-size: 14pt;"><strong>The Marketing Information System (MIS)</strong></span></p>
<table style="border-collapse: collapse; width: 89.836%; height: 341.35px; border-spacing: 1px; border: 1px solid rgb(0, 0, 0);" border="1"><colgroup><col style="width: 23.6777%;"><col style="width: 4.98477%;"><col style="width: 35.1703%;"><col style="width: 11.9081%;"><col style="width: 24.2315%;"></colgroup>
<tbody>
<tr style="height: 170.8px;">
<td style="border-width: 1px; padding-top: 1px; padding-right: 1px; padding-bottom: 1px; border-color: #000000;" rowspan="3">
<p> </p>
<p> </p>
<p> </p>
<p>{marketing managers}</p>
</td>
<td style="border-width: 1px; padding: 1px; border-color: #000000; text-align: center;">
<p><span style="font-size: 14pt;"> </span></p>
<p><span style="font-size: 14pt;">▶️</span></p>
</td>
<td style="border-width: 1px; padding: 1px; border-color: #000000;">
<p> Find out their { information needs}</p>
</td>
<td style="border-width: 1px; padding-top: 1px; padding-right: 1px; padding-bottom: 1px; border-color: #000000; text-align: center;">
<p style="text-align: center;"> </p>
<p style="text-align: center;"><span style="font-size: 14pt;">▶️</span></p>
</td>
<td style="border-width: 1px; padding: 1px; border-color: #000000;">
<p> Developed through:</p>
<ul>
<li>{internal records}</li>
<li>marketing intelligence activities</li>
<li>research process</li>
</ul>
</td>
</tr>
<tr style="height: 33.375px;">
<td style="border-width: 1px; padding: 1px; border-color: #000000;" colspan="3"> </td>
<td style="border-width: 1px; padding: 1px; border-color: #000000; text-align: center;"><span style="font-size: 14pt;">🔽</span></td>
</tr>
<tr style="height: 137.175px;">
<td style="border-width: 1px; padding: 1px; border-color: #000000; text-align: center;">
<p><span style="font-size: 14pt;"> </span></p>
<p><span style="font-size: 14pt;">◀️</span></p>
</td>
<td style="border-width: 1px; padding: 1px; border-color: #000000;">
<p> Timely and accurate data distribution</p>
</td>
<td style="border-width: 1px; padding: 1px; border-color: #000000; text-align: center;">
<p> </p>
<p><span style="font-size: 14pt;">◀️</span></p>
</td>
<td style="border-width: 1px; padding: 1px; border-color: #000000;">
<p> Processed by the {analysis unit}</p>
</td>
</tr>
</tbody>
</table>
<p> </p>
<p> </p>
<p> </p>', '', 'short_answer', 'null', 'null', 'null', 'null', '[{"content": "<ul data-path-to-node=\"3\">\n<li>\n<p data-path-to-node=\"3,0,0\"><strong data-path-to-node=\"3,0,0\" data-index-in-node=\"0\">37. {marketing managers}</strong></p>\n<ul data-path-to-node=\"3,0,1\">\n<li>\n<p data-path-to-node=\"3,0,1,0,0\"><strong data-path-to-node=\"3,0,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “The MIS <strong data-path-to-node=\"3,0,1,0,0\" data-index-in-node=\"20\">begins and ends with marketing managers</strong>.” (Đoạn G)</p>\n</li>\n<li>\n<p data-path-to-node=\"3,0,1,1,0\"><strong data-path-to-node=\"3,0,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Sơ đồ bắt đầu từ đối tượng trung tâm là các <strong data-path-to-node=\"3,0,1,1,0\" data-index-in-node=\"56\">nhà quản trị marketing</strong>. Họ là người khơi mào quy trình và cũng là người nhận kết quả cuối cùng.</p>\n</li>\n</ul>\n</li>\n<li>\n<p data-path-to-node=\"3,1,0\"><strong data-path-to-node=\"3,1,0\" data-index-in-node=\"0\">38. Find out their {information needs}</strong></p>\n<ul data-path-to-node=\"3,1,1\">\n<li>\n<p data-path-to-node=\"3,1,1,0,0\"><strong data-path-to-node=\"3,1,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “First, it interacts with these managers to <strong data-path-to-node=\"3,1,1,0,0\" data-index-in-node=\"55\">assess the information needs</strong> they have.” (Đoạn G)</p>\n</li>\n<li>\n<p data-path-to-node=\"3,1,1,1,0\"><strong data-path-to-node=\"3,1,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bước đầu tiên của hệ thống là tương tác với các quản lý để đánh giá/tìm hiểu xem họ đang cần những thông tin gì (<strong data-path-to-node=\"3,1,1,1,0\" data-index-in-node=\"125\">information needs</strong>).</p>\n</li>\n</ul>\n</li>\n<li>\n<p data-path-to-node=\"3,2,0\"><strong data-path-to-node=\"3,2,0\" data-index-in-node=\"0\">39. Developed through: {internal records}</strong></p>\n<ul data-path-to-node=\"3,2,1\">\n<li>\n<p data-path-to-node=\"3,2,1,0,0\"><strong data-path-to-node=\"3,2,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “Next, it develops the needed information from <strong data-path-to-node=\"3,2,1,0,0\" data-index-in-node=\"58\">internal records</strong>, marketing intelligence activities and the research process.” (Đoạn G)</p>\n</li>\n<li>\n<p data-path-to-node=\"3,2,1,1,0\"><strong data-path-to-node=\"3,2,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Sau khi biết nhu cầu, hệ thống sẽ thu thập dữ liệu từ 3 nguồn: (1) <strong data-path-to-node=\"3,2,1,1,0\" data-index-in-node=\"79\">Hồ sơ nội bộ (internal records)</strong>, (2) hoạt động tình báo marketing và (3) quy trình nghiên cứu.</p>\n</li>\n</ul>\n</li>\n<li>\n<p data-path-to-node=\"3,3,0\"><strong data-path-to-node=\"3,3,0\" data-index-in-node=\"0\">40. Processed by the {analysis unit}</strong></p>\n<ul data-path-to-node=\"3,3,1\">\n<li>\n<p data-path-to-node=\"3,3,1,0,0\"><strong data-path-to-node=\"3,3,1,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> “The <strong data-path-to-node=\"3,3,1,0,0\" data-index-in-node=\"16\">analysis unit</strong> processes the data to make it more useful…” (Đoạn G)</p>\n</li>\n<li>\n<p data-path-to-node=\"3,3,1,1,0\"><strong data-path-to-node=\"3,3,1,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Dữ liệu thô sau khi thu thập sẽ được xử lý bởi <strong data-path-to-node=\"3,3,1,1,0\" data-index-in-node=\"59\">bộ phận phân tích (analysis unit)</strong> để trở nên có ích hơn trước khi gửi lại cho các nhà quản lý.</p>\n</li>\n</ul>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('d244155c-eb59-4519-a6f7-87d42c61661b', '5718598c-7700-4916-99d6-69b91fa469bc', 'fillup', 'Questions 1–10', '<div class="quests-inner-desc">
<div class="txt">
<p>Complete the note below</p>
<p>Write <strong>ONE WORD AND/OR A NUMBER</strong> for each answer.</p>
</div>
</div>
<div class="quests-des">
<div class="content-write">
<table class="quill-better-table choice-table" style="border-collapse: collapse; border: 1px solid #000000; border-spacing: 1px;" border="1"><colgroup> <col width="696"> </colgroup>
<tbody>
<tr data-row="row-2zcw">
<td style="border-width: 1px; border-color: #000000; padding: 1px;" data-row="row-2zcw">
<p class="qlbt-cell-line ql-align-center" data-row="row-2zcw" data-cell="cell-jkqg" data-rowspan="1" data-colspan="1"><span style="font-size: 14pt;"><strong>Campsite Reservation Form</strong></span></p>
</td>
</tr>
<tr data-row="row-6gyt">
<td style="border-width: 1px; border-color: #000000; padding: 1px;" data-row="row-6gyt">
<p class="qlbt-cell-line" data-row="row-6gyt" data-cell="cell-rabp" data-rowspan="1" data-colspan="1"><strong>Name:</strong> Sandra Kemp</p>
<p class="qlbt-cell-line" data-row="row-6gyt" data-cell="cell-rabp" data-rowspan="1" data-colspan="1"><strong>Park region: </strong>{Southern} California</p>
<p class="qlbt-cell-line" data-row="row-6gyt" data-cell="cell-rabp" data-rowspan="1" data-colspan="1"><strong>Campground name: </strong>{Mountain} Campground</p>
<p class="qlbt-cell-line" data-row="row-6gyt" data-cell="cell-rabp" data-rowspan="1" data-colspan="1"><strong>Type of site:</strong> {tent}</p>
<p class="qlbt-cell-line" data-row="row-6gyt" data-cell="cell-rabp" data-rowspan="1" data-colspan="1"><strong>Type of vehicle: </strong>will be driving a <span class="fill-history-correct">{truck}</span></p>
<p class="qlbt-cell-line" data-row="row-6gyt" data-cell="cell-rabp" data-rowspan="1" data-colspan="1"><strong>Licence plate number</strong> <span class="fill-history-correct">{QY0918}</span></p>
<p class="qlbt-cell-line" data-row="row-6gyt" data-cell="cell-rabp" data-rowspan="1" data-colspan="1"><strong><span class="note-highlight" data-highlight-idx="1" data-hilight-id="hquest_cjm163">Number of nights:</span></strong> tw<span class="note-highlight" data-highlight-idx="2" data-hilight-id="hquest_cjm360">o</span></p>
<p class="qlbt-cell-line" data-row="row-6gyt" data-cell="cell-rabp" data-rowspan="1" data-colspan="1"><strong><span class="note-highlight" data-highlight-idx="4" data-hilight-id="hquest_cjm407">Departure date:</span></strong> <span class="note-highlight" data-highlight-idx="5" data-hilight-id="hquest_cjm52">{April 12th| April 12 | 12th April | 12 April }</span></p>
</td>
</tr>
<tr data-row="row-mdys">
<td style="border-width: 1px; border-color: #000000; padding: 1px;" data-row="row-mdys">
<p class="qlbt-cell-line" data-row="row-mdys" data-cell="cell-0ttv" data-rowspan="1" data-colspan="1"><strong>Bear-proof food container:</strong> size required : <span class="fill-history-correct">{small}</span></p>
<p class="qlbt-cell-line" data-row="row-mdys" data-cell="cell-0ttv" data-rowspan="1" data-colspan="1"><strong>Type of nature walk booked: </strong>the {flower} walk</p>
<p class="qlbt-cell-line" data-row="row-mdys" data-cell="cell-0ttv" data-rowspan="1" data-colspan="1"><strong>Type of park pass: </strong>the <span class="fill-history-correct">{one-year|1 year}</span> pass</p>
<p class="qlbt-cell-line" data-row="row-mdys" data-cell="cell-0ttv" data-rowspan="1" data-colspan="1"><strong>Donation programme selection: </strong>the {youth}programme</p>
</td>
</tr>
