INSERT INTO public.questions VALUES ('d1a299f6-2022-42cf-be45-4f60acfe1029', 'abda3c23-0b52-4bae-a212-c9266748abfd', 'matching', 'Questions 26–30', NULL, '<p>Complete the flow chart below.</p>
<p>Choose <strong>FIVE </strong>answers from the box and write the correct letter, A–H, next to questions 26–30.</p>
', 'matching', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p style=\"text-align: center;\"><strong>Aerial Reforestation Process<br></strong></p>\n<p style=\"text-align: center;\"> </p>\n<p style=\"text-align: center;\">Choose a reforestation area with plenty of {H light}</p>\n<p style=\"text-align: center;\">↓</p>\n<p style=\"text-align: center;\">Take a lot of suitable {C seeds} appropriate to your purposes.</p>\n<p style=\"text-align: center;\">↓</p>\n<p style=\"text-align: center;\">Mix with long-lasting {E compost}</p>\n<p style=\"text-align: center;\">↓</p>\n<p style=\"text-align: center;\">Press into lumps of {G clay}</p>\n<p style=\"text-align: center;\">↓</p>\n<p style=\"text-align: center;\">Apply an outer coating, e.g. paper, to provide appropriate levels of {D nutrients}<br> and protection.</p>", "answerOptions": [{"optionText": "A land"}, {"optionText": "B plants"}, {"optionText": "C seeds"}, {"optionText": "D nutrients"}, {"optionText": "E compost"}, {"optionText": "F insecticide"}, {"optionText": "G clay"}, {"optionText": "H light"}], "matchingItems": null}', 'null', '[{"content": "<p>1</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('4bb13c0d-8591-451a-a097-e0eb398bdead', '1b86fad8-de2a-4f6b-81bf-fe25dc9fc019', 'fillup', 'Questions 31–40', '<div class="quests-inner-desc">
<div class="txt">
<p>Complete the notes below.</p>
<p>Write<strong> ONE WORD ONLY </strong>for each answer.</p>
</div>
</div>
<div class="quests-des">
<div class="content-write">
<p class="ql-align-center" style="text-align: center;"><strong>RESEARCH ON BIRDS IN AUSTRALIA</strong></p>
<p><strong>The study Cunningham in 1995</strong></p>
<p>– It aimed to study birds which were {protected} in cities.</p>
<p><strong>Methodology</strong></p>
<p>– Researchers were able to {estimate} rather than count the number of birds by some methods, such as random sampling.</p>
<p>– Research studied bird’s companionship habits using a {mapping} system.</p>
<p>– Research attached tags to birds’ legs to identify their {trends}<span class="fill-history-correct"> </span>over time.</p>
<p><strong>Findings</strong></p>
<p>– Birds tended to choose the same nesting site in which they were raised.</p>
<p>– Human activities such as {pollution} had a negative effect on the reproduction of birds.</p>
<p><strong>Measures taken by local organisation:</strong></p>
<p>– To increase birds’ rate of {survival} in various ways.</p>
<p>– To reduce the dangers caused by {wind} farms, e.g. colliding with turbines.</p>
<p><strong>The study by Conway in 2006</strong></p>
<p>– Researchers monitored the {frequency} of birds’ nocturnal callings during flight.</p>
<p>– {recordings}<strong> </strong>were taken to listening to birds’ sounds.</p>
<p>– Data could be collected through noise detection devices placed at a great {distance}</p>
</div>
</div>', NULL, 'fill-in-the-blank', 'null', 'null', 'null', 'null', '[{"content": "<h3 data-path-to-node=\"2\">PART 4: BIRD RESEARCH IN AUSTRALIA</h3>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Lecturer:</strong> Good afternoon. This is the <span class=\"citation-1299 citation-1300 citation-end-1300\">third session of the series of lectures on wildlife. For this lecture, we&#8217;re going to look at two studies on the habitats of birds and protection measures taken in Australia, including the basic methodology and rela<sup class=\"superscript\" data-turn-source-index=\"1\"><!----></sup></span><span class=\"citation-1299 citation-end-1299\">ted areas of resear<sup class=\"superscript\" data-turn-source-index=\"2\"><!----></sup></span>ch.</p>\n<div class=\"source-inline-chip-container ng-star-inserted\"><!----><!----></div>\n<p><!----><!----><!----><!----><!----><!----><!----><!----><!----></p>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">Lecturer:</strong> Now <span class=\"citation-1298 citation-end-1298\">let me give you some background information about the first research project on birds. The study was carried out by R. B. Cunningham and his team from the Australian National University in 1995. The primary goal was to detect the breeding ha<sup class=\"superscript\" data-turn-source-index=\"3\"><!----></sup></span>bits and resting sites of some birds, especially those <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"4\" data-index-in-node=\"310\">(31) protected</strong></span> species in urban regions. These species included birds like peregrine falcons and kestrels in Australia.</p>\n<div class=\"source-inline-chip-container ng-star-inserted\"><!----><!----></div>\n<p><!----><!----><!----><!----><!----><!----><!----><!----><!----></p>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">Lecturer:</strong> <span class=\"citation-1296 citation-1297 citation-end-1297\">The bird data set consisted of a total of 153 species recorded from 946 sites. One might expect that in order to obtain valid data on their distribution patterns and population densities, researchers had to count through binoculars<sup class=\"superscript\" data-turn-source-index=\"4\"><!----></sup></span><span class=\"citation-1296 citation-end-1296\">. Instead, they managed to<sup class=\"superscript\" data-turn-source-index=\"5\"><!----></sup></span> <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"5\" data-index-in-node=\"268\">(32) estimate</strong></span> with various standard distance sampling methods like random sampling.</p>\n<div class=\"source-inline-chip-container ng-star-inserted\"><!----><!----></div>\n<p><!----><!----><!----><!----><!----><!----><!----><!----><!----></p>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">Lecturer:</strong> In addition, a <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"6\" data-index-in-node=\"25\">(33) mapping</strong></span> system was used to study their companionship behaviour. It recorded proposed birds&#8217; nesting sites to monitor the mating behavior <span class=\"citation-1295\">of targeted species. To obtain valid data of birds&#8217; whereabouts, researchers attached identity tags to birds&#8217; </span><span class=\"citation-1294 citation-1295 citation-end-1295\">legs transmitting radio signals. The tagging process was done when the birds were between five and seven days of ag<sup class=\"superscript\" data-turn-source-index=\"6\"><!----></sup></span><span class=\"citation-1294\">e. After the initial tagging, data was collected from subsets of radio-tagged birds, making it possible to assess the </span><span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"6\" data-index-in-node=\"510\"><span class=\"citation-1294 citation-end-1294\">(<sup class=\"superscript\" data-turn-source-index=\"7\"><!----></sup></span>34) trends</strong></span> of birds over 15 months.</p>\n<div class=\"source-inline-chip-container ng-star-inserted\"><!----><!----></div>\n<p><!----><!----><!----><!----><!----><!----><!----><!----><!----></p>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">Lecturer:</strong> So what did they find? Well, as it turned out, many of the birds tagged had the tendency to nest in the same habitat where they grew up. Their nesting sites were quite varied and included freshwater reed beds, tidal reed beds, agricultural crops and man-made sites. Even though naturally occurring nests were common, birds sometimes accidentally nested in man-made devices like power towers, chimneys and tunnels.</p>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">Lecturer:</strong> This research also studied the impact of humans on bird communities and found out that <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"8\" data-index-in-node=\"97\">(35) <span class=\"citation-1292 citation-1293\">pollution</span></strong></span><span class=\"citation-1292 citation-1293 citation-end-1293\"> had contributed greatly to the declining birth rates of some species which were considered to be extinct or threatened to vanish from the study area. These species are dependent on natural forests because of their breeding holes; they will become extinct when local natural for<sup class=\"superscript\" data-turn-source-index=\"8\"><!----></sup></span><span class=\"citation-1292 citation-end-1292\">ests continue to be polluted heav<sup class=\"superscript\" data-turn-source-index=\"9\"><!----></sup></span>ily.</p>\n<div class=\"source-inline-chip-container ng-star-inserted\"><!----><!----></div>\n<p><!----><!----><!----><!----><!----><!----><!----><!----><!----></p>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">Lecturer:</strong> A number of measures were thus taken by members from local animal conservation organizations to boost their alarming <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"9\" data-index-in-node=\"127\">(36) <span class=\"citation-1291\">survival</span></strong></span><span class=\"citation-1291 citation-end-1291\"> rates. Firstly, breeding boxes were placed in trees, taking on the role of breeding holes that were contaminated. Protection guidelines were also introduced strictly prohibiting killing, disturbance and habitat destruction<sup class=\"superscript\" data-turn-source-index=\"10\"><!----></sup></span>.</p>\n<div class=\"source-inline-chip-container ng-star-inserted\"><!----><!----></div>\n<p><!----><!----><!----><!----><!----><!----><!----><!----><!----></p>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">Lecturer:</strong> A further measure was taken to ensure the safety of birds from <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"10\" data-index-in-node=\"73\">(37) wind</strong></span> farms. In fact, birds are sometimes shed <span class=\"citation-1288 citation-1289 citation-1290 citation-end-1290\">by wind turbine blades. A great deal of work was done on how to prevent them from colliding with turbines. A case in point was protecting space for bird migration by ensuring that migratory routes were kept free. Falcons generally cope well with wind turbines but not in weather conditions where visibility is b<sup class=\"superscript\" data-turn-source-index=\"11\"><!----></sup></span><span class=\"citation-1288 citation-1289 citation-end-1289\">ad. So with knowledge of how fast falcons fly, bird stations in northern Australia can notify wind farms further south of the falcons&#8217; approach so that turbines can be shut <sup class=\"superscript\" data-turn-source-index=\"12\"><!----></sup></span><span class=\"citation-1288 citation-end-1288\">down as they pass by.<sup class=\"superscript\" data-turn-source-index=\"13\"><!----></sup></span></p>\n<div class=\"source-inline-chip-container ng-star-inserted\"><!----><!----></div>\n<p><!----><!----><!----><!----><!----><!----><!----><!----><!----></p>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Lecturer:</strong> Then another piece of research was done a couple of years later by Conway in 2006. His team detected the calling <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"11\" data-index-in-node=\"123\">(38) frequency</strong> </span>of seabirds <span class=\"citation-1287 citation-end-1287\">flying at night. Acoustic signals are important communication tools for birds. These signals can indicate social cohesion, prey location and breeding behavior. Courtship songs are common among various species during mating seaso<sup class=\"superscript\" data-turn-source-index=\"14\"><!----></sup></span>ns.</p>\n<div class=\"source-inline-chip-container ng-star-inserted\"><!----><!----></div>\n<p><!----><!----><!----><!----><!----><!----><!----><!----><!----></p>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">Lecturer:</strong> Surveyors also took <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"12\" data-index-in-node=\"30\">(39) <span class=\"citation-1286\">recordings</span></strong></span><span class=\"citation-1286 citation-end-1286\"><span style=\"text-decoration: underline; background-color: #ffe786;\"> </span>of the sounds of all the individual birds detected. A tablet PC was used to process detailed information like sound pitch, spectrum length and timing of surveys. To minimize the disturbance on the bird comm<sup class=\"superscript\" data-turn-source-index=\"15\"><!----></sup></span>unity, all the sounds were recorded from a <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong data-path-to-node=\"12\" data-index-in-node=\"295\">(40) distance</strong></span> using microphones to detect noise.</p>\n<div class=\"source-inline-chip-container ng-star-inserted\"><!----><!----></div>\n<p><!----><!----><!----><!----><!----><!----><!----><!----><!----></p>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">Lecturer:</strong> They found that the <span class=\"citation-1285 citation-end-1285\">probability of call events was much higher for solitary birds communicating early and late in the day. Further analyses indicated that during foraging, the frequency of calls was significantly greater for birds encountering schoolin<sup class=\"superscript\" data-turn-source-index=\"16\"><!----></sup></span>g fish. The results of this study showed that increased calling activity in the presence of more profitable prey could be of crucial importance to seabirds that benefit from group foraging.</p>\n<div class=\"source-inline-chip-container ng-star-inserted\"><!----><!----></div>\n<p><!----><!----><!----><!----><!----><!----><!----><!----><!----></p>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">Lecturer:</strong> So, does anyone have more questions on&#8230;</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('baf1818f-d05c-4f6a-9534-024703333074', '515158f3-0462-4553-aba6-058453c0b941', 'checkbox', 'Questions 11 and 12', '', '<p data-start="36" data-end="64">Choose <strong>TWO </strong>letters, <strong>A</strong>–<strong>E</strong>.</p>
<p data-start="66" data-end="128">Which <strong>TWO </strong>parts of the gym are closed for part of the day?</p>', 'multiple_choice', 'null', '[{"correct": false, "option_text": "A. the café"}, {"correct": false, "option_text": "B. the weights room"}, {"correct": false, "option_text": "C. the reception desk"}, {"correct": true, "option_text": "D. the childcare centre"}, {"correct": true, "option_text": "E. the shop"}]', 'null', 'null', 'null', 0);
INSERT INTO public.questions VALUES ('7aec4fda-4972-4f5f-84f7-a090e47c856a', '515158f3-0462-4553-aba6-058453c0b941', 'checkbox', 'Questions 13 and 14', '', '<p data-start="331" data-end="359">Choose <strong>TWO </strong>letters, <strong>A</strong>–<strong>E</strong>.</p>
<p data-start="361" data-end="413">Which <strong>TWO </strong>facilities have recently been updated?</p>', 'multiple_choice', 'null', '[{"correct": true, "option_text": "A. the change rooms"}, {"correct": false, "option_text": "B. the sauna"}, {"correct": true, "option_text": "C. the treadmills"}, {"correct": false, "option_text": "D. the car park"}, {"correct": false, "option_text": "E. the yoga studio"}]', 'null', 'null', 'null', 1);
INSERT INTO public.questions VALUES ('933b3281-451e-4dbe-8e4c-38cd6f029e35', '515158f3-0462-4553-aba6-058453c0b941', 'matching', 'Questions 15–20', '', '<p data-start="610" data-end="635">Label the plan below.</p>
<p data-start="637" data-end="696">Write the correct letter, <strong>A</strong>–<strong>J</strong></p>', 'summary_completion', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p><img src=\"data:image/jpeg;base64,\" width=\"642\" height=\"558\"></p>\n<p>15. Personal trainer’s office — {F}<br>16. Pool — {G}<br>17. Stretch area — {C}<br>18. Men’s changing room — {H}<br>19. Weights room — {B}<br>20. Café — {A}</p>", "answerOptions": [{"optionText": "A"}, {"optionText": "B"}, {"optionText": "C"}, {"optionText": "D"}, {"optionText": "E"}, {"optionText": "F"}, {"optionText": "G"}, {"optionText": "H"}, {"optionText": "I"}, {"optionText": "J"}], "matchingItems": []}', 'null', 'null', 2);
INSERT INTO public.questions VALUES ('afc83a33-1a8b-48ed-83b4-9132292c0981', 'a48e01dc-5d10-4a72-a3db-78995459668f', 'matrix', 'Questions 15–20', '', '<p data-start="800" data-end="872">What activity can children do at each of the following summer camps?</p>
<p data-start="874" data-end="969">Choose <strong>SIX </strong>answers from the box and write the correct letter, <strong>A</strong>–<strong>I</strong></p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "standard", "matrixItems": [{"itemText": "Elm Camp", "correctCategoryLetter": "F"}, {"itemText": "Maple Camp", "correctCategoryLetter": "E"}, {"itemText": "Willow Camp", "correctCategoryLetter": "G"}, {"itemText": "Cedar Camp", "correctCategoryLetter": "D"}, {"itemText": "Birch Camp", "correctCategoryLetter": "C"}, {"itemText": "Pine Camp", "correctCategoryLetter": "B"}], "matrixCategories": [{"categoryText": "acting in a play", "categoryLetter": "A"}, {"categoryText": "making a short film", "categoryLetter": "B"}, {"categoryText": "taking lessons from a writer", "categoryLetter": "C"}, {"categoryText": "playing in a musical group", "categoryLetter": "D"}, {"categoryText": "taking care of animals", "categoryLetter": "E"}, {"categoryText": "learning about plants", "categoryLetter": "F"}, {"categoryText": "learning to cook", "categoryLetter": "G"}, {"categoryText": "playing team sports", "categoryLetter": "H"}, {"categoryText": "sailing on the lake", "categoryLetter": "I"}]}', 'null', 1);
INSERT INTO public.questions VALUES ('5870e23f-b0b9-4c80-a524-b2d596edb4b0', '71262a1d-d0c1-40bb-9a33-9c15e09988bf', 'fillup', 'Questions 31-40', '<p>Write <strong>ONE WORD ONLY</strong> for each answer.</p>
<p><span style="font-size: 12pt;"><strong>Canadian Maple Syrup</strong></span></p>
<p><strong>Description</strong></p>
<ul>
<li>
<p>It is a sweet liquid poured over pancakes etc.</p>
</li>
<li>
<p>The production of sap needs a climate where night and day temperatures are very {different}</p>
</li>
</ul>
<p><strong>History</strong></p>
<ul>
<li>
<p>Folk stories claim that maple syrup was first used to cook {meat}</p>
</li>
<li>
<p>Sap collection in spring developed into a First Nations {tradition}</p>
</li>
<li>
<p>The sap was collected in buckets.</p>
</li>
<li>
<p>The sap was concentrated into syrup by:</p>
<ul>
<li>
<p>using hot stones to produce {steam}</p>
</li>
<li>
<p>leaving it outside at night and then removing the layer of {ice} on top.</p>
</li>
</ul>
</li>
</ul>
<p><strong>Uses</strong></p>
<ul>
<li>
<p>First Nations people drank the fresh sap to give them energy.</p>
</li>
<li>
<p>European settlers put the syrup in various types of {medicine}</p>
</li>
<li>
<p>They also used it for drinks and for candy.</p>
</li>
<li>
<p>Its use for making sugar declined after 1880, when the {tax} on Caribbean sugar was removed.</p>
</li>
</ul>
<p><strong>Threats</strong></p>
<p><strong>Natural</strong></p>
<ul>
<li>
<p>Harvests may be affected by storms and destructive {insects}</p>
</li>
<li>
<p>Climate change may also affect sap production.</p>
</li>
</ul>
<p><strong>Social</strong></p>
<ul>
<li>
<p>Maple syrup is expensive and faces considerable {competition}</p>
</li>
<li>
<p>The obesity issue is affecting sales.</p>
</li>
</ul>
<p><strong>Reasons for optimism</strong></p>
<ul>
<li>
<p>Maple syrup is an important export.</p>
</li>
<li>
<p>It is quite {healthy} compared with other sweeteners.</p>
</li>
<li>
<p>Its taste is the main reason for its popularity.</p>
</li>
</ul>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"1\"><strong data-path-to-node=\"1\" data-index-in-node=\"0\">PART 4: </strong></p>\n<p data-path-to-node=\"2\">Maple syrup can be described as very sweet. Canadians pour it generously over things like pancakes for breakfast. The syrup is produced from the maple tree, and it actually comes from the tree’s sap, which is the watery substance that comes out of the trunk of the tree when this is cut. In order for enough sap to be produced, very special climate conditions are needed in spring. The temperatures need to drop to well below zero at night, but then they need to rise sharply during the day. So they’re hugely<span style=\"background-color: #f3db7b;\"> <strong data-path-to-node=\"2\" data-index-in-node=\"503\">(31) different</strong></span> over a 24-hour period, and that’s exactly what happens in northeastern Canada every spring.</p>\n<p data-path-to-node=\"3\">The indigenous peoples of North America, known as the First Nations, discovered the maple secret long before the Europeans arrived. Early folk stories say it was first discovered by a chief who threw his tomahawk, which is similar to an axe, into the trunk of a tree. Clear sap started to run from the cut. His wife used this sap to boil <span style=\"background-color: #f3db7b;\"><strong data-path-to-node=\"3\" data-index-in-node=\"338\">(32) meat</strong>,</span> and the heat turned it into a sweet syrup, which they found delicious.</p>\n<p data-path-to-node=\"4\">Whether or not that story is true, we do know that the maple tree was very important to <strong>First Nations</strong> peoples for hundreds of years. Collecting the sap each spring became a <span style=\"background-color: #f3db7b;\"><strong data-path-to-node=\"4\" data-index-in-node=\"173\">(33) tradition</strong></span> among them. Whole families would migrate to the areas where the maple trees grew and set up camp there.</p>\n<p data-path-to-node=\"5\">They collected the sap from the trees using buckets. Then they needed to concentrate the sap, removing some of the water from it to create syrup. They had two ways of doing this. One way was to drop hot stones from a fire into the buckets to create <span style=\"background-color: #f3db7b;\"><strong data-path-to-node=\"5\" data-index-in-node=\"249\">(34) steam</strong></span>. If repeated often enough, this would eventually concentrate the syrup. Another method that they used to concentrate the syrup was to leave the sap outside overnight, exposed to freezing temperatures. This would mean that a thick layer of<span style=\"background-color: #f3db7b;\"> <strong data-path-to-node=\"5\" data-index-in-node=\"499\">(35) ice</strong></span> would form on top, which could be discarded, leaving the sugary sap below. Again, this process could be repeated over several days and eventually a sweet brown syrup was produced.</p>\n<p data-path-to-node=\"6\">The First Nation’s people had various uses for the sap and syrup. They drank the sap fresh from the tree as a tonic, knowing that it was an important source of energy. But for the most part, they reduced the syrup further and then cooled it so that it crystallized into sugar. This was easy to carry and kept indefinitely</p>\n<p data-path-to-node=\"6\">European settlers who arrived in Canada began to learn about the syrup from First Nations peoples and further expanded its uses. For example, they incorporated it into <span style=\"background-color: #f3db7b;\"><strong data-path-to-node=\"6\" data-index-in-node=\"336\">(36) medicine</strong></span> of different kinds. They also discovered that by adding yeast to the sap, they could make a maple drink, and by throwing the hot syrup into the snow, they could make a toffee-like candy.</p>\n<p data-path-to-node=\"7\">But like the First Nations, they turned most of their sap into maple sugar. For most people, it was the only type of sugar they could afford, since the only alternative was the sugar imported from the Caribbean, which was made from sugar cane and this was very expensive. However, after 1880, the Canadian government decided to stop charging<span style=\"background-color: #f3db7b;\"> <strong data-path-to-node=\"7\" data-index-in-node=\"342\">(37) tax</strong></span> on Caribbean sugar, and this made it much cheaper. That meant it was no longer cost-effective to produce maple sugar, and so syrup making became the only viable industry remaining for Canadians, and that’s what we’ve been doing ever since.</p>\n<p data-path-to-node=\"8\">At present, maple syrup is enjoying a boom. However, serious threats remain. Like any agricultural product, the harvest is subject to such things as major storms or the arrival of invasive <span style=\"background-color: #f3db7b;\"><strong data-path-to-node=\"8\" data-index-in-node=\"189\">(38) insects</strong></span>, both of which have happened and these could destroy everything. It is predicted with some certainty that in the longer term, climate change will also have an adverse effect on the sap run.</p>\n<p data-path-to-node=\"9\">Then there are the social factors. Producing maple syrup is a very labor-intensive process, making it an expensive purchase, and of equal concern is the fact that nowadays there’s a lot of <span style=\"background-color: #f3db7b;\"><strong data-path-to-node=\"9\" data-index-in-node=\"189\">(39) competition</strong></span> from cheaper, artificially flavored brands. Furthermore, we’re at a time khi obesity is a major issue, making a product that is 67% sugar increasingly difficult to sell.</p>\n<p data-path-to-node=\"10\">Nevertheless, there are reasons to be optimistic. Producers are developing markets abroad. Our syrup is currently being exported to over 50 countries. Back here at home, chefs use it enthusiastically. It’s certainly high in calories, but it also contains proteins, minerals, and antioxidants. As such, it is still relatively <span style=\"background-color: #f3db7b;\"><strong data-path-to-node=\"10\" data-index-in-node=\"325\">(40) healthy</strong></span> when you compare it with sugar or corn syrup. Canadians are proud of maple syrup and its deep roots in our history and geography.</p>\n<p>However, the primary reason for maple syrup’s success around the world remains its taste.There’s nothing quite like it.</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('541ae772-906b-4005-9037-f960c5a7a206', '9a1ed96d-89a5-418a-97d7-622a8668d513', 'fillup', 'Questions 1-10', '<div class="instruction">
