<p data-start="637" data-end="696">Write the correct letter, <strong>A</strong>–<strong>J</strong></p>', 'summary_completion', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p><img src=\"data:image/jpeg;base64,\" width=\"642\" height=\"558\"></p>\n<p>15. Personal trainer’s office — {F}<br>16. Pool — {G}<br>17. Stretch area — {C}<br>18. Men’s changing room — {H}<br>19. Weights room — {B}<br>20. Café — {A}</p>", "answerOptions": [{"optionText": "A"}, {"optionText": "B"}, {"optionText": "C"}, {"optionText": "D"}, {"optionText": "E"}, {"optionText": "F"}, {"optionText": "G"}, {"optionText": "H"}, {"optionText": "I"}, {"optionText": "J"}], "matchingItems": []}', 'null', 'null', 2);
INSERT INTO public.questions VALUES ('14b21d7a-f476-41d8-8d3a-efea9356a5db', '8c120807-0a79-421b-a0e4-1963a5f8127e', 'radio', 'Questions 21–22', '', '<p data-start="32" data-end="73">Choose the correct letter, <strong>A</strong>, <strong>B </strong>or <strong>C</strong>.</p>
<h4 data-start="75" data-end="107">Field trip to Bolton Island</h4>', 'multiple_choice', '[{"correct": 1, "options": [{"option_text": "A. because it is geologically unique"}, {"option_text": "B. because its easy accessible"}, {"option_text": "C. because large numbers of rare animals frequent it"}], "question": "Why were Mark and Stella attracted to Bolton Island for their field trip?"}, {"correct": 2, "options": [{"option_text": "A. the natural lagoon"}, {"option_text": "B. its fertile soil"}, {"option_text": "C. rock formation"}], "question": "Which aspect of Bolton Island’s physical geography did Mark and Stella focus on?"}, {"correct": 1, "options": [{"option_text": "A. getting useful information from the local residents"}, {"option_text": "B. recognising which features were man-made"}, {"option_text": "C. finding official data about the island"}], "question": "Which problem did Mark and Stella have in studying Bolton Island’s physical geography?"}, {"correct": 0, "options": [{"option_text": "A. reading previous field trip reports"}, {"option_text": "B. drawing up a detailed schedule for their trip"}, {"option_text": "C. doing online research"}], "question": "What preparation was most useful for Mark and Stella’s trip?"}]', 'null', 'null', 'null', 'null', 0);
INSERT INTO public.questions VALUES ('66d96789-5e78-4efc-b042-3fc4c202a5d6', 'a0bf0e74-2e4b-4e45-b222-7d26a27218e0', 'fillup', 'Questions 24-26', '<p>Complete the summary below.</p>
<p>Choose <strong>ONE WORD ONLY</strong> from the passage for each answer.</p>
<p style="text-align: center;"><strong>What recent history tells us about recycling</strong></p>
<p>Richard Fisher, a researcher from Cranfield University, points out that the pace of consumerism has increased more quickly than was predicted in the 1980s. There has, for example, been unexpected growth in waste from {electronic} products. He suggests that the need to protect the environment should be linked to basic values, and adds that it might be better if consumers had more influence over {business} and more direction was provided by {government}</p>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p><strong data-path-to-node=\"27\" data-index-in-node=\"0\">24. electronic</strong></p>\n<ul data-path-to-node=\"28\">\n<li><strong data-path-to-node=\"28,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> (Đoạn F) “Nobody would have said there would be so much <strong data-path-to-node=\"28,0,0\" data-index-in-node=\"67\">electronic</strong> waste.”</li>\n</ul>\n<p><strong data-path-to-node=\"29\" data-index-in-node=\"0\">25. business</strong></p>\n<ul data-path-to-node=\"30\">\n<li><strong data-path-to-node=\"30,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> (Đoạn F) “We need to look at whether it’s <strong data-path-to-node=\"30,0,0\" data-index-in-node=\"53\">business</strong> that drives consumers or the other way around.”</li>\n</ul>\n<p><strong data-path-to-node=\"31\" data-index-in-node=\"0\">26. government</strong></p>\n<ul data-path-to-node=\"32\">\n<li><strong data-path-to-node=\"32,0,0\" data-index-in-node=\"0\">Dẫn chứng:</strong> (Đoạn F) “You need <strong data-path-to-node=\"32,0,0\" data-index-in-node=\"30\">government</strong> to play a leadership role…”</li>\n</ul>\n"}]', 2);
INSERT INTO public.questions VALUES ('f1c6cdc2-b91c-47b4-88e7-90c94e6abc95', '8c120807-0a79-421b-a0e4-1963a5f8127e', 'checkbox', 'Questions 25 and 26', '', '<p data-start="1045" data-end="1073">Choose <strong>TWO </strong>letters, <strong>A</strong>–<strong>E</strong>.</p>
<p data-start="1075" data-end="1142">Which <strong>TWO </strong>mistakes did Mark and Stella make with their visuals?</p>', 'multiple_choice', 'null', '[{"correct": false, "option_text": "A. not taking enough care when making sketches"}, {"correct": false, "option_text": "B. not ensuring their photos had proper lighting"}, {"correct": true, "option_text": "C. not using anything to indicate the scale of their photos"}, {"correct": false, "option_text": "D. not making sufficient photos and drawings of things of interest"}, {"correct": true, "option_text": "E. not adequately recording when and where drawings were made"}]', 'null', 'null', 'null', 1);
INSERT INTO public.questions VALUES ('0edd6df7-ab25-4215-bd0a-5f05ca68e366', '8c120807-0a79-421b-a0e4-1963a5f8127e', 'checkbox', 'Questions 27 and 28', '', '<p data-start="1506" data-end="1534">Choose <strong>TWO </strong>letters, <strong>A</strong>–<strong>E</strong>.</p>
<p data-start="1536" data-end="1620">Which <strong>TWO </strong>things does Stella say students need to do for a successful interview?</p>', 'multiple_choice', 'null', '[{"correct": true, "option_text": "A. Guide the way in which the interview progresses"}, {"correct": false, "option_text": "B. Prepare the questions well in advance"}, {"correct": false, "option_text": "C. Check the recording equipment is working"}, {"correct": true, "option_text": "D. explain fully the purpose of the interview"}, {"correct": false, "option_text": "E. give a personal opinion on the topics which are covered"}]', 'null', 'null', 'null', 2);
INSERT INTO public.questions VALUES ('5e0bdb6b-8375-4040-9c53-f9cff927267a', '8c120807-0a79-421b-a0e4-1963a5f8127e', 'checkbox', 'Questions 29 and 30', '', '<p data-start="1940" data-end="1968">Choose <strong>TWO </strong>letters, <strong>A</strong>–<strong>E</strong>.</p>
<p data-start="1970" data-end="2067">Which <strong>TWO </strong>things do Mark and Stella suggest doing with regard to note-taking on a field trip?</p>', 'multiple_choice', 'null', '[{"correct": false, "option_text": "A. Ensure that terminology is correctly used in the notes"}, {"correct": true, "option_text": "B. Check your notes every evening"}, {"correct": false, "option_text": "C. Be highly selective in what you write down"}, {"correct": false, "option_text": "D. Have only one member of a team to write notes"}, {"correct": true, "option_text": "E. Keep your notes in an organised fashion"}]', 'null', 'null', 'null', 3);
INSERT INTO public.questions VALUES ('5b301341-7fa9-40a8-a92d-83af22df7a20', '1ab92eab-0cb2-42ba-8a8b-7b14ce9d62c8', 'fillup', 'Questions 31 – 40', '<p data-path-to-node="3">Complete the notes below.</p>
<p data-path-to-node="4">Write <strong data-path-to-node="4" data-index-in-node="6">ONE WORD ONLY</strong> for each answer.</p>
<p data-path-to-node="5"><span style="font-size: 14pt;"><strong data-path-to-node="5" data-index-in-node="0">Early gold mining in the Otago region, New Zealand</strong></span></p>
<p data-path-to-node="6"><strong data-path-to-node="6" data-index-in-node="0">Background</strong></p>
<ul data-path-to-node="7">
<li>
<p data-path-to-node="7,0,0">1852: there was a brief gold rush.</p>
</li>
<li>
<p data-path-to-node="7,1,0">Late 1850s: local governments offered a {reward} to experienced gold prospectors.</p>
</li>
<li>
<p data-path-to-node="7,2,0">May 1861: miner Gabriel Read found gold in a {river}</p>
</li>
</ul>
<p data-path-to-node="8"><strong data-path-to-node="8" data-index-in-node="0">Who took part in the gold rush?</strong></p>
<ul data-path-to-node="9">
<li>
<p data-path-to-node="9,0,0">Mainly young single men or men leaving families at home.</p>
</li>
<li>
<p data-path-to-node="9,1,0">Women opened {hotels} for the miners.</p>
</li>
<li>
<p data-path-to-node="9,2,0">Businessmen offered services, e.g. hardware stores and {banks}</p>
</li>
</ul>
<p data-path-to-node="10"><strong data-path-to-node="10" data-index-in-node="0">What were early mining towns like?</strong></p>
<ul data-path-to-node="11">
<li>
<p data-path-to-node="11,0,0">At first, the buildings were made of canvas and timber, and later {concrete}</p>
</li>
</ul>
<p data-path-to-node="12"><strong data-path-to-node="12" data-index-in-node="0">What difficulties did miners face at the gold fields?</strong></p>
<ul data-path-to-node="13">
<li>
<p data-path-to-node="13,0,0">The freezing temperatures and unexpected {flooding}</p>
</li>
<li>
<p data-path-to-node="13,1,0">A poor diet of tea and {flour}</p>
</li>
</ul>
<p data-path-to-node="14"><strong data-path-to-node="14" data-index-in-node="0">What benefits and problems did gold bring to the Otago region?</strong></p>
<ul data-path-to-node="15">
<li>
<p data-path-to-node="15,0,0">Growth of the Otago town of Dunedin led to complaints about:</p>
<ul data-path-to-node="15,0,1">
<li>
<p data-path-to-node="15,0,1,0,0">The increasing price of {land}</p>
</li>
<li>
<p data-path-to-node="15,0,1,1,0">Problems with sanitation</p>
</li>
</ul>
</li>
<li>
<p data-path-to-node="15,1,0">The gold also resulted in:</p>
<ul data-path-to-node="15,1,1">
<li>
<p data-path-to-node="15,1,1,0,0">Investment in shipping</p>
</li>
<li>
<p data-path-to-node="15,1,1,1,0">The first New Zealand {university}</p>
</li>
<li>
<p data-path-to-node="15,1,1,2,0">The need for experienced workers, in particular {engineers}</p>
</li>
</ul>
</li>
</ul>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', 'null', 0);
INSERT INTO public.questions VALUES ('33cd4c7b-b9d9-4d55-b371-c9d8859b33ce', 'a48e01dc-5d10-4a72-a3db-78995459668f', 'radio', 'Questions 11–14', '', '<p data-start="32" data-end="73">Choose the correct letter, <strong>A</strong>, <strong>B </strong>or <strong>C</strong>.</p>
<p data-start="75" data-end="95"><strong>Children''s club</strong></p>', 'multiple_choice', '[{"correct": 2, "options": [{"option_text": "A. they can use the computer equipment"}, {"option_text": "B. they get to make new friends"}, {"option_text": "C. the programme leaders are young"}], "question": "The summer programmes are popular with children because"}, {"correct": 1, "options": [{"option_text": "A. arranging the programmes"}, {"option_text": "B. hiring the right staff"}, {"option_text": "C. dealing with finance"}], "question": "What is the most challenging task for the programme director?"}, {"correct": 0, "options": [{"option_text": "A. advise young people"}, {"option_text": "B. organise activities"}, {"option_text": "C. supervise outings"}], "question": "New employees are trained in how to"}, {"correct": 2, "options": [{"option_text": "A. pay before May 1st"}, {"option_text": "B. register at the office"}, {"option_text": "C. apply online"}], "question": "To make sure of place on the right programme, parents should"}]', 'null', 'null', 'null', 'null', 0);
INSERT INTO public.questions VALUES ('ae9b0e55-2d6b-49ed-94ac-818224e30365', '6dd42cbf-e278-48b0-9a5c-8fa52910b86f', 'fillup', 'Questions 1–10', '<p data-start="61" data-end="161">Complete the notes below.</p>
<p data-start="61" data-end="161">Write <strong data-start="116" data-end="144">ONE WORD AND/OR A NUMBER</strong> for each answer.</p>
<article class="text-token-text-primary w-full focus:outline-none [--shadow-height:45px] has-data-writing-block:pointer-events-none has-data-writing-block:-mt-(--shadow-height) has-data-writing-block:pt-(--shadow-height) [&amp;:has([data-writing-block])&gt;*]:pointer-events-auto [content-visibility:auto] supports-[content-visibility:auto]:[contain-intrinsic-size:auto_100lvh] scroll-mt-[calc(var(--header-height)+min(200px,max(70px,20svh)))]" dir="auto" tabindex="-1" data-turn-id="cc66c4fd-cf13-408c-afa0-554e22fc322e" data-testid="conversation-turn-395" data-scroll-anchor="false" data-turn="assistant">
<div class="text-base my-auto mx-auto [--thread-content-margin:--spacing(4)] @w-sm/main:[--thread-content-margin:--spacing(6)] @w-lg/main:[--thread-content-margin:--spacing(16)] px-(--thread-content-margin)">
<div class="[--thread-content-max-width:40rem] @w-lg/main:[--thread-content-max-width:48rem] mx-auto max-w-(--thread-content-max-width) flex-1 group/turn-messages focus-visible:outline-hidden relative flex w-full min-w-0 flex-col agent-turn" tabindex="-1">
<div class="flex max-w-full flex-col grow">
<div class="min-h-8 text-message relative flex w-full flex-col items-end gap-2 text-start break-words whitespace-normal [.text-message+&amp;]:mt-1" dir="auto" data-message-author-role="assistant" data-message-id="33d60d0f-598d-47e8-870c-3f6d18878bd1" data-message-model-slug="gpt-5-2">
<div class="flex w-full flex-col gap-1 empty:hidden first:pt-[1px]">
<div class="markdown prose dark:prose-invert w-full wrap-break-word light markdown-new-styling">
<h3 data-start="163" data-end="200">Enquiries on Hot Air Balloon Trip</h3>
<p data-start="202" data-end="248">The lowest price: {125} per person</p>
<p data-start="250" data-end="330">Each participant will be given a free {certificate} at the end of the flight</p>
<p data-start="332" data-end="383">The exact date can only be booked {online}</p>
<p data-start="385" data-end="449">The balloon can fly a maximum height of {1800} metres</p>
<p data-start="451" data-end="492">There are no flights at {night}</p>
<p data-start="451" data-end="492">The best time of year to go is in {autumn}</p>
<p data-start="547" data-end="618">Flights may be cancelled because of bad weather, e.g. {thunderstorm}</p>
<p data-start="620" data-end="672">It is advised to wear a jacket and {helmet}</p>
<p data-start="674" data-end="726">There is no {age} restriction for adults</p>
<p data-start="728" data-end="795" data-is-last-node="" data-is-only-node="">Participants must be able to {stand} throughout the flight</p>
</div>
</div>
</div>
</div>
<div class="z-0 flex min-h-[46px] justify-start"> </div>
</div>
</div>
</article>', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">PART 1</strong></p>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Jason:</strong> Good morning, Smart Travel. Jason speaking.</p>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">Woman:</strong> Hi, good morning. I saw your advert in today’s paper about hot air balloon trips. It sounds pretty exciting and I wonder how much it costs.</p>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">Jason:</strong> Well, the price may vary depending on the location, number of participants and add-ons. A single ride may cost you up to £280 per person, but if you choose group booking, there is a discount and the cheapest flight is <span style=\"text-decoration: underline;\"><span style=\"background-color: #f4d24a;\"><strong data-path-to-node=\"5\" data-index-in-node=\"225\">(1) 125</strong></span></span> each for a group booking of at least 10 people.</p>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">Woman:</strong> Oh, that’s not too bad. What do you mean by add-ons?</p>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">Jason:</strong> They are optional items like taking photos for you during the ride, champagne and sit-down breakfast after the flight. Upon completing the trip, we will provide each participant with a <span style=\"text-decoration: underline; background-color: #f4d24a;\"><strong data-path-to-node=\"7\" data-index-in-node=\"192\">(2) certificate</strong></span>, and that is entirely free of charge.</p>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">Woman:</strong> Can I book a ride over the phone?</p>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">Jason:</strong> Yes, that’s an option. Reservations can be made one year ahead of your trip by telephone, but to pick a specific date, you must book<span style=\"text-decoration: underline;\"> <span style=\"background-color: #f4d24a;\"><strong data-path-to-node=\"9\" data-index-in-node=\"140\">(3) online</strong>.</span></span> A confirmation email will be sent to you right afterwards.</p>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">Woman:</strong> How high can the balloons go?</p>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Jason:</strong> A hot air balloon’s height is limited by the temperature of the air and how much fuel it can carry. And the highest altitude ever recorded for a ride is <span style=\"text-decoration: underline;\"><span style=\"background-color: #f4d24a;\"><strong data-path-to-node=\"11\" data-index-in-node=\"160\">(4) 1800</strong> </span></span>meters, but most rides stay below 300 meters.</p>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">Woman:</strong> Oh boy, that’s impressive. How long is a single ride?</p>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">Jason:</strong> The average hot air balloon ride lasts about an hour. The entire ballooning experience, which includes ground preparation, flight and post-flight packing up and celebration, may take two to three hours.</p>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">Woman:</strong> And what time are the flights?</p>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">Jason:</strong> Our flights generally meet about an hour before sunrise on the day. You will be notified of the exact meeting time the evening before your flight. <span style=\"text-decoration: underline; background-color: #f4d24a;\"><strong data-path-to-node=\"15\" data-index-in-node=\"154\">(5) Night</strong></span> flights are avoided due to weather conditions.</p>\n<hr data-path-to-node=\"16\" />\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">Woman:</strong> Which month do you recommend for a hot air balloon trip?</p>\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">Jason:</strong> <span style=\"text-decoration: underline;\"><span style=\"background-color: #f4d24a;\"><strong data-path-to-node=\"18\" data-index-in-node=\"7\">(6) Autumn</strong> </span></span>is the best time of year to take the trip. Not only can you see the changing hues of the trees from above, but it is a great way to spend time with the whole family before it gets too cold.</p>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">Woman:</strong> I see.</p>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">Jason:</strong> But please note that our flight may be cancelled and you will be notified by phone the day before.</p>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">Woman:</strong> Why is that?</p>\n<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">Jason:</strong> It can be quite dangerous to fly under bad weather conditions like a <span style=\"text-decoration: underline; background-color: #f4d24a;\"><strong data-path-to-node=\"22\" data-index-in-node=\"76\">(7) thunderstorm</strong></span>, so our experienced pilots will not go under such conditions.</p>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">Woman:</strong> What should I wear for the ride?</p>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">Jason:</strong> We suggest wearing comfortable clothing like a jacket. Multiple layers are always better. Wearing a <span style=\"text-decoration: underline; background-color: #f4d24a;\"><strong data-path-to-node=\"24\" data-index-in-node=\"107\">(8) helmet</strong></span> for safety concerns is also a good idea. Sandals are not permitted.</p>\n<p data-path-to-node=\"25\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">Woman:</strong> Can children or older people participate?</p>\n<p data-path-to-node=\"26\"><strong data-path-to-node=\"26\" data-index-in-node=\"0\">Jason:</strong> All children must be above the minimum <span style=\"text-decoration: underline; background-color: #f4d24a;\"><strong data-path-to-node=\"26\" data-index-in-node=\"46\">(9) age</strong></span> of 9 years old and they have to be accompanied by at least a parent or guardian. However, an adult has no age limit as long as they meet the health requirements.</p>\n<p data-path-to-node=\"27\"><strong data-path-to-node=\"27\" data-index-in-node=\"0\">Woman:</strong> What exactly are the health requirements?</p>\n<p data-path-to-node=\"28\"><strong data-path-to-node=\"28\" data-index-in-node=\"0\">Jason:</strong> Participants must at least be in fair physical condition. For example, they shall have no significant knee, hip or back problems, and no recent surgeries or broken bones. They must also <span style=\"text-decoration: underline; background-color: #f4d24a;\"><strong data-path-to-node=\"28\" data-index-in-node=\"193\">(10) stand</strong></span> unassisted for an hour during the flight. It is the required position during the whole flight.</p>\n<p data-path-to-node=\"29\">As the balloon comes to land, all passengers will need to adopt the landing position with knees bent in front of them.</p>\n<p data-path-to-node=\"30\"><strong data-path-to-node=\"30\" data-index-in-node=\"0\">Woman:</strong> Are those rides safe?</p>\n<p data-path-to-node=\"31\"><strong data-path-to-node=\"31\" data-index-in-node=\"0\">Jason:</strong> Hot air balloon companies are required to have a commercial balloon pilot licence and all our pilots go through rigorous training.</p>\n<p data-path-to-node=\"32\"><strong data-path-to-node=\"32\" data-index-in-node=\"0\">Jason:</strong> It is a relatively gentle activity, however, the impact of a balloon landing can vary drastically depending on wind speed. Sometimes it is similar to the momentum of jumping off a small chair.</p>\n<p data-path-to-node=\"33\">If you cannot jump off a small chair, speaking to your doctor before booking a balloon flight is best.</p>\n<p data-path-to-node=\"34\"><strong data-path-to-node=\"34\" data-index-in-node=\"0\">Woman:</strong> Thank you very much. I think that’s all I need to know.</p>\n<p data-path-to-node=\"35\"><strong data-path-to-node=\"35\" data-index-in-node=\"0\">Jason:</strong> Thanks for calling. Goodbye.</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('603bbd59-5fc3-4717-bd89-c72bc9e15071', 'c99f28f5-c486-47db-bcc7-5064a8e4300d', 'fillup', 'Questions 11–17', '<p data-start="78" data-end="157">Write <strong data-start="112" data-end="140">ONE WORD AND/OR A NUMBER</strong> for each answer.</p>
<p style="text-align: left;" data-start="159" data-end="179"><span style="font-size: 12pt;"><strong data-start="163" data-end="179">Barton House</strong></span></p>
<p data-start="181" data-end="424">Before Barton bought this house, it was a {farm}.</p>
<p data-start="181" data-end="424">The Chinese wallpaper was painted in the {18th} century.</p>
<p data-start="181" data-end="424">Barton died in the {bird} room.</p>
<p data-start="181" data-end="424">The dining room has many antiques such as the {chairs} sold by Japanese.</p>
<p data-start="426" data-end="449"><strong>Backyard Garden</strong></p>
<p data-start="451" data-end="600">{rare} plants that have been there for years.</p>
<p data-start="451" data-end="600">{flamingos|flamingoes} were introduced by the government.</p>
<p data-start="451" data-end="600">The most popular animal is the {swans}.</p>', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">PART 2</strong></p>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Carly (Tour Guide):</strong> <span class=\"citation-324 citation-325 citation-end-325\">Good afternoon, welcome to Barton Museum. I am Carly and I am your tour guide. I would be taking you through all the places of interest in this museum.</span></p>\n<p data-path-to-node=\"4\"><span class=\"citation-322 citation-323 citation-end-323\">Before we actually set out to go, the first building we stop</span><span class=\"citation-322 citation-end-322\"> at is the Barton House which was built by the man himself, Ba</span>rton. When he first came to this area, it was largely uninhabited and as a matter of fact, this place was a vast expanse of land where an abandoned <span style=\"text-decoration: underline; background-color: #f4d24a;\"><strong data-path-to-node=\"4\" data-index-in-node=\"270\">(11) farm</strong></span> was situated.</p>\n<p data-path-to-node=\"5\">After he bought it, he began building and in about three years, the basic structure was complete, although he never really stopped building. As a man who loved the arts, Barton spent a good fortune on them. He had several paintings from all over the world and his gallery is still considered one of the best in town.</p>\n<p data-path-to-node=\"6\">One of the most notable of his collection is the Chinese Wallpaper, which was painted in the <span style=\"text-decoration: underline; background-color: #f4d24a;\"><strong data-path-to-node=\"6\" data-index-in-node=\"93\">(12) 18th</strong></span> century. Rumor has it that he paid hundreds of thousands of dollars for the piece of art.</p>\n<p data-path-to-node=\"7\">Barton kept adding some features to his house every year. He did this until the night he died. He was building a new <span style=\"text-decoration: underline; background-color: #f4d24a;\"><strong data-path-to-node=\"7\" data-index-in-node=\"117\">(13) bird</strong></span> room in which he collapsed and never came to himself.</p>\n<p data-path-to-node=\"8\">His dining room is also beautifully adorned with antiquity. From the tables to the stools to the mats—the <span style=\"text-decoration: underline; background-color: #f4d24a;\"><strong data-path-to-node=\"8\" data-index-in-node=\"106\">(14) <span class=\"citation-321\">chairs</span></strong></span><span class=\"citation-321 citation-end-321\"> were bought from some Japanese merchants in the area.</span></p>\n<p data-path-to-node=\"9\"><span class=\"citation-320 citation-end-320\">Then looking at the location of his house, which sits some feet higher than surrounding lands, it is possible to see areas of just green lush vegetation that run for miles.</span> <span class=\"citation-319 citation-end-319\">At the backyard, there is a garden which he started himself</span>. He used to care for the plants there personally and made sure they never lacked water.</p>\n<p data-path-to-node=\"10\">He detested fertilizers as he believed that it would spoil the cycle of growth of the plants. In the garden he had some trees—they are not ordinary trees but some <span style=\"text-decoration: underline; background-color: #f4d24a;\"><strong data-path-to-node=\"10\" data-index-in-node=\"163\">(15) rare</strong></span> ones, and they have been alive for decades now.</p>\n<p data-path-to-node=\"11\">Under one of those trees was his favorite spot and history tells us that he used to sing and pray under the tree. Recently, the government brought in some <span style=\"text-decoration: underline; background-color: #f4d24a;\"><strong data-path-to-node=\"11\" data-index-in-node=\"155\">(16) flamingos</strong></span> here as the environment supports their growth and development well.</p>\n<p data-path-to-node=\"12\">They are believed to make the scenery livelier and more beautiful. Although there are many exotic animals in the garden, <span style=\"text-decoration: underline; background-color: #f4d24a;\"><strong data-path-to-node=\"12\" data-index-in-node=\"121\">(17) swans</strong></span> are still the most popular animal here. They seem to be everywhere, and it was said that Barton thought that they were a gift from the heaven.</p>\n<hr>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">Carly:</strong> Now let’s take a look at other interesting places this site has to offer.</p>\n<p data-path-to-node=\"16\">Away from the backyard, there is a <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"16\" data-index-in-node=\"35\">(18) gallery (C)</strong> just at the right side of the road, a few feet from the entrance, and there is usually a history exhibition every week.</span></p>\n<p data-path-to-node=\"17\">Halfway down the path to the east of the toilet, we have the<span style=\"background-color: #f3db7b;\"> <span style=\"text-decoration: underline;\"><strong data-path-to-node=\"17\" data-index-in-node=\"61\">(19) woodland (F)</strong> and the area is just beautiful. Barton decided to have it just because he loved the view.</span></span></p>\n<p data-path-to-node=\"18\"><span style=\"text-decoration: underline; background-color: #f3db7b;\">If you keep walking down the path in front of you to the west of the site, you will see a large <strong data-path-to-node=\"18\" data-index-in-node=\"96\">(20) gift shop (E)</strong> beside the toilet.</span> It has a large collection of handicrafts. These handicrafts are not actually made by Barton himself but are imitations of his artistic works.</p>\n<p data-path-to-node=\"19\">As you have heard enough about this man, we would now proceed to see these things for ourselves and I’m very sure that you will enjoy the tour.</p>"}]', 0);
INSERT INTO public.questions VALUES ('1c6ed4f2-20e4-4872-a65c-8149762165b1', 'c99f28f5-c486-47db-bcc7-5064a8e4300d', 'matrix', 'Questions 18–20', NULL, '<p data-start="628" data-end="710">Write the correct letter, <strong data-start="677" data-end="684">A–F</strong>, next to Questions 18–20.</p>
<p data-start="716" data-end="732"><img src="data:image/png;base64," width="375" height="310" loading="lazy"></p>', 'other', 'null', 'null', 'null', '{"layoutType": "simple", "legendTitle": null, "matrixItems": [{"itemText": "gallery ", "correctCategoryLetter": "C"}, {"itemText": "woodland ", "correctCategoryLetter": "F"}, {"itemText": "gift shop", "correctCategoryLetter": "E"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}]}', '[{"content": "<p>1</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('3edeb46f-2aac-489c-866a-a8a726216d90', '0b56f5a5-2904-4047-a57a-0253b99813c0', 'radio', 'Questions 21–24', NULL, '<p data-start="53" data-end="112">Choose the correct answers</p>
<p data-start="133" data-end="294">
', 'multiple_choice_single', '[{"correct": 1, "options": [{"content": "They are easy to copy."}, {"content": "They are complex."}, {"content": "They are childish."}], "question": "What does Josh think about Jackson Pollock''s paintings?"}, {"correct": 0, "options": [{"content": "it lacked documentation."}, {"content": "it was too cheap."}, {"content": "it featured the wrong colours."}], "question": "The $5 painting was considered to be a fake because"}, {"correct": 1, "options": [{"content": "what was on the back of the painting"}, {"content": "the type of paint used"}, {"content": "how the paint was applied"}], "question": "What made the International Foundation for Art Research reject the $5 painting?"}, {"correct": 2, "options": [{"content": "Only an experienced critic can evaluate a painting''s authenticity."}, {"content": "Modern scientific methods have replaced the traditional approach."}, {"content": "Experts from the science and art worlds should work together."}], "question": "What do Josh and Emily agree about art evaluation?"}]', 'null', 'null', 'null', '[{"content": "<h3 data-path-to-node=\"1\">Part 3</h3>\n<p data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">Josh:</strong> Hi Emily!</p>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Emily:</strong> Hi Josh! Are you ready to work on the assignment?</p>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">Josh:</strong> Yeah. Now, we need to describe how modern scientific techniques are being used in the field of art history.</p>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">Emily:</strong> Right. And Doctor Abbott suggested that we choose some famous cases to illustrate the argument.</p>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">Josh:</strong> Okay, so what have you found?</p>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">Emily:</strong> Well, there’s a Canadian forensic scientist called Biro.</p>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">Josh:</strong> Yes, I think I’ve heard of him. What do you know about him?</p>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">Emily:</strong> Well, I’m a big fan of Jackson Pollock, the modern American artist.</p>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">Josh:</strong> Hmm&#8230; didn’t he paint those really huge abstract paintings?</p>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Emily:</strong> That’s him. I guess it would be pretty easy to fake one of those paintings.</p>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">Josh:</strong> No way, Emily! I know a lot of people think that even a child could paint one. To the untrained eye they might look simple, <span style=\"text-decoration: underline; background-color: #f3db7b;\">but <strong data-path-to-node=\"12\" data-index-in-node=\"134\">(21) they’re incredibly intricate works of art [Answer: B &#8211; complex]</strong>.</span></p>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">Emily:</strong> Well sorry, but I really can’t agree with you. Anyway, what did Biro find out?</p>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">Josh:</strong> Well, Biro worked on a case where a client asked him to prove that a painting she bought for only $5 was an authentic Jackson Pollock.</p>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">Emily:</strong> So was it a fake?</p>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">Josh:</strong> Well, Biro found evidence to show it was a genuine Pollock, but the art world didn’t accept his findings.</p>\n<p data-path-to-node=\"17\"><strong data-path-to-node=\"17\" data-index-in-node=\"0\">Emily:</strong> Why?</p>\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">Josh:</strong> Well, one critic said that compared to other Pollocks, the white and yellow lines on the painting were too straight.</p>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">Emily:</strong> Come on Josh, that doesn’t seem that convincing.</p>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">Josh:</strong> No, you’re right, it is a bit weak. <span style=\"text-decoration: underline; background-color: #f3db7b;\">But <strong data-path-to-node=\"20\" data-index-in-node=\"46\">(22) the strongest argument was that there were no records of previous owners. For the painting to be authentic, you really should be able to trace the painting all the way back to the artist’s studio [Answer: A &#8211; lacked documentation]</strong>.</span></p>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">Josh:</strong> Well, that’s true, I suppose. Did they consult with anyone else?</p>\n<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">Emily:</strong> Hmm&#8230; The International Foundation for Art Research got involved.</p>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">Josh:</strong> And what was their verdict?</p>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">Emily:</strong> Well, they saw a definite similarity in the painting techniques used.</p>\n<p data-path-to-node=\"25\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">Josh:</strong> You mean the way Pollock dripped the oils on the canvas?</p>\n<p data-path-to-node=\"26\"><strong data-path-to-node=\"26\" data-index-in-node=\"0\">Emily:</strong> Yeah. And they noted the dirt and paint marks on the back, which all of Pollock’s paintings have.</p>\n<p data-path-to-node=\"27\"><strong data-path-to-node=\"27\" data-index-in-node=\"0\">Josh:</strong> Why is that?</p>\n<p data-path-to-node=\"28\"><strong data-path-to-node=\"28\" data-index-in-node=\"0\">Emily:</strong> He used to lie his canvases down on the ground when he painted them.<span style=\"text-decoration: underline; background-color: #f3db7b;\"> But <strong data-path-to-node=\"28\" data-index-in-node=\"80\">(23) the foundation were worried about the acrylic paint that was used on the painting. It’s quite common now, but it was very unusual back in Pollock’s day, so it was probably painted much later [Answer: B &#8211; type of paint used]</strong>.</span></p>\n<p data-path-to-node=\"29\"><strong data-path-to-node=\"29\" data-index-in-node=\"0\">Josh:</strong> Right. So, whose side are we on in this argument?</p>\n<p data-path-to-node=\"30\"><strong data-path-to-node=\"30\" data-index-in-node=\"0\">Emily:</strong> When it comes to art, you can see the art critic’s point. If their knowledge and expertise tells them that it definitely isn’t a Pollock painting, shouldn&#8217;t we believe them? I mean, that is usually how it works in the art world, isn’t it?</p>\n<p data-path-to-node=\"31\"><strong data-path-to-node=\"31\" data-index-in-node=\"0\">Josh:</strong> Art historians have always judged paintings, but things are changing now. If we have modern scientific techniques like fingerprint analysis, why not use them?</p>\n<p data-path-to-node=\"32\"><strong data-path-to-node=\"32\" data-index-in-node=\"0\">Emily:</strong> Hmm&#8230; That’s true. Well, <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"32\" data-index-in-node=\"33\">(24) maybe we need a combination. I think you’re right [Answer: C &#8211; experts from the science and art worlds should work together]</strong>.</span></p>\n<hr />\n<p data-path-to-node=\"35\"><strong data-path-to-node=\"35\" data-index-in-node=\"0\">Emily:</strong> So did you find out anything else Josh?</p>\n<p data-path-to-node=\"36\"><strong data-path-to-node=\"36\" data-index-in-node=\"0\">Josh:</strong> Well, have you ever heard of a painting called <em data-path-to-node=\"36\" data-index-in-node=\"53\">The Battle of Anghiari</em>?</p>\n<p data-path-to-node=\"37\"><strong data-path-to-node=\"37\" data-index-in-node=\"0\">Emily:</strong> I have actually. It’s the lost masterpiece by Leonardo da Vinci, the famous Italian artist.</p>\n<p data-path-to-node=\"38\"><strong data-path-to-node=\"38\" data-index-in-node=\"0\">Josh:</strong> What about it?</p>\n<p data-path-to-node=\"39\"><strong data-path-to-node=\"39\" data-index-in-node=\"0\">Emily:</strong> Well, an Italian art analyst called Seracini thinks he knows where it is and he’s using scientific techniques to help locate it.</p>\n<p data-path-to-node=\"40\"><strong data-path-to-node=\"40\" data-index-in-node=\"0\">Josh:</strong> How?</p>\n<p data-path-to-node=\"41\"><strong data-path-to-node=\"41\" data-index-in-node=\"0\">Emily:</strong> Well, art historians knew where the painting was last seen.</p>\n<p data-path-to-node=\"42\"><strong data-path-to-node=\"42\" data-index-in-node=\"0\">Josh:</strong> That’s right, in the Hall of the 500 in Florence.</p>\n<p data-path-to-node=\"43\"><strong data-path-to-node=\"43\" data-index-in-node=\"0\">Emily:</strong> Right. So, Seracini had a theory that the painting was still there and he set out to prove it. He used a lot of different technology like radar and thermographic cameras. <span style=\"text-decoration: underline; background-color: #f3db7b;\">But initially <strong data-path-to-node=\"43\" data-index-in-node=\"192\">(25) he scanned every inch of the hall with a laser in order to make a really accurate 3D model of the building’s design [Answer: D &#8211; a laser scanner]</strong>.</span></p>\n<p data-path-to-node=\"44\"><strong data-path-to-node=\"44\" data-index-in-node=\"0\">Josh:</strong> Did he think the painting was hidden in the building somewhere?</p>\n<p data-path-to-node=\"45\"><strong data-path-to-node=\"45\" data-index-in-node=\"0\">Emily:</strong> Exactly. Then to find out what the hall looked like in Leonardo’s time,<span style=\"text-decoration: underline;\"> <span style=\"background-color: #f3db7b;\"><strong data-path-to-node=\"45\" data-index-in-node=\"79\">(26) he took pictures of it with a thermographic camera [Answer: G &#8211; a thermographic camera]</strong>.</span></span></p>\n<p data-path-to-node=\"46\"><strong data-path-to-node=\"46\" data-index-in-node=\"0\">Josh:</strong> Couldn’t he have used ultrasound to do that?</p>\n<p data-path-to-node=\"47\"><strong data-path-to-node=\"47\" data-index-in-node=\"0\">Emily:</strong> Not really. Different types of building materials produce different amounts of radiat<span class=\"citation-1739 citation-end-1739\">ion and you can really see those differences in a thermal image.</span> <span class=\"citation-1738 citation-end-1738\">So brick would look different from wood or glass, for example.</span></p>\n<div class=\"source-inline-chip-container ng-star-inserted\"></div>\n<p data-path-to-node=\"34\">\n<p data-path-to-node=\"48\"><strong data-path-to-node=\"48\" data-index-in-node=\"0\"><span class=\"citation-1737\">Josh:</span></strong><span class=\"citation-1737 citation-end-1737\"> Yes. Seracini worked out what the building looked like when it was first</span> built and what renovations took place after that. <span style=\"text-decoration: underline; background-color: #f3db7b;\">He found that <strong data-path-to-node=\"48\" data-index-in-node=\"143\">(27) two large glass windows on the east wall had been removed and filled in [Answer: F &#8211; glass]</strong>,</span> leaving a space big enough for it.</p>\n<div class=\"source-inline-chip-container ng-star-inserted\"></div>\n<p data-path-to-node=\"34\">\n<p data-path-to-node=\"49\"><strong data-path-to-node=\"49\" data-index-in-node=\"0\">Emily:</strong> But why hasn’t the painting been seen for 400 years?</p>\n<p data-path-to-node=\"50\"><strong data-path-to-node=\"50\" data-index-in-node=\"0\">Josh:</strong> Hmm&#8230; To answer that question, Seracini needed to study that wall even more closely.</p>\n<p data-path-to-node=\"51\"><strong data-path-to-node=\"51\" data-index-in-node=\"0\">Emily:</strong> Did he use the thermographic camera again?</p>\n<p data-path-to-node=\"52\"><strong data-path-to-node=\"52\" data-index-in-node=\"0\">Josh:</strong> No. <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"52\" data-index-in-node=\"10\">(28) This time he used another kind of technology: radar. And what did that show? It showed there were, in fact, two walls there [Answer: E &#8211; a radar machine]</strong></span>, an older one and a newer one built in front of it.</p>\n<p data-path-to-node=\"53\"><strong data-path-to-node=\"53\" data-index-in-node=\"0\">Emily:</strong> So does Seracini believe that da Vinci’s painting is on the concealed wall?</p>\n<p data-path-to-node=\"54\"><strong data-path-to-node=\"54\" data-index-in-node=\"0\">Josh:</strong> Yes, <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"54\" data-index-in-node=\"11\">(29) on a stone wall concealed by the newer brick wall [Answer: C &#8211; stone]</strong>.</span></p>\n<p data-path-to-node=\"55\"><strong data-path-to-node=\"55\" data-index-in-node=\"0\">Emily:</strong> So what’s the next stage in the investigation?</p>\n<p data-path-to-node=\"56\"><strong data-path-to-node=\"56\" data-index-in-node=\"0\">Josh:</strong> Well, he isn’t allowed to remove any plaster or bricks, <span style=\"text-decoration: underline; background-color: #f3db7b;\">so <strong data-path-to-node=\"56\" data-index-in-node=\"65\">(30) he’s now experimenting with a gamma-ray camera to try and verify his theory [Answer: B &#8211; gamma-ray technology]</strong>.</span></p>\n<p data-path-to-node=\"57\"><strong data-path-to-node=\"57\" data-index-in-node=\"0\">Emily:</strong> Well, I think we’ve got some really strong examples there of how science can help art. Let’s see if we can type up an outline.</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('3dca0521-1b02-41a7-ada4-bacaa9e76735', '0b56f5a5-2904-4047-a57a-0253b99813c0', 'matching', 'Questions 25 – 30', NULL, '<p data-start="53" data-end="143">Complete the flow-chart below.</p>
', 'matching', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p data-start=\"1229\" data-end=\"1293\"><span style=\"font-size: 12pt;\"><strong data-start=\"1229\" data-end=\"1293\">Seracini''s search for Leonardo Da Vinci''s Battle of Anghiari</strong></span></p>\n<p data-start=\"1229\" data-end=\"1293\"> </p>\n<p>• Seracini used {D. a laser scanner} to help make a model of the building.</p>\n<p> </p>\n<p>• Seracini used {G. a thermographic camera} to reveal different materials in the walls. He found the original architecture.</p>\n<p> </p>\n<p>• Seracini guessed that Da Vinci painted his masterpiece on the east wall, in a space that used to hold {F. glass}</p>\n<p> </p>\n<p>• Seracini analysed the wall using {E. a radar machine} and discovered a second wall behind it.</p>\n<p> </p>\n<p>• Seracini hypothesised that the Da Vinci painting is still there on the original {C. stone} wall.</p>\n<p> </p>\n<p>• Seracini is using {B. gamma-ray technology} to prove his theory.</p>", "answerOptions": [{"optionText": "A. ultrasound"}, {"optionText": "B. gamma-ray technology"}, {"optionText": "C. stone"}, {"optionText": "D. a laser scanner"}, {"optionText": "E. a radar machine"}, {"optionText": "F. glass"}, {"optionText": "G. a thermographic camera"}, {"optionText": "H. brick"}], "matchingItems": [{"questionPart": "creating a blank", "correctAnswer": "Stone scoring tool", "sectionContent": null}, {"questionPart": "smoothing the surface", "correctAnswer": "Sandstone block", "sectionContent": null}, {"questionPart": "carving details", "correctAnswer": "Bone point", "sectionContent": null}, {"questionPart": "making holes", "correctAnswer": "Stick drill", "sectionContent": null}, {"questionPart": "fixing coloured decorations", "correctAnswer": "Plant glue", "sectionContent": null}]}', 'null', '[{"content": "<p>1</p>\n"}]', 1);
INSERT INTO public.questions VALUES ('71bb04e5-1601-4d32-a1c0-df043d403107', '2d4b7ba3-7581-4c3a-8c2d-bb45a8e6dbee', 'fillup', 'Questions 31–40', '<article class="text-token-text-primary w-full focus:outline-none [--shadow-height:45px] has-data-writing-block:pointer-events-none has-data-writing-block:-mt-(--shadow-height) has-data-writing-block:pt-(--shadow-height) [&amp;:has([data-writing-block])&gt;*]:pointer-events-auto scroll-mt-[calc(var(--header-height)+min(200px,max(70px,20svh)))]" dir="auto" tabindex="-1" data-turn-id="43fe7f54-581b-4dd6-98a4-ba74f9737acc" data-testid="conversation-turn-415" data-scroll-anchor="false" data-turn="assistant">
<div class="text-base my-auto mx-auto [--thread-content-margin:--spacing(4)] @w-sm/main:[--thread-content-margin:--spacing(6)] @w-lg/main:[--thread-content-margin:--spacing(16)] px-(--thread-content-margin)">
<div class="[--thread-content-max-width:40rem] @w-lg/main:[--thread-content-max-width:48rem] mx-auto max-w-(--thread-content-max-width) flex-1 group/turn-messages focus-visible:outline-hidden relative flex w-full min-w-0 flex-col agent-turn" tabindex="-1">
<div class="flex max-w-full flex-col grow">
<div class="min-h-8 text-message relative flex w-full flex-col items-end gap-2 text-start break-words whitespace-normal [.text-message+&amp;]:mt-1" dir="auto" data-message-author-role="assistant" data-message-id="43fe7f54-581b-4dd6-98a4-ba74f9737acc" data-message-model-slug="gpt-5-2">
<div class="flex w-full flex-col gap-1 empty:hidden first:pt-[1px]">
<p data-start="53" data-end="152">Write <strong data-start="109" data-end="135">NO MORE THAN TWO WORDS</strong> for each answer.</p>
<p style="text-align: left;" data-start="159" data-end="181"><span style="font-size: 12pt;"><strong>Company Outsourcing</strong></span></p>
<p><strong data-start="183" data-end="217">Case study – TCP Technologies:</strong></p>
<p class="markdown prose dark:prose-invert w-full wrap-break-word light markdown-new-styling">Manager: Manjeet Khanna</p>
<p class="markdown prose dark:prose-invert w-full wrap-break-word light markdown-new-styling">Main target: to create a {democratic} environment</p>
<p data-start="314" data-end="685"><strong data-start="314" data-end="336">Grading for staff:</strong></p>
<p data-start="314" data-end="685">• Every month grades are published on an {internal website}</p>
<p data-start="314" data-end="685">• The cultural openness increased the quantity of incoming contracted opportunities.</p>
<p data-start="314" data-end="685">• The cultural openness improved the level of {transparency} of the company.</p>
<p data-start="314" data-end="685">• The increased rate of staff satisfaction has led to growth of 32% in the {company’s income}</p>
<p data-start="314" data-end="685"><strong data-start="687" data-end="708">Recent interview:</strong></p>
<p data-start="687" data-end="854">• A company is not an entity comprised of components, but a living organism composed of cells.</p>
<p data-start="687" data-end="854">• Manjeet’s motto is {employee first}</p>
<p data-start="856" data-end="1055"><strong data-start="856" data-end="889">Benefits of management style:</strong></p>
<p data-start="856" data-end="1055">• The rate of staff turnover has been reduced.</p>
<p data-start="856" data-end="1055">• A {solution} can be from any other company.</p>
<p data-start="856" data-end="1055">• Grades are not used for {promotion}</p>
<p data-start="1057" data-end="1476" data-is-last-node="" data-is-only-node=""><strong data-start="1057" data-end="1088">Features of managing style:</strong></p>
<p data-start="1057" data-end="1476" data-is-last-node="" data-is-only-node="">• Personally, the manager wrote emails to respond to the complaints.</p>
<p data-start="1057" data-end="1476" data-is-last-node="" data-is-only-node="">• The complaint form known as a {ticket} has access to all employees online.</p>
<p data-start="1057" data-end="1476" data-is-last-node="" data-is-only-node="">• The manager can receive any complaints concerning air conditioning, food quality and {vacation} entitlement.</p>
<p data-start="1057" data-end="1476" data-is-last-node="" data-is-only-node="">• A {ban} on the anonymous complaint was introduced in the new system.</p>
</div>
</div>
</div>
<div class="z-0 flex min-h-[46px] justify-start"> </div>
</div>
</div>
</article>
', NULL, 'gap_filling', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"1\"><strong data-path-to-node=\"1\" data-index-in-node=\"0\">PART 4</strong></p>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Dr. Toby Bennett:</strong> Welcome class to your very first lecture in this series on business in the modern world, conducted by myself, Doctor <span class=\"citation-2809 citation-end-2809\">Toby Bennett. Today we will be looking into the practice of company outsourcing, using TCP Technologies as a case study.</span></p>\n<div class=\"source-inline-chip-container ng-star-inserted\"></div>\n<p data-path-to-node=\"2\">\n<p data-path-to-node=\"4\"><span class=\"citation-2808 citation-end-2808\">Now, for those of you who are unfamiliar with this practice, I will give you a summative definition. Company outsourcing involves the contracting of various business activities by one company to another. This practice will sometimes occur from a western c</span>ompany to a party based in a third world country. The rationale being to make significant financial savings on lower international labour rates and to potentially increase quality.</p>\n<div class=\"source-inline-chip-container ng-star-inserted\"></div>\n<p data-path-to-node=\"2\">\n<hr data-path-to-node=\"5\" />\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">Dr. Toby Bennett:</strong> Now our case study for today is TCP Technologies, a party located in India that receives outsourced tasks from western companies. The manager of TCP Technologies is a man called Manjit Karnal, <span class=\"citation-2806 citation-2807 citation-end-2807\">who has personally developed a series of aims and philosophies by which the company is expected to operate.</span></p>\n<div class=\"source-inline-chip-container ng-star-inserted\"></div>\n<p data-path-to-node=\"2\">\n<p data-path-to-node=\"7\"><span class=\"citation-2804 citation-2805 citation-end-2805\">He claims that the most important of these philosophies is to create a workplace where each individual member has the opportunity to contribute their opinion to the operations of the company. </span><span class=\"citation-2804 citation-end-2804\">That is to say that he found it important to de</span>velop a <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"7\" data-index-in-node=\"247\">(31) democratic</strong> </span>environment as a means of ensuring quality from every individual.</p>\n<div class=\"source-inline-chip-container ng-star-inserted\"></div>\n<p data-path-to-node=\"2\">\n<hr data-path-to-node=\"8\" />\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">Dr. Toby Bennett:</strong> <span class=\"citation-2803 citation-end-2803\">At TCP Technologies, a grading system has been developed that encourages an ethos of hard work and recognizes accomplishment. This grading of individuals is based upon a series of factors such as turnover, hours worked an</span>d efficiency.</p>\n<div class=\"source-inline-chip-container ng-star-inserted\"></div>\n<p data-path-to-node=\"2\">\n<p data-path-to-node=\"10\">Every month, Karnal publishes the grades on an<span style=\"text-decoration: underline;\"> <span style=\"background-color: #f3db7b;\"><strong data-path-to-node=\"10\" data-index-in-node=\"47\">(32) <span class=\"citation-2802\">internal website</span></strong></span></span><span class=\"citation-2802 citation-end-2802\"> where staff can access not only their own grades but also compare it to others. A spirit of playful competitiveness has developed through this method, which has resulted in increased efficiency and turnover across the com</span>pany.</p>\n<div class=\"source-inline-chip-container ng-star-inserted\"></div>\n<p data-path-to-node=\"2\">\n<hr data-path-to-node=\"11\" />\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">Dr. Toby Bennett:</strong> Karnal <span class=\"citation-2801 citation-end-2801\">also saw it as essential to develop a culturally diverse group of employees as a means of presenting a multifaceted image that would appeal to a host of potential employees from across the globe. This cultural openness has n</span>ot only increased the quantity of incoming contracted opportunities by 7% but has also benefited the company itself significantly.</p>\n<div class=\"source-inline-chip-container ng-star-inserted\"></div>\n<p data-path-to-node=\"2\">\n<p data-path-to-node=\"13\">A level of <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"13\" data-index-in-node=\"11\">(33) <span class=\"citation-2799 citation-2800\">transparency</span></strong></span><span class=\"citation-2799 citation-2800 citation-end-2800\"> now exists that had not before been apparent. According to questionnaires carried out recently, these newly introduced measures have significantly increased the rate of staff satisfaction, which has subsequently led to an increas</span><span class=\"citation-2799 citation-end-2799\">e of 32% in </span>the <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"13\" data-index-in-node=\"274\">(34) company’s income</strong></span>. These figures are truly admirable and serve as a testament to the measures that Karnal has introduced to the workplace at TCP Technologies.</p>\n<div class=\"source-inline-chip-container ng-star-inserted\"></div>\n<p data-path-to-node=\"2\">\n<hr data-path-to-node=\"14\" />\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">Dr. Toby Bennett:</strong> <span class=\"citation-2797 citation-2798 citation-end-2798\">In a recent interview published by The Economist, he declared, &#8220;The figures speak for themselves. My system works.&#8221; When asked if he had any advice for companies on methods they could employ to streamline workflow and increase turnover, he re</span><span class=\"citation-2797 citation-end-2797\">plied: &#8220;It&#8217;s simple really. A company must see itself not as one entity comprised of nameless components, but instead as a living organism composed of cells, each on</span>e essential to the functioning of the whole. I suggest that the motto by which your management operates will be <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"15\" data-index-in-node=\"537\">(35) employee first</strong></span>.&#8221;</p>\n<div class=\"source-inline-chip-container ng-star-inserted\"></div>\n<p data-path-to-node=\"2\">\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">Dr. Toby Bennett:</strong> Many benefits have been reaped from the aforementioned ch<span class=\"citation-2796\">anges in management style, such as a significant decrease in staff turnover. This improvement alone has solved many problems that had before stunted the growth of the company. A lot of these improvements came from the realization that the </span><span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"16\" data-index-in-node=\"314\"><span class=\"citation-2796\">(36) solution</span></strong></span><span class=\"citation-2796 citation-end-2796\"> does not have to be p</span>roduced internally but ca<span class=\"citation-2795 citation-end-2795\">n come from any other company.</span></p>\n<div class=\"source-inline-chip-container ng-star-inserted\"></div>\n<p data-path-to-node=\"2\">\n<p data-path-to-node=\"17\"><span class=\"citation-2794\">The grading system also immeasurably enhanced the dynamics of the company. The fact that this measuring system is solely produced for staff members and inaccessible by management means that it cannot be used as a judging criterion for </span><span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"17\" data-index-in-node=\"235\"><span class=\"citation-2794\">(37) promotion</span></strong></span><span class=\"citation-2794 citation-end-2794\">. It has proven itself a relaxed and i</span>nformal means of stimulating workflow.</p>\n<div class=\"source-inline-chip-container ng-star-inserted\"></div>\n<p data-path-to-node=\"2\">\n<hr data-path-to-node=\"18\" />\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">Dr. Toby Bennett:</strong> When asked about specific features of his managing style, Karnal mentioned that it is important for him to respond persona<span class=\"citation-2793 citation-end-2793\">lly to any complaints filed by staff members. Having found the existing complaints process slow and ineffective, he introduced a new online system that created a direct line of communication between Karnal and all employees of the company.</span></p>\n<div class=\"source-inline-chip-container ng-star-inserted\"></div>\n<p data-path-to-node=\"2\">\n<p data-path-to-node=\"20\"><span class=\"citation-2792 citation-end-2792\">The comp</span>laint form, dubbed by Karnal as a<span style=\"text-decoration: underline;\"> <span style=\"background-color: #f3db7b;\"><strong data-path-to-node=\"20\" data-index-in-node=\"42\">(38) ticket</strong>,</span></span> eradicates the middleman, is easily accessible <span class=\"citation-2791 citation-end-2791\">to all employees online, and has an interface that can be instinctively navigated. Any staff-related complaint, such as those relating to air conditioning and food quality, can be submitted directly to Karnal via this online system.</span></p>\n<div class=\"source-inline-chip-container ng-star-inserted\"></div>\n<p data-path-to-node=\"2\">\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\"><span class=\"citation-2790 citation-end-2790\"><span style=\"text-decoration: underline; background-color: #f3db7b;\">(39) Vacation</span></span></strong> entitlement is also a popular issue discussed through this forum. The main benefit of using the system is that staff must include their personal details on the ticket before they are able to submit it. In the past, anonymous complaints had been the root of much confusion and caused many wasted work hours. So, the new system has put a <span style=\"text-decoration: underline; background-color: #f3db7b;\"><strong data-path-to-node=\"21\" data-index-in-node=\"350\">(40) ban</strong></span> on this form of complaint.</p>\n<div class=\"source-inline-chip-container ng-star-inserted\"></div>\n<p data-path-to-node=\"2\">\n<p data-path-to-node=\"22\">That wraps up the lecture for today. Please remember that attendance is mandatory.</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('ca5b5d0d-9f69-4eec-9869-ea4b64516a71', '73b79239-1e2f-45b4-b0c3-348156a3b5f9', 'checkbox', 'Questions 27-28', '', '<p data-start="1287" data-end="1313">Choose <strong>TWO </strong>letters, <strong>A</strong>–<strong>E</strong>.</p>
<p data-start="1315" data-end="1381">Which <strong>TWO </strong>additions will Terence make to the section on history?</p>', 'multiple_choice', 'null', '[{"correct": false, "option_text": "A. data about the kings in the Ife area"}, {"correct": true, "option_text": "B. extra information about the surrounding region"}, {"correct": true, "option_text": "C. examination of the beliefs of the Ife people"}, {"correct": false, "option_text": "D. an explanation of the development of modern Ife"}, {"correct": false, "option_text": "E. more details of past activities of the Ife people"}]', 'null', 'null', '[{"content": "<p>1</p>"}]', 2);
INSERT INTO public.questions VALUES ('44a20e7d-31a4-44cd-9f31-d1d89afc865f', 'f5b8f384-9c05-4d1d-b908-27c49676f6dd', 'radio', 'Questions 21–24', '', '<p>Choose the correct answer.</p>
<p class="ql-align-center"><strong>Stone Point: a New Zealand historical site</strong></p>
<p class="ql-align-center"> </p>', 'multiple_choice', '[{"correct": 0, "options": [{"option_text": "it was used for defence or attack purposes."}, {"option_text": "it was the landing point for the first Maori settlers."}, {"option_text": "it was developed as a commercial port."}], "question": "According to Liz, Stone Point played a key role in local history because"}, {"correct": 1, "options": [{"option_text": "its rich soil."}, {"option_text": "the supply of fish."}, {"option_text": "available building materials."}], "question": "Scott and Liz agree that Maori originally chose to inhabit Stone Point because of"}, {"correct": 2, "options": [{"option_text": "will be of interest to international students."}, {"option_text": "is required as a component of their research."}, {"option_text": "would be best avoided."}], "question": "Scott and Liz agree that using Maori terminology in their presentation"}, {"correct": 0, "options": [{"option_text": "focus on the human aspect instead."}, {"option_text": "check the accuracy of specific dates."}, {"option_text": "explain complex technical language."}], "question": "When Scott mentions the engines at Stone Point. Liz advises him to"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Liz:</strong> Hi Scott. Here are my notes. Let’s sort this presentation out then. The first thing I found out about Stone Point is it’s an extinct volcanic cone.</p>\n<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">Scott:</strong> You probably know that already, being a New Zealander.</p>\n<p data-path-to-node=\"5\"><strong data-path-to-node=\"5\" data-index-in-node=\"0\">Liz:</strong> Yes, and there are two other cones nearby which also overlook the harbour.</p>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">Scott:</strong> Right, yeah. The first settlers of New Zealand, the Maori, sailed to New Zealand thousands of years after these volcanoes erupted. I think the tutor allocated us this topic, though, because of Stone Point’s significant historical role. <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"6\" data-index-in-node=\"243\">(Q21) It’s been used by both Maori and European settlers as a place to shelter from attack or launch an attack for centuries.</strong></span></p>\n<p data-path-to-node=\"7\"><strong data-path-to-node=\"7\" data-index-in-node=\"0\">Liz:</strong> Yeah, and the fact it was an ideal place for building a village. It would have been quite a sheltered spot. I suppose the Maori settled there because they thought the volcanic soil would help their crops grow well.</p>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">Scott:</strong> They would have realised the benefits of the soil after a few good harvests, but <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"8\" data-index-in-node=\"88\">(Q22) initially the fishing opportunities would have been the attraction.</strong></span></p>\n<p data-path-to-node=\"9\"><strong data-path-to-node=\"9\" data-index-in-node=\"0\">Liz:</strong> Hmm, you’re right. Actually, I also read that Maori regard Stone Point as taonga. I believe that means a “treasured thing”.</p>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">Scott:</strong> Wow, your Maori vocabulary is improving, Scott!</p>\n<p data-path-to-node=\"11\"><strong data-path-to-node=\"11\" data-index-in-node=\"0\">Liz:</strong> Hmm. We do have to deal with Stone Point’s cultural value for Maori—that’s still part of its historical significance—but <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"11\" data-index-in-node=\"126\">(Q23) we need to keep most Maori terminology out of the presentation. Otherwise, a lot of the international students won’t be able to follow us.</strong></span></p>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">Scott:</strong> That’s a shame. I’m sure they’d be interested. I mean, I am. But yeah, we wouldn’t be able to explain it in the time allowed, so I guess we have to stick to English.</p>\n<p data-path-to-node=\"13\"><strong data-path-to-node=\"13\" data-index-in-node=\"0\">Liz:</strong> Anyway, European migrants turned Stone Point into a lookout point for ships. Then it became a fort, an army base, in the late 1880s. And then during the World Wars, the fort was modernized again. It’s also been a public park. Sometimes I’d prefer to devote more of the presentation to the military use of Stone Point. There are some great websites about the engines they installed.</p>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">Scott:</strong> Sorry, I wouldn’t go into the technical side if I were you. If you start describing mechanical stuff, people will switch off. <strong data-path-to-node=\"14\" data-index-in-node=\"133\"><span style=\"background-color: #f1c40f;\">(Q24) I think it’s more interesting to look at the impact Stone Point had on the people’s lives at the time</span>.</strong> I mean, for example, there were about 25 years when they used local prisoners to build the tunnels and the underground rooms.</p>\n<p data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">Liz:</strong> They lived there too? Yeah, I guess if we can find some first-hand accounts…</p>\n<h2 data-path-to-node=\"17\"> </h2>\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">Scott:</strong> Okay, so let’s make a checklist of things to do. <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"18\" data-index-in-node=\"56\">(Q25) For the early Maori habitation section, we have to look at the material we’ve used again and make sure we know who the writers were and when they wrote it.</strong></span></p>\n<p data-path-to-node=\"19\"><strong data-path-to-node=\"19\" data-index-in-node=\"0\">Liz:</strong> Yes, that needs work. <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"19\" data-index-in-node=\"27\">(Q26) And for the part about Stone Point being used as a lookout point, I’m sure we can locate some drawings of how Stone Point looked then and the kind of ships coming in.</strong></span></p>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">Scott:</strong> Nice. And what else?</p>\n<p data-path-to-node=\"21\"><strong data-path-to-node=\"21\" data-index-in-node=\"0\">Liz:</strong> <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"21\" data-index-in-node=\"5\">(Q27) We haven’t got a lot of detail for the reconstruction of the fort. We should add some more information about what it was the prisoners were adding to it.</strong></span></p>\n<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">Scott:</strong> Okay, I’ll do that bit too.</p>\n<p data-path-to-node=\"23\"><strong data-path-to-node=\"23\" data-index-in-node=\"0\">Liz:</strong> So, I’ll deal with the section regarding the modernization that happened in the 1930s and 40s. I mean, that’s the bit where we have the most visible evidence of historic buildings. <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"23\" data-index-in-node=\"186\">(Q28) I’ll ring the Department of Conservation and see if they’ll agree to let me film the site—maybe allow me access to some of the tunnels the public don’t see.</strong></span></p>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">Scott:</strong> OK. <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"24\" data-index-in-node=\"11\">(Q29) For the 1950s onwards, could you also arrange a meeting with someone from the Department of Conservation to ask them about their restoration work?</strong></span></p>\n<p data-path-to-node=\"25\"><strong data-path-to-node=\"25\" data-index-in-node=\"0\">Liz:</strong> I could try. Oh, and just about its use as a public park today—<span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"25\" data-index-in-node=\"68\">(Q30) where is the boundary exactly? Does it go all the way to the beach?</strong></span></p>\n<p data-path-to-node=\"26\"><strong data-path-to-node=\"26\" data-index-in-node=\"0\">Scott:</strong> Not sure. I’ll check that out.</p>\n<p data-path-to-node=\"27\"><strong data-path-to-node=\"27\" data-index-in-node=\"0\">Liz:</strong> Great. I suppose it would finish off the presentation nicely if we explain the future plans for the site.</p>"}]', 0);
INSERT INTO public.questions VALUES ('b806bd28-ca60-450d-b730-f642981bf321', 'f5b8f384-9c05-4d1d-b908-27c49676f6dd', 'matching', 'Questions 25–30', '', '<p>What do Liz and Scott agree they must do for each of the following sections of their presentation on Stone Point?</p>
<p>Choose <strong>SIX</strong> correct answers, <strong>A-H.</strong></p>', 'summary_completion', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p><strong>Sections of Presentation</strong></p>\n<p> </p>\n<p>Early Maori inhabitation of Stone Point {D check authors details}</p>\n<p> </p>\n<p>The use of Stone Point as a lookout point  {B find images}</p>\n<p> </p>\n<p>The reconstruction of the fort {A provide further description}</p>\n<p> </p>\n<p>Modernisation of the fort in the 1930s-40s {F obtain official permission}</p>\n<p> </p>\n<p>Uses of Stone Point from 1950s to the present day {C set up an interview}</p>\n<p> </p>\n<p>The use of Stone Point as a public park {E check the exact location}<br><br></p>", "answerOptions": [{"optionText": "A provide further description"}, {"optionText": "B find images"}, {"optionText": "C set up an interview"}, {"optionText": "D check authors details"}, {"optionText": "E check the exact location"}, {"optionText": "F obtain official permission"}, {"optionText": "G be more objective"}, {"optionText": "H reduce it in length"}], "matchingItems": []}', 'null', 'null', 1);
INSERT INTO public.questions VALUES ('86bcc74f-f852-4d27-9b4c-6b5f42a56d45', 'bb086638-0175-44d3-9399-776a8034b7d5', 'radio', 'Questions 1-8', '', '<p>Choose <strong>TRUE</strong> if the statement agrees with the information,<strong>FALSE</strong> if the statement contradicts the information,<strong>NOT GIVEN</strong> if there is no information on this</p>', 'true_false_not_given', '[{"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Ochre was used in paintings before it was used in fabric dyes."}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Natural dyes that need a mordant are rare."}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "In medieval times, people sometimes wore fabric made of undyed wool."}, {"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Silk has always been more expensive than cotton and wool."}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Cotton imported from India was dyed upon arrival in Europe."}, {"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Perkin became more famous than his teacher, von Hofmann."}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Very few synthetic dyes were produced in Europe in the second half of the 19th century."}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Today, the commercial production of natural dyes is limited to a small number of isolated communities."}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">1. Ochre was used in paintings before it was used in fabric dyes. — {TRUE}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 1):</strong> * <em data-path-to-node=\"5,0,0\" data-index-in-node=\"22\">“Scientists have been able to date the… pigments made from <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"83\">ochre, used in cave paintings, to over 15,000 BCE</strong>.”</em></p>\n<ul data-path-to-node=\"5,0,1\">\n<li>\n<p data-path-to-node=\"5,0,1,0,0\"><em data-path-to-node=\"5,0,1,0,0\" data-index-in-node=\"0\">“With the development of fixed settlements and agriculture, around <strong data-path-to-node=\"5,0,1,0,0\" data-index-in-node=\"67\">7,000 to 2,000 BCE</strong>, people began to produce <strong data-path-to-node=\"5,0,1,0,0\" data-index-in-node=\"111\">fabrics and used natural substances such as ochre to color them</strong>.”</em></p>\n</li>\n</ul>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Mốc 15,000 BCE (tranh hang động) diễn ra trước mốc 7,000 BCE (nhuộm vải). Do đó, Ochre được dùng làm tranh trước khi dùng làm thuốc nhuộm vải là chính xác.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">2. Natural dyes that need a mordant are rare. — {FALSE}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 2):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">“<strong data-path-to-node=\"7,0,0\" data-index-in-node=\"21\">Most</strong> natural dyes are adjective dyes and <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"62\">require the application of a mordant solution</strong> to the fibers at some point in the dyeing process.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc dùng từ <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"28\">“Most”</strong> (phần lớn/hầu hết), trong khi câu hỏi dùng từ <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"81\">“rare”</strong> (hiếm). Hai thông tin này đối lập hoàn toàn nên đáp án là False.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">3. In medieval times, people sometimes wore fabric made of undyed wool. — {TRUE}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 3):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">“It [wool] was a common <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"44\">medieval</strong> fabric worn in <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"68\">both dyed and natural colors</strong>…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “Natural colors” (màu tự nhiên của lông cừu) đồng nghĩa với việc vải không qua nhuộm (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"98\">undyed wool</strong>). Vì vậy, khẳng định người xưa đôi khi mặc vải len chưa nhuộm là đúng.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">4. Silk has always been more expensive than cotton and wool. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 3):</strong> Đoạn này có nhắc Silk được nhập từ Trung Quốc và yêu cầu thuốc nhuộm chất lượng cao nhất; Cotton thì được coi là “luxury fabric” (vải xa xỉ) ở châu Âu.</p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ nêu đặc điểm của từng loại vải chứ <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"59\">không thực hiện phép so sánh giá cả</strong> (more expensive) giữa Silk với Cotton và Wool xuyên suốt lịch sử. Chúng ta không có căn cứ để xác nhận thông tin này.</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">5. Cotton imported from India was dyed upon arrival in Europe. — {FALSE}</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 3):</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"20\">“Cotton… was imported all the way from India and <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"71\">was dyed before it was shipped</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi nói cotton được nhuộm khi vừa đến châu Âu (upon arrival), nhưng dẫn chứng khẳng định nó được nhuộm ở Ấn Độ <strong data-path-to-node=\"13,1,0\" data-index-in-node=\"127\">trước khi được vận chuyển đi</strong> (before shipped).</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">6. Perkin became more famous than his teacher, von Hofmann. — {NOT GIVEN}</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 6):</strong> <em data-path-to-node=\"15,0,0\" data-index-in-node=\"20\">“W.H. Perkin, a student of celebrated European scientist Wilhelm von Hofmann, accidentally discovered the first synthetic dye…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ giới thiệu mối quan hệ thầy trò và thành tựu của Perkin (mở nhà máy, phát triển thuốc nhuộm tổng hợp), nhưng <strong data-path-to-node=\"15,1,0\" data-index-in-node=\"133\">không hề so sánh ai nổi tiếng hơn ai</strong> (more famous than).</p>\n</li>\n</ul>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">7. Very few synthetic dyes were produced in Europe in the second half of the 19th century. — {FALSE}</strong></p>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong data-path-to-node=\"17,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 6):</strong> <em data-path-to-node=\"17,0,0\" data-index-in-node=\"20\">“Synthetic dye production grew in Europe, and <strong data-path-to-node=\"17,0,0\" data-index-in-node=\"66\">hardly a year passed until the end of the century without a new synthetic dye being patented</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong data-path-to-node=\"17,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cấu trúc “hardly a year passed without…” (hầu như không năm nào trôi qua mà không có…) ám chỉ sự bùng nổ, rất nhiều thuốc nhuộm mới ra đời. Điều này trái ngược với thông tin <strong data-path-to-node=\"17,1,0\" data-index-in-node=\"190\">“very few”</strong> (rất ít).</p>\n</li>\n</ul>\n<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">8. Today, the commercial production of natural dyes is limited to a small number of isolated communities. — {TRUE}</strong></p>\n<ul data-path-to-node=\"19\">\n<li>\n<p data-path-to-node=\"19,0,0\"><strong data-path-to-node=\"19,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 7):</strong> <em data-path-to-node=\"19,0,0\" data-index-in-node=\"20\">“…now the use of natural dyes on a commercial scale <strong data-path-to-node=\"19,0,0\" data-index-in-node=\"74\">only exists in a few remote areas</strong> where people have… little access to synthetic dyes…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"19,1,0\"><strong data-path-to-node=\"19,1,0\" data-index-in-node=\"0\">Giải thích:</strong> “A few remote areas” (một vài vùng xa xôi) đồng nghĩa với “a small number of isolated communities” (một số ít các cộng đồng biệt lập). Khẳng định này khớp với bài đọc.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('ae18c094-f1f7-46a3-a2a4-669c6e34f56a', 'bb086638-0175-44d3-9399-776a8034b7d5', 'fillup', 'Questions 9-13', '<p data-path-to-node="17">Complete the summary below.</p>
<p data-path-to-node="17">Choose <strong data-path-to-node="17" data-index-in-node="35">ONE WORD ONLY</strong> from the passage for each answer.</p>
<p>Write your answers in boxes 9-13 on your answer sheet.</p>
<p><span style="font-size: 14pt;"><strong>The history of some dyes</strong></span></p>
<p><strong>Highly valued dyes</strong></p>
<ul>
<li>
<p>Tyrian purple</p>
<ul>
<li>
<p>Mucus from {shellfish} found in the Mediterranean</p>
</li>
</ul>
</li>
<li>
<p>Cochineal (a red dye)</p>
<ul>
<li>
<p>Made from {insects} found in Latin America</p>
</li>
</ul>
</li>
<li>
<p>Saffron (a yellow dye)</p>
<ul>
<li>
<p>Initially made from crocuses found on the island of Crete</p>
</li>
</ul>
</li>
<li>
<p>Indigo (a blue dye)</p>
<ul>
<li>
<p>Made from plant leaves from India</p>
</li>
</ul>
</li>
</ul>
<p>17th Century Europe</p>
<p><strong>Dyes made by country people:</strong></p>
<ul>
<li>
<p>{blackberries} had two uses</p>
<ul>
<li>
<p>Jam</p>
</li>
<li>
<p>Blue dye</p>
</li>
</ul>
</li>
<li>
<p>Liquid from cleaning {beehives} had two uses</p>
<ul>
<li>
<p>Making mead</p>
</li>
<li>
<p>Yellow dye</p>
</li>
</ul>
</li>
</ul>
<p><strong>19th Century Europe</strong></p>
<ul>
<li>
<p>Progress in study of {chemistry} led to synthetic dyes</p>
</li>
</ul>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">9. shellfish — {Mucus from shellfish found in the Mediterranean}</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 4):</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"20\">“…the mucus found in certain species of <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"62\">shellfish</strong> produced the deep rich <strong data-path-to-node=\"5,0,0\" data-index-in-node=\"95\">Tyrian purple</strong>…”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Màu tím Tyrian huyền thoại được chiết xuất từ chất nhầy của một loài động vật có vỏ (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"97\">shellfish</strong>) ở vùng Địa Trung Hải.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">10. insects — {Cochineal (a red dye) … Made from insects}</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 4):</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"20\">“…and <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"28\">cochineal</strong> was the name given to the red dye from Latin America… [which] was extracted from <strong data-path-to-node=\"7,0,0\" data-index-in-node=\"121\">insects</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cochineal là loại thuốc nhuộm đỏ nổi tiếng được lấy từ một loài côn trùng (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"87\">insects</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">11. blackberries — {blackberries had two uses: Jam / Blue dye}</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 5):</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"20\">“People who picked <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"39\">blackberries</strong> to make <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"60\">jam</strong> soon recognized this wild fruit as a source for a <strong data-path-to-node=\"9,0,0\" data-index-in-node=\"114\">blue dye</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Ở vùng nông thôn, quả dâu tằm/mâm xôi đen (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"55\">blackberries</strong>) vừa được dùng làm mứt (jam), vừa là nguồn tạo ra thuốc nhuộm màu xanh.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">12. beehives — {Liquid from cleaning beehives had two uses: Making mead / Yellow dye}</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 5):</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"20\">“Washing <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"29\">beehives</strong> in preparation for making <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"64\">mead</strong>… yielded a liquid that could be used as a <strong data-path-to-node=\"11,0,0\" data-index-in-node=\"113\">yellow dye</strong>.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc tẩy rửa các tổ ong (<strong data-path-to-node=\"11,1,0\" data-index-in-node=\"37\">beehives</strong>) để lấy nguyên liệu làm rượu mật ong (mead) tạo ra một loại dung dịch dùng để nhuộm màu vàng.</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">13. chemistry — {Progress in study of chemistry led to synthetic dyes}</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng (Đoạn 6):</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"20\">“With the tremendous rise of interest in <strong data-path-to-node=\"13,0,0\" data-index-in-node=\"61\">chemistry</strong> in the mid-19th century, several important innovations in dyeing came about [synthetic dye].”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Sự tiến bộ và hứng thú trong nghiên cứu hóa học (<strong data-path-to-node=\"13,1,0\" data-index-in-node=\"61\">chemistry</strong>) vào giữa thế kỷ 19 đã dẫn đến sự ra đời của thuốc nhuộm tổng hợp (synthetic dyes).</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('c483e263-93de-4acd-bd71-0581b774c758', 'fe82cd76-3568-43cf-b16f-fe30d4cc4ced', 'checkbox', 'Questions 21 and 22', '', '<p data-start="36" data-end="64">Choose <strong>TWO </strong>letters, <strong>A</strong>–<strong>E</strong>.</p>
<p data-start="66" data-end="144">What were Monderman’s <strong>TWO </strong>aims when promoting the idea of ‘shared spaces’?</p>', 'multiple_choice', 'null', '[{"correct": true, "option_text": "A. to improve safety"}, {"correct": true, "option_text": "B. to encourage walking"}, {"correct": false, "option_text": "C. to improve the flow of vehicles"}, {"correct": false, "option_text": "D. to improve the appearance of streets"}, {"correct": false, "option_text": "E. to calculate optimum driving speeds"}]', 'null', 'null', 'null', 0);
INSERT INTO public.questions VALUES ('962b8223-93ce-464a-adab-5c6aab21ddbd', 'fe82cd76-3568-43cf-b16f-fe30d4cc4ced', 'checkbox', 'Questions 23 and 24', '', '<p data-start="425" data-end="453">Choose <strong>TWO </strong>letters, <strong>A</strong>–<strong>E</strong>.</p>
<p data-start="455" data-end="508">Which <strong>TWO </strong>statements summarise Monderman’s ideas?</p>', 'multiple_choice', 'null', '[{"correct": false, "option_text": "A. Rules should be regularly updated"}, {"correct": false, "option_text": "B. Anyone can be a competent driver"}, {"correct": true, "option_text": "C. Ineffective street furniture should be removed"}, {"correct": false, "option_text": "D. Town centres need to be continually modernised"}, {"correct": true, "option_text": "E. More rules make drivers behave less responsibly"}]', 'null', 'null', 'null', 1);
INSERT INTO public.questions VALUES ('347ef33a-9286-462c-b6a7-46e9b4662b05', '4fe8c9c6-f8bc-4772-b785-5e29235f58a4', 'fillup', 'Questions 1-10', '<p class="MsoNormal">Complete the notes below.</p>
<p class="MsoNormal">Write <strong>ONE WORD AND/OR NUMBER</strong> for each answer.</p>
<p class="MsoNormal" style="text-align: left;" align="center"><strong><span style="font-size: 14.0pt; line-height: 115%;">Building Work</span></strong></p>
<p class="MsoNormal">Address: 15 Hill Street</p>
<p class="MsoNormal"><strong>Contact information</strong></p>
<ul style="margin-top: 0in;" type="disc">
<li class="MsoNormal" style="mso-list: l11 level1 lfo1; tab-stops: list .5in;">
<p>Name: Sally {Keyworth}</p>
</li>
<li class="MsoNormal" style="mso-list: l11 level1 lfo1; tab-stops: list .5in;">
<p>phone: 027 584 6613</p>
</li>
</ul>
<p><strong>Kitchen</strong></p>
<ul style="margin-top: 0in;" type="disc">
<li class="MsoNormal" style="mso-list: l6 level1 lfo3; tab-stops: list .5in;">
<p>needs a bigger window</p>
</li>
<li class="MsoNormal" style="mso-list: l6 level1 lfo3; tab-stops: list .5in;">
<p>the kitchen is too hot – fit a {fan}</p>
</li>
</ul>
<p class="MsoNormal"><strong>Bathroom</strong></p>
<ul style="margin-top: 0in;" type="disc">
<li class="MsoNormal" style="mso-list: l5 level1 lfo5; tab-stops: list .5in;">
<p>put in a {shower} on the back wall</p>
</li>
<li class="MsoNormal" style="mso-list: l5 level1 lfo5; tab-stops: list .5in;">
<p>decide the {colour|color} of the small tiles later</p>
</li>
</ul>
<p class="MsoNormal"><strong>Outside</strong></p>
<ul style="margin-top: 0in;" type="disc">
<li class="MsoNormal" style="mso-list: l1 level1 lfo7; tab-stops: list .5in;">
<p>put a higher {gate} in the garden</p>
</li>
<li class="MsoNormal" style="mso-list: l1 level1 lfo7; tab-stops: list .5in;">
<p>put a new {lock} on the garage door</p>
</li>
<li class="MsoNormal" style="mso-list: l1 level1 lfo7; tab-stops: list .5in;">
<p>fix the roof – it was damaged by a {storm}</p>
</li>
<li class="MsoNormal" style="mso-list: l1 level1 lfo7; tab-stops: list .5in;">
<p>fit a new rain gutter made of {plastic}</p>
</li>
</ul>
<p class="MsoNormal"><strong>Other information</strong></p>
<ul style="margin-top: 0in;" type="disc">
<li class="MsoNormal" style="mso-list: l4 level1 lfo11; tab-stops: list .5in;">
<p>start date: {May 8th | 8 May | 8th May| May 8}</p>
</li>
</ul>
<ul style="margin-top: 0in;" type="disc">
<li class="MsoNormal" style="mso-list: l3 level1 lfo12; tab-stops: list .5in;">
<p>security code: {AG4176}</p>
</li>
</ul>', NULL, 'fill-in-the-blank', 'null', 'null', 'null', 'null', '[{"content": "<p class=\"MsoNormal\"><strong>PART 1</strong></p>\n<p class=\"MsoNormal\"><strong>Sally:</strong> Morning, thanks for coming round. I’m Sally.</p>\n<p class=\"MsoNormal\"><strong>Builder:</strong> Morning. Um, so just before we get started, I’ll just make a few notes. So um, we’re at 15 Hill Street?</p>\n<p class=\"MsoNormal\"><strong>Sally:</strong> Yes, that’s right.</p>\n<p class=\"MsoNormal\"><strong>Builder:</strong> Okay great. And then I need to write down your contact information just for the office, you know. So first, what’s your surname please Sally?</p>\n<p class=\"MsoNormal\"><strong>Sally:</strong> It’s <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>(1) Keyworth</strong></span>. I’ll spell that: K-E-Y-W-O-R-T-H.</p>\n<p class=\"MsoNormal\"><strong>Builder:</strong> And your phone number? I’ve got that somewhere… yes, 027 584 6613.</p>\n<p class=\"MsoNormal\"><strong>Sally:</strong> That’s right.</p>\n<p class=\"MsoNormal\"><strong>Builder:</strong> OK Sally, so what building work would you like to have done?</p>\n<p class=\"MsoNormal\"><strong>Sally:</strong> Well, let’s go into the kitchen first. So you see it’s quite dark in here. We’ve tried having a few lights fitted, but it hasn’t really made any difference. So what we’ve decided is the window is too small; we’d like a larger one.</p>\n<p class=\"MsoNormal\"><strong>Builder:</strong> That shouldn’t be a problem. And is there anything else you’d like done in the kitchen?</p>\n<p class=\"MsoNormal\"><strong>Sally:</strong> Well, at this time of year—I mean I shouldn’t complain really—but I wish it wasn’t so hot in here. Is there anything you can do about that?</p>\n<p class=\"MsoNormal\"><strong>Builder:</strong> Air conditioning?</p>\n<p class=\"MsoNormal\"><strong>Sally:</strong> It’s too expensive.</p>\n<p class=\"MsoNormal\"><strong>Builder:</strong> How about a <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>(2) fan</strong></span> then?</p>\n<p class=\"MsoNormal\"><strong>Sally:</strong> Yes, that would be perfect.</p>\n<p class=\"MsoNormal\"><strong>Builder:</strong> Alright. Oh, and what’s next Sally?</p>\n<p class=\"MsoNormal\"><strong>Sally:</strong> Well, if we walk through into the bathroom… the thing is, when my father’s staying, he can’t use the bath. So I thought here on the back wall, I’d like you to fit a <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>(3) shower</strong>.</span> Is that possible?</p>\n<p class=\"MsoNormal\"><strong>Builder:</strong> Shouldn’t be too hard. I’ll get you some brochures because there are a few ways of doing that.</p>\n<p class=\"MsoNormal\"><strong>Sally:</strong> Thanks.</p>\n<p class=\"MsoNormal\"><strong>Builder</strong>: Now those tiles on the wall look new, so do you want to keep those?</p>\n<p class=\"MsoNormal\"><strong>Sally:</strong> Yes, the tiles are new, but actually my husband doesn’t like them. We want to change to those very small ones. But do I have to choose a<span style=\"text-decoration: underline;\"> <span style=\"background-color: #ffe786;\"><strong>(4) colour</strong> (hoặc <strong>color</strong>) </span></span>now?</p>\n<p class=\"MsoNormal\"><strong>Builder:</strong> You can do that later. I’ll get some charts for you to look at.</p>\n<div class=\"MsoNormal\" style=\"text-align: center;\" align=\"center\">\n<hr align=\"center\" size=\"2\" width=\"100%\"></div>\n<p class=\"MsoNormal\"><strong>Sally:</strong> Now the last thing, let’s walk outside. I need to show you some things outside the house.</p>\n<p class=\"MsoNormal\"><strong>Builder:</strong> Right out… oh, nice garden! And the fence looks in good condition.</p>\n<p class=\"MsoNormal\"><strong>Sally:</strong> Yes, it’s new. But the thing is the <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>(5) gate</strong></span>; it’s too low. You have to bend down to open it. We need something that’s higher.</p>\n<p class=\"MsoNormal\"><strong>Builder:</strong> Right, I’ll see to that.</p>\n<p class=\"MsoNormal\"><strong>Sally:</strong> Then the other thing is the garage here. We had a break-in actually.</p>\n<p class=\"MsoNormal\"><strong>Builder:</strong> Uh yeah, I can see. Um, the door should be fine but the <span style=\"text-decoration: underline;\"><span style=\"background-color: #ffe786;\"><strong>(6) lock</strong>.</span></span>.. I’ll replace that shall I?</p>\n<p class=\"MsoNormal\"><strong>Sally:</strong> Yes thanks. Then also if you step back here and look up on the roof, you can see that it’s damaged.</p>\n<p class=\"MsoNormal\"><strong>Builder:</strong> Did that happen in the <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>(7) storm</strong></span> a couple of weeks ago?</p>\n<p class=\"MsoNormal\"><strong>Sally:</strong> Yes, that’s right.</p>\n<p class=\"MsoNormal\"><strong>Builder: </strong>I’ll get up there and take a look at that then. That might be quite a big job, but I’ll get back to you once I’ve had a look.</p>\n<p class=\"MsoNormal\"><strong>Sally:</strong> OK.</p>\n<p class=\"MsoNormal\"><strong>Builder</strong>:<strong> </strong>I can see that your rain gutter is broken as well.</p>\n<p class=\"MsoNormal\"><strong>Sally</strong>: Can you fix that?</p>\n<p class=\"MsoNormal\"><strong>Builder:</strong> Well, I’ll need to replace it, maybe with a steel one. It’ll be stronger.</p>\n<p class=\"MsoNormal\"><strong>Sally:</strong> No, <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>(8) plastic</strong></span> will be fine thanks. It’s cheaper.</p>\n<p class=\"MsoNormal\"><strong>Builder:</strong> Okay.</p>\n<p class=\"MsoNormal\"><strong>Sally: </strong>And that’s everything I think. Is there any other information you need? What about a start date?</p>\n<p class=\"MsoNormal\"><strong>Builder:</strong> Well, I’m completely booked all April, and I’ve got a job on May the 5th. That’ll be a few days, so let’s say <span style=\"text-decoration: underline;\"><span style=\"background-color: #ffe786;\"><strong>(9) May 8th</strong> (hoặc <strong>8 May / 8th May</strong>).</span></span></p>\n<p class=\"MsoNormal\"><strong>Sally:</strong> Okay.</p>\n<p class=\"MsoNormal\"><strong>Builder</strong>: Now what about a key in case you’re out?</p>\n<p class=\"MsoNormal\"><strong>Sally:</strong> We have a security code, I’ll give you that. It’s a mix of letters and numbers. The code is <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>(10) AG4176</strong>.</span></p>\n<p class=\"MsoNormal\"><strong>Builder:</strong> Got that. Okay, we’ll organize some…</p>\n"}]', 0);
INSERT INTO public.questions VALUES ('726e325e-2cc7-4e1c-95ad-d0f1fe86afaf', 'c405373c-b159-4dd3-b478-ac465dd8d135', 'radio', 'Questions 21–24', '', '<p>Choose the correct letter, <strong data-path-to-node="5" data-index-in-node="27">A</strong>, <strong data-path-to-node="5" data-index-in-node="30">B</strong> or <strong data-path-to-node="5" data-index-in-node="35">C</strong>.</p>', 'multiple_choice', '[{"correct": 0, "options": [{"option_text": "A   limited in scope."}, {"option_text": "B   hard to research."}, {"option_text": "C   boring for listeners."}], "question": "At first, Don thought the topic of recycling footwear might be too"}, {"correct": 1, "options": [{"option_text": "A   how popular they are among young people."}, {"option_text": "B   how suitable they are for school."}, {"option_text": "C   how quickly they wear out."}], "question": "When discussing trainers, Bella and Don disagree about"}, {"correct": 1, "options": [{"option_text": "A   they no longer fit."}, {"option_text": "B   she no longer likes them."}, {"option_text": "C   they are no longer in fashion."}], "question": "Bella says that she sometimes recycles shoes because"}, {"correct": 1, "options": [{"option_text": "A   Public consumption of footwear has risen."}, {"option_text": "B   Less footwear is recycled now than in the past."}, {"option_text": "C   People dispose of more footwear than they used to."}], "question": "What did the article say that confused Don?"}]', 'null', 'null', 'null', '[{"content": "<p>1</p>"}]', 0);
INSERT INTO public.questions VALUES ('7f0bb03b-6adb-41cb-868d-5aaa004603b0', 'c405373c-b159-4dd3-b478-ac465dd8d135', 'matching', 'Questions 25–28', '', '<p>Choose <strong>FOUR</strong> answers from the box and write the correct letter, <strong>A–F</strong>, next to Questions 25–28.</p>', 'summary_completion', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p>the high-heeled shoes {E the shoes were too dirty}</p>\n<p> </p>\n<p>the ankle boots {B the colour of one shoe had faded}</p>\n<p> </p>\n<p>the baby shoes {A one shoe was missing}</p>\n<p> </p>\n<p>the trainers {C one shoe had a hole in it}</p>", "answerOptions": [{"optionText": "A one shoe was missing"}, {"optionText": "B the colour of one shoe had faded"}, {"optionText": "C one shoe had a hole in it"}, {"optionText": "D the shoes were brand new"}, {"optionText": "E the shoes were too dirty"}, {"optionText": "F the stitching on the shoes was broken"}], "matchingItems": []}', 'null', '[{"content": "<p>1</p>"}]', 1);
INSERT INTO public.questions VALUES ('ef9ffd87-ae96-4a42-b449-3d95ccc53e9f', 'c405373c-b159-4dd3-b478-ac465dd8d135', 'radio', 'Questions 29–30', '', '<p>Choose the correct letter, <strong data-path-to-node="23" data-index-in-node="27">A</strong>, <strong data-path-to-node="23" data-index-in-node="30">B</strong> or <strong data-path-to-node="23" data-index-in-node="35">C</strong>.</p>', 'multiple_choice', '[{"correct": 2, "options": [{"option_text": "A   People believed the ''new'' pairs of shoes were unhygienic."}, {"option_text": "B   There were not enough good parts to use in the old shoes."}, {"option_text": "C   The shoes in the ''new'' pairs were not completely alike."}], "question": "Why did the project to make ''new'' shoes out of old shoes fail?"}, {"correct": 0, "options": [{"option_text": "A   from a new angle."}, {"option_text": "B   with relevant images."}, {"option_text": "C   in a straightforward way."}], "question": "Bella and Don agree that they can present their topic"}]', 'null', 'null', 'null', '[{"content": "<p>1</p>"}]', 2);
INSERT INTO public.questions VALUES ('64786e2d-088c-46d2-9777-4c5e83071992', '7c5b88f6-258d-4f20-a5cd-2b755e554ff8', 'fillup', 'Questions 31–40', '<p id="p-rc_b815457bdca5c7fd-606" data-path-to-node="3"><span class="citation-69471 citation-end-69471">Complete the notes below.<sup class="superscript" data-turn-source-index="1"><!----></sup></span></p>
<div class="source-inline-chip-container ng-star-inserted"><!----><!----></div>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>
<p id="p-rc_b815457bdca5c7fd-607" data-path-to-node="4"><span class="citation-69470">Write </span><strong data-path-to-node="4" data-index-in-node="6"><span class="citation-69470">ONE WORD ONLY</span></strong><span class="citation-69470 citation-end-69470"> for each answer.</span></p>
<table style="border-collapse: collapse; width: 99.9592%; height: 2px; border-spacing: 2px; border: 2px solid #000000;" border="1"><colgroup><col style="width: 99.8776%;"></colgroup>
<tbody>
<tr>
<td style="border-width: 2px; padding: 2px; border-color: #000000;">
<p style="text-align: left;" data-path-to-node="5"><strong data-path-to-node="5" data-index-in-node="0"><span class="citation-69469 citation-end-69469"><span style="font-size: 14pt;">Tardigrades</span><sup class="superscript" data-turn-source-index="3"><!----></sup></span></strong></p>
<ul data-path-to-node="6">
<li>
<p id="p-rc_b815457bdca5c7fd-608" data-path-to-node="6,0,0"><span class="citation-69468">more than 1,000 sp</span><span class="citation-69466 citation-69467 citation-69468 citation-end-69468">ecies, 0.05–1.2 millimetres long<sup class="superscript" data-turn-source-index="4"><!----></sup></span><span class="citation-69466 citation-69467 citation-end-69467"><sup class="superscript" data-turn-source-index="5"><!----></sup></span><span class="citation-69466 citation-end-69466"><sup class="superscript" data-turn-source-index="6"><!----></sup></span></p>
<p class="source-inline-chip-container ng-star-inserted"><!----><!----></p>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>
</li>
<li>
<p id="p-rc_b815457bdca5c7fd-609" data-path-to-node="6,1,0"><span class="citation-69463 citation-69464 citation-69465">also known as water ‘bears’ (due to how they {move}</span><span class="citation-69463 citation-69464 citation-69465 citation-end-69465">) and ‘moss piglets’<sup class="superscript" data-turn-source-index="7"><!----></sup></span><span class="citation-69463 citation-69464 citation-end-69464"><sup class="superscript" data-turn-source-index="8"><!----></sup></span><span class="citation-69463 citation-end-69463"><sup class="superscript" data-turn-source-index="9"><!----></sup></span></p>
<p class="source-inline-chip-container ng-star-inserted"><!----><!----></p>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>
</li>
</ul>
<p data-path-to-node="7"><strong data-path-to-node="7" data-index-in-node="0"><span class="citation-69460 citation-69461 citation-69462 citation-end-69462">Physical appearance<sup class="superscript" data-turn-source-index="10"><!----></sup></span><span class="citation-69460 citation-69461 citation-end-69461"><sup class="superscript" data-turn-source-index="11"><!----></sup></span><span class="citation-69460 citation-end-69460"><sup class="superscript" data-turn-source-index="12"><!----></sup></span></strong></p>
<ul data-path-to-node="8">
<li>
<p id="p-rc_b815457bdca5c7fd-610" data-path-to-node="8,0,0"><span class="citation-69457 citation-69458 citation-69459">a {short}</span><span class="citation-69457 citation-69458 citation-end-69458"> round body and four pairs of legs<sup class="superscript" data-turn-source-index="14"><!----></sup></span><span class="citation-69457 citation-end-69457"><sup class="superscript" data-turn-source-index="15"><!----></sup></span></p>
<p class="source-inline-chip-container ng-star-inserted"><!----><!----></p>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>
</li>
<li>
<p id="p-rc_b815457bdca5c7fd-611" data-path-to-node="8,1,0"><span class="citation-69455 citation-69456">claws or {discs}</span><span class="citation-69455 citation-69456 citation-end-69456"> for gripping<sup class="superscript" data-turn-source-index="16"><!----></sup></span><span class="citation-69455 citation-end-69455"><sup class="superscript" data-turn-source-index="17"><!----></sup></span></p>
<p class="source-inline-chip-container ng-star-inserted"><!----><!----></p>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>
</li>
<li>
<p id="p-rc_b815457bdca5c7fd-612" data-path-to-node="8,2,0"><span class="citation-69453 citation-69454 citation-end-69454">absence of respiratory organs<sup class="superscript" data-turn-source-index="18"><!----></sup></span><span class="citation-69453 citation-end-69453"><sup class="superscript" data-turn-source-index="19"><!----></sup></span></p>
<p class="source-inline-chip-container ng-star-inserted"><!----><!----></p>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>
</li>
<li>
<p id="p-rc_b815457bdca5c7fd-613" data-path-to-node="8,3,0"><span class="citation-69451 citation-69452 citation-end-69452">body f<sup class="superscript" data-turn-source-index="20"><!----></sup></span><span class="citation-69451 citation-end-69451">illed with a liquid t<sup class="superscript" data-turn-source-index="21"><!----></sup></span>hat carries both {oxygen} and blood</p>
<p class="source-inline-chip-container ng-star-inserted"><!----><!----></p>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>
</li>
<li>
<p data-path-to-node="8,4,0">mouth shaped like a {tube} with teeth called stylets</p>
</li>
</ul>
<p data-path-to-node="9"><strong data-path-to-node="9" data-index-in-node="0">Habitat</strong></p>
<ul data-path-to-node="10">
<li>
<p id="p-rc_b815457bdca5c7fd-614" data-path-to-node="10,0,0">often found at t<span class="citation-69450 citation-end-69450">he bottom of a lake or on plants<sup class="superscript" data-turn-source-index="22"><!----></sup></span></p>
<p class="source-inline-chip-container ng-star-inserted"><!----><!----></p>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>
</li>
<li>
<p id="p-rc_b815457bdca5c7fd-615" data-path-to-node="10,1,0"><span class="citation-69449">very resilient and can exist in very low or high {temperatures}</span><span class="citation-69449 citation-end-69449"><sup class="superscript" data-turn-source-index="23"><!----></sup></span></p>
<p class="source-inline-chip-container ng-star-inserted"><!----><!----></p>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>
</li>
</ul>
<p data-path-to-node="11"><strong data-path-to-node="11" data-index-in-node="0"><span class="citation-69448 citation-end-69448">Cryptobiosis<sup class="superscript" data-turn-source-index="24"><!----></sup></span></strong></p>
<ul data-path-to-node="12">
<li>
<p id="p-rc_b815457bdca5c7fd-616" data-path-to-node="12,0,0"><span class="citation-69447">In dry conditions, t</span><span class="citation-69445 citation-69446 citation-69447 citation-end-69447">hey roll into a ball called a ‘tun’.<sup class="superscript" data-turn-source-index="25"><!----></sup></span><span class="citation-69445 citation-69446 citation-end-69446"><sup class="superscript" data-turn-source-index="26"><!----></sup></span><span class="citation-69445 citation-end-69445"><sup class="superscript" data-turn-source-index="27"><!----></sup></span></p>
<p class="source-inline-chip-container ng-star-inserted"><!----><!----></p>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>
</li>
<li>
<p id="p-rc_b815457bdca5c7fd-617" data-path-to-node="12,1,0"><span class="citation-69442 citation-69443 citation-69444 citation-end-69444">They stay alive with a much lower metabolism than usual.<sup class="superscript" data-turn-source-index="28"><!----></sup></span><span class="citation-69442 citation-69443 citation-end-69443"><sup class="superscript" data-turn-source-index="29"><!----></sup></span><span class="citation-69442 citation-end-69442"><sup class="superscript" data-turn-source-index="30"><!----></sup></span></p>
<p class="source-inline-chip-container ng-star-inserted"><!----><!----></p>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>
</li>
<li>
<p id="p-rc_b815457bdca5c7fd-618" data-path-to-node="12,2,0"><span class="citation-69439 citation-69440 citation-69441">A type of {protein}</span><span class="citation-69439 citation-69440 citation-end-69440"> ensures their DNA is not damaged.<sup class="superscript" data-turn-source-index="32"><!----></sup></span><span class="citation-69439 citation-end-69439"><sup class="superscript" data-turn-source-index="33"><!----></sup></span></p>
<p class="source-inline-chip-container ng-star-inserted"><!----><!----></p>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>
</li>
<li>
<p id="p-rc_b815457bdca5c7fd-619" data-path-to-node="12,3,0"><span class="citation-69437 citation-69438 citation-end-69438">Research is underway to find out how many days they can stay alive in {space}</span> .</p>
<p class="source-inline-chip-container ng-star-inserted"><!----><!----></p>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>
</li>
</ul>
<p data-path-to-node="13"><strong data-path-to-node="13" data-index-in-node="0">Feeding</strong></p>
<ul data-path-to-node="14">
<li>
<p data-path-to-node="14,0,0">consume liquids, e.g., those found in moss or {seaweed}</p>
</li>
<li>
<p data-path-to-node="14,1,0">may eat other tardigrades</p>
</li>
</ul>
<p data-path-to-node="15"><strong data-path-to-node="15" data-index-in-node="0">Conservation status</strong></p>
<p class="source-inline-chip-container ng-star-inserted"><!----><!----></p>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>
<ul data-path-to-node="16">
<li>
<p data-path-to-node="16,0,0">They are not considered to be {endangered} .</p>
</li>
</ul>
</td>
</tr>
</tbody>
</table>
<p data-path-to-node="4"> </p>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p>1</p>"}]', 0);
INSERT INTO public.questions VALUES ('9b3fb6c5-9886-4f7b-b656-ff6f7b80d6a4', '7127e55b-6001-4616-bd0f-a0d52f450556', 'fillup', 'Questions 31 – 40', '<p data-path-to-node="3">Complete the notes below.</p>
<p data-path-to-node="4">Write <strong data-path-to-node="4" data-index-in-node="6">ONE WORD ONLY</strong> for each answer.</p>
<p data-path-to-node="5"><span style="font-size: 14pt;"><strong data-path-to-node="5" data-index-in-node="0">Early gold mining in the Otago region, New Zealand</strong></span></p>
<p data-path-to-node="6"><strong data-path-to-node="6" data-index-in-node="0">Background</strong></p>
<ul data-path-to-node="7">
<li>
<p data-path-to-node="7,0,0">1852: there was a brief gold rush.</p>
</li>
<li>
<p data-path-to-node="7,1,0">Late 1850s: local governments offered a {reward} to experienced gold prospectors.</p>
</li>
<li>
<p data-path-to-node="7,2,0">May 1861: miner Gabriel Read found gold in a {river}</p>
</li>
</ul>
<p data-path-to-node="8"><strong data-path-to-node="8" data-index-in-node="0">Who took part in the gold rush?</strong></p>
<ul data-path-to-node="9">
<li>
<p data-path-to-node="9,0,0">Mainly young single men or men leaving families at home.</p>
</li>
<li>
<p data-path-to-node="9,1,0">Women opened {hotels} for the miners.</p>
</li>
<li>
<p data-path-to-node="9,2,0">Businessmen offered services, e.g. hardware stores and {banks}</p>
</li>
</ul>
<p data-path-to-node="10"><strong data-path-to-node="10" data-index-in-node="0">What were early mining towns like?</strong></p>
<ul data-path-to-node="11">
<li>
<p data-path-to-node="11,0,0">At first, the buildings were made of canvas and timber, and later {concrete}</p>
</li>
</ul>
<p data-path-to-node="12"><strong data-path-to-node="12" data-index-in-node="0">What difficulties did miners face at the gold fields?</strong></p>
<ul data-path-to-node="13">
<li>
<p data-path-to-node="13,0,0">The freezing temperatures and unexpected {flooding}</p>
</li>
<li>
<p data-path-to-node="13,1,0">A poor diet of tea and {flour}</p>
</li>
</ul>
<p data-path-to-node="14"><strong data-path-to-node="14" data-index-in-node="0">What benefits and problems did gold bring to the Otago region?</strong></p>
<ul data-path-to-node="15">
<li>
<p data-path-to-node="15,0,0">Growth of the Otago town of Dunedin led to complaints about:</p>
<ul data-path-to-node="15,0,1">
<li>
<p data-path-to-node="15,0,1,0,0">The increasing price of {land}</p>
</li>
<li>
<p data-path-to-node="15,0,1,1,0">Problems with sanitation</p>
</li>
</ul>
</li>
<li>
<p data-path-to-node="15,1,0">The gold also resulted in:</p>
<ul data-path-to-node="15,1,1">
<li>
<p data-path-to-node="15,1,1,0,0">Investment in shipping</p>
</li>
<li>
<p data-path-to-node="15,1,1,1,0">The first New Zealand {university}</p>
</li>
<li>
<p data-path-to-node="15,1,1,2,0">The need for experienced workers, in particular {engineers}</p>
</li>
</ul>
</li>
</ul>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', 'null', 0);
INSERT INTO public.questions VALUES ('449e6e7f-8b06-4d30-9ffe-42ff56895877', 'dd0983fe-b91f-4689-b71f-aee47137bf92', 'fillup', 'Questions 1–7', '<p data-start="162" data-end="275">Complete the table below.<br data-start="207" data-end="210">Write <strong data-start="216" data-end="258">NO MORE THAN TWO WORDS AND/OR A NUMBER</strong> for each answer.</p>
<p data-start="162" data-end="275"><span style="font-size: 12pt;"><strong data-start="277" data-end="306">Holiday on Jackson Island</strong></span></p>
<table class="MsoTableGrid" style="border-collapse: collapse; width: 80.0743%; border-image: initial; height: 221.776px; border: medium none currentcolor;" border="1" cellspacing="0" cellpadding="0">
<tbody>
<tr style="height: 31.2642px;">
<td style="width: 22.0744%; border: 1pt solid windowtext; padding: 0in 5.4pt;" valign="top" width="144">
<p class="MsoNormal" style="margin-bottom: 0in; line-height: normal;"><strong>Place</strong></p>
</td>
<td style="width: 27.7104%; border-width: 1pt 1pt 1pt medium; border-style: solid solid solid none; border-color: windowtext windowtext windowtext currentcolor; border-image: initial; padding: 0in 5.4pt;" valign="top" width="144">
<p class="MsoNormal" style="margin-bottom: 0in; line-height: normal;"><strong>Anna’s accommodation</strong></p>
</td>
<td style="width: 21.6047%; border-width: 1pt 1pt 1pt medium; border-style: solid solid solid none; border-color: windowtext windowtext windowtext currentcolor; border-image: initial; padding: 0in 5.4pt;" valign="top" width="144">
<p class="MsoNormal" style="margin-bottom: 0in; line-height: normal;"><strong>Things Anna did</strong></p>
</td>
<td style="width: 28.6497%; border-width: 1pt 1pt 1pt medium; border-style: solid solid solid none; border-color: windowtext windowtext windowtext currentcolor; border-image: initial; padding: 0in 5.4pt;" valign="top" width="144">
<p class="MsoNormal" style="margin-bottom: 0in; line-height: normal;"><strong>Anna’s recommendation</strong></p>
</td>
</tr>
<tr style="height: 47.6278px;">
<td style="width: 22.0744%; border-width: medium 1pt 1pt; border-style: none solid solid; border-color: currentcolor windowtext windowtext; border-image: initial; padding: 0in 5.4pt;" valign="top" width="144">
<p class="MsoNormal" style="margin-bottom: 0in; line-height: normal;">Camford</p>
</td>
<td style="width: 27.7104%; border-width: medium 1pt 1pt medium; border-style: none solid solid none; border-color: currentcolor windowtext windowtext currentcolor; padding: 0in 5.4pt;" valign="top" width="144">
<p class="MsoNormal" style="margin-bottom: 0in; line-height: normal;">Example With cousin</p>
</td>
<td style="width: 21.6047%; border-width: medium 1pt 1pt medium; border-style: none solid solid none; border-color: currentcolor windowtext windowtext currentcolor; padding: 0in 5.4pt;" valign="top" width="144">
<p class="MsoNormal" style="margin-bottom: 0in; line-height: normal;">went shopping in the market</p>
</td>
<td style="width: 28.6497%; border-width: medium 1pt 1pt medium; border-style: none solid solid none; border-color: currentcolor windowtext windowtext currentcolor; padding: 0in 5.4pt;" valign="top" width="144">
<p class="MsoNormal" style="margin-bottom: 0in; line-height: normal;">Need to take {cash}</p>
</td>
</tr>
<tr style="height: 47.6278px;">
<td style="width: 22.0744%; border-width: medium 1pt 1pt; border-style: none solid solid; border-color: currentcolor windowtext windowtext; border-image: initial; padding: 0in 5.4pt;" valign="top" width="144">
<p class="MsoNormal" style="margin-bottom: 0in; line-height: normal;">Newtown</p>
</td>
<td style="width: 27.7104%; border-width: medium 1pt 1pt medium; border-style: none solid solid none; border-color: currentcolor windowtext windowtext currentcolor; padding: 0in 5.4pt;" valign="top" width="144">
<p class="MsoNormal" style="margin-bottom: 0in; line-height: normal;"> </p>
</td>
<td style="width: 21.6047%; border-width: medium 1pt 1pt medium; border-style: none solid solid none; border-color: currentcolor windowtext windowtext currentcolor; padding: 0in 5.4pt;" valign="top" width="144">
<p class="MsoNormal" style="margin-bottom: 0in; line-height: normal;">bus tour</p>
</td>
<td style="width: 28.6497%; border-width: medium 1pt 1pt medium; border-style: none solid solid none; border-color: currentcolor windowtext windowtext currentcolor; padding: 0in 5.4pt;" valign="top" width="144">
<p class="MsoNormal" style="margin-bottom: 0in; line-height: normal;">visit the {museum}</p>
</td>
</tr>
<tr style="height: 47.6278px;">
<td style="width: 22.0744%; border-width: medium 1pt 1pt; border-style: none solid solid; border-color: currentcolor windowtext windowtext; border-image: initial; padding: 0in 5.4pt;" valign="top" width="144">
<p class="MsoNormal" style="margin-bottom: 0in; line-height: normal;">Golden Beach</p>
</td>
<td style="width: 27.7104%; border-width: medium 1pt 1pt medium; border-style: none solid solid none; border-color: currentcolor windowtext windowtext currentcolor; padding: 0in 5.4pt;" valign="top" width="144">
<p class="MsoNormal" style="margin-bottom: 0in; line-height: normal;">in a {caravan}</p>
</td>
<td style="width: 21.6047%; border-width: medium 1pt 1pt medium; border-style: none solid solid none; border-color: currentcolor windowtext windowtext currentcolor; padding: 0in 5.4pt;" valign="top" width="144">
<p class="MsoNormal" style="margin-bottom: 0in; line-height: normal;">{sailing}</p>
</td>
<td style="width: 28.6497%; border-width: medium 1pt 1pt medium; border-style: none solid solid none; border-color: currentcolor windowtext windowtext currentcolor; padding: 0in 5.4pt;" valign="top" width="144">
<p class="MsoNormal" style="margin-bottom: 0in; line-height: normal;">stay for at least {four days|4 days}</p>
</td>
</tr>
<tr style="height: 47.6278px;">
<td style="width: 22.0744%; border-width: medium 1pt 1pt; border-style: none solid solid; border-color: currentcolor windowtext windowtext; border-image: initial; padding: 0in 5.4pt;" valign="top" width="144">
<p class="MsoNormal" style="margin-bottom: 0in; line-height: normal;">{white mountain}</p>
</td>
<td style="width: 27.7104%; border-width: medium 1pt 1pt medium; border-style: none solid solid none; border-color: currentcolor windowtext windowtext currentcolor; padding: 0in 5.4pt;" valign="top" width="144">
<p class="MsoNormal" style="margin-bottom: 0in; line-height: normal;">in a motel</p>
</td>
<td style="width: 21.6047%; border-width: medium 1pt 1pt medium; border-style: none solid solid none; border-color: currentcolor windowtext windowtext currentcolor; padding: 0in 5.4pt;" valign="top" width="144">
<p class="MsoNormal" style="margin-bottom: 0in; line-height: normal;">went {snow boarding}</p>
</td>
<td style="width: 28.6497%; border-width: medium 1pt 1pt medium; border-style: none solid solid none; border-color: currentcolor windowtext windowtext currentcolor; padding: 0in 5.4pt;" valign="top" width="144">
<p class="MsoNormal" style="margin-bottom: 0in; line-height: normal;">book some less on in advance</p>
</td>
</tr>
</tbody>
</table>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p class=\"MsoNormal\"><strong>SECTION 1</strong></p>\n<p class=\"MsoNormal\"><strong>John:</strong> Hi Anna, how was your holiday to Jackson Island?</p>\n<p class=\"MsoNormal\"><strong>Anna:</strong> It was good, there’s quite a lot to see. It’s quite a big island really.</p>\n<p class=\"MsoNormal\"><strong>John:</strong> Yeah, I was thinking of going in the summer. So where would you recommend going on the island?</p>\n<p class=\"MsoNormal\"><strong>Anna:</strong> Well, the capital of course, Camford. I stayed there with my cousin.</p>\n<p class=\"MsoNormal\"><strong>John:</strong> What did you do there?</p>\n<p class=\"MsoNormal\"><strong>Anna:</strong> Well, actually I spent most of my time there shopping.</p>\n<p class=\"MsoNormal\"><strong>John:</strong> So has it got good shopping centres?</p>\n<p class=\"MsoNormal\"><strong>Anna:</strong> Yes, but they’re the same as at home really. So I did all my shopping in the market, which is great.</p>\n<p class=\"MsoNormal\"><strong>John:</strong> Hmm, what kinds of things are good to buy there?</p>\n<p class=\"MsoNormal\"><strong>Anna:</strong> Everything, but bags and shoes especially. Just make sure you’ve got <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>(1) cash</strong></span> with you, as most of the stalls don’t take credit cards.</p>\n<p class=\"MsoNormal\"><strong>John:</strong> OK, that’s good to know. Where else did you go?</p>\n<p class=\"MsoNormal\"><strong>Anna:</strong> Well, my cousin and I went to Newtown. She said it was famous for its modern architecture. We only had half a day there, so we took a bus tour around the town. But if I were you, I’d give the bus tour a miss. Unless you know a lot about architecture, the buildings all look the same. There’s a <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>(2) museum</strong></span> though, that’s supposed to be good. You might like that.</p>\n<p class=\"MsoNormal\"><strong>John:</strong> Okay, I’ll give it a go then.</p>\n<p class=\"MsoNormal\"><strong>Anna:</strong> After that, we headed for Golden Beach, because we were going to meet up with an old friend that I hadn’t seen for years. But we had to stay in a<span style=\"text-decoration: underline;\"> <span style=\"background-color: #ffe786;\"><strong>(3) caravan</strong></span></span> as the hotels were all booked up.</p>\n<p class=\"MsoNormal\"><strong>John:</strong> Is it as pretty as it looks in the brochures?</p>\n<p class=\"MsoNormal\"><strong>Anna:</strong> Yes, it’s very picturesque. We did some <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>(4) sailing</strong></span> on the most beautiful blue sea. It was so clear that you could see the bottom even quite far out to sea. That part of the trip was great, and I’d have liked to have stayed even longer. I’d suggest staying there for a minimum of <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>(5) 4 days</strong></span> if I were you. We had two days there and it wasn’t nearly enough.</p>\n<p class=\"MsoNormal\"><strong>John:</strong> Sounds great. I’ll put that on my “must do” list. Was that the end of your trip?</p>\n<p class=\"MsoNormal\"><strong>Anna:</strong> No, after Golden Beach, we drove into the centre of the island to <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>(6) White Mountain</strong>.</span></p>\n<p class=\"MsoNormal\"><strong>John:</strong> White as in the colour?</p>\n<p class=\"MsoNormal\"><strong>Anna:</strong> Yes! The island’s great because you can go from the beaches up to the snowy mountain in a couple of hours. We took a tent because we were going to camp, but the weather was so cold—in fact, it was snowing when I was there—that we stopped in a motel instead.</p>\n<p class=\"MsoNormal\"><strong>John:</strong> Did you go skiing then?</p>\n<p class=\"MsoNormal\"><strong>Anna:</strong> No, but we tried <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>(7) snowboarding</strong></span>, and it was harder than it looked. It looks so easy when you see other people doing it, but it took me ages to get the hang of it. I wish I’d had some lessons, but you had to make your bookings in advance.</p>\n<p class=\"MsoNormal\"><strong>John:</strong> OK, I’ll look into that thanks.</p>\n<div class=\"MsoNormal\" style=\"text-align: center;\" align=\"center\"><hr align=\"center\" size=\"2\" width=\"100%\"></div>\n<p class=\"MsoNormal\"><strong>John:</strong> So are there any other tips or advice you could give me?</p>\n<p class=\"MsoNormal\"><strong>Anna:</strong> I don’t know, let me think… Oh, one place you should try to visit is this very quaint cafe which is at the foot of the mountain. It has the best <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>(8) cakes</strong> </span>ever! It’s worth going there just for them.</p>\n<p class=\"MsoNormal\"><strong>John:</strong> Hmm, I’ll have to try those. So what other advice would you give?</p>\n<p class=\"MsoNormal\"><strong>Anna:</strong> Oh, let me think… uh… we didn’t really have any problems.</p>\n<p class=\"MsoNormal\"><strong>John:</strong> Well, how did you get around when you were there?</p>\n<p class=\"MsoNormal\"><strong>Anna:</strong> We wanted to get a motorbike at first—they’re very cheap to hire and great fun to ride as the roads are very good. But it turned out not to be a good idea because the weather is so changeable. You’d be much better off in a <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>(9) car</strong></span>. There are plenty of places where you can hire them and the roads are well signposted so you won’t get lost.</p>\n<p class=\"MsoNormal\"><strong>John:</strong> And presumably I can get a map when I get there?</p>\n<p class=\"MsoNormal\"><strong>Anna:</strong> Well you can, but they are expensive. It’d be better to get one—a <span style=\"text-decoration: underline; background-color: #ffe786;\"><strong>(10) map</strong></span>—here before you go.</p>\n<p class=\"MsoNormal\"><strong>John:</strong> Great, that’s been really useful. Thank you!</p>"}]', 0);
INSERT INTO public.questions VALUES ('476d130e-0fe9-449d-aaf2-1699f5a2221a', 'dd0983fe-b91f-4689-b71f-aee47137bf92', 'fillup', 'Questions 8–10', '<p data-start="685" data-end="774">Complete the notes below.<br data-start="731" data-end="734">Write <strong data-start="740" data-end="757">ONE WORD ONLY</strong> for each answer.</p>
<p data-start="776" data-end="911"><strong data-start="776" data-end="791">More Advice</strong><br data-start="791" data-end="794">• Try the {cakes} at the cafe on the mountain.<br data-start="844" data-end="847">• Hire a {car}<br data-start="868" data-end="871">• Buy a {map} before the holiday.</p>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', 'null', 1);
INSERT INTO public.questions VALUES ('a3f5e5dc-bb60-44c5-9eee-4f559608d338', 'fe82cd76-3568-43cf-b16f-fe30d4cc4ced', 'radio', 'Questions 25–30', '', '<p>Choose the correct letter, <strong>A</strong>, <strong>B </strong>or <strong>C</strong>.</p>', 'multiple_choice', '[{"correct": 0, "options": [{"option_text": "A. happened by chance"}, {"option_text": "B. could not be explained"}, {"option_text": "C. was made by a local newspaper"}], "question": "The discovery made in Portishead"}, {"correct": 0, "options": [{"option_text": "A. risked facing legal action"}, {"option_text": "B. failed to keep people informed"}, {"option_text": "C. had to undertake complicated work"}], "question": "When they switched off the traffic lights in Bristol, local authorities"}, {"correct": 1, "options": [{"option_text": "A. equally safe for drivers and pedestrians"}, {"option_text": "B. safer for drivers than for pedestrians"}, {"option_text": "C. safer for pedestrians than for drivers"}], "question": "According to research into road safety around Europe, roads in Britain are"}, {"correct": 0, "options": [{"option_text": "A. They were presented in an inappropriate form"}, {"option_text": "B. They were too closely based on other research"}, {"option_text": "C. They misrepresented the opinions of disabled people"}], "question": "Why does Jack criticise the findings about disabled road users?"}, {"correct": 0, "options": [{"option_text": "A. feel anxious about crossing the road"}, {"option_text": "B. want to change the layout of the square"}, {"option_text": "C. say that pedestrians had equal status to drivers"}], "question": "Compared to the men interviewed in Dishford, women were more likely to"}, {"correct": 2, "options": [{"option_text": "A. give the public clearer choices"}, {"option_text": "B. consult local people early in the design process"}, {"option_text": "C. walk more around the neighbourhood they are working in"}], "question": "According to the group ‘Living Streets’, urban planners should"}]', 'null', 'null', 'null', 'null', 2);
INSERT INTO public.questions VALUES ('3d79c778-3af2-4000-a7ab-74044779533e', 'f9d004dc-8cd9-4f59-9920-4c90c0c4c470', 'matching', 'Questions 14–19', NULL, '<p>Reading Passage 2 has six sections. Choose the correct heading for each section from the list of headings below.</p>', 'matching_features', 'null', 'null', '{"layoutType": "heading", "summaryText": null, "answerOptions": [{"optionText": "i. Professions in which super-taskers are likely to be found"}, {"optionText": "ii. The effects of multi-tasking on neurological structure"}, {"optionText": "iii. A distinction between situations when people can and can’t multi-task"}, {"optionText": "iv. Real multi-tasking is nearly impossible"}, {"optionText": "v. Multi-tasking and gender"}, {"optionText": "vi. The neurological reasons for struggling to manage more things"}, {"optionText": "vii. The ability to multi-task is determined by people’s genes"}, {"optionText": "viii. Gender and the structure of the brain"}], "matchingItems": null}', 'null', '[{"content": "<ul data-path-to-node=\"2\">\n<li>\n<p data-path-to-node=\"2,0,0\"><strong class=\"\" data-path-to-node=\"2,0,0\" data-index-in-node=\"0\">14. Section A: iv (Real multi-tasking is nearly impossible)</strong></p>\n<ul data-path-to-node=\"2,0,1\">\n<li>\n<p data-path-to-node=\"2,0,1,0,0\"><strong class=\"\" data-path-to-node=\"2,0,1,0,0\" data-index-in-node=\"0\">Vị trí:</strong><span class=\"\"> Đoạn A,</span><span class=\"\"> dòng 2–4.</span></p>\n</li>\n<li>\n<p data-path-to-node=\"2,0,1,1,0\"><strong class=\"\" data-path-to-node=\"2,0,1,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> “…</span><span class=\"\">research shows that your brain </span><strong class=\"\" data-path-to-node=\"2,0,1,1,0\" data-index-in-node=\"46\">isn’t capable</strong><span class=\"\"> of paying close attention to more than one complex task at a time.</span><span class=\"\">“</span></p>\n</li>\n<li>\n<p data-path-to-node=\"2,0,1,2,0\"><strong class=\"\" data-path-to-node=\"2,0,1,2,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Đoạn này khẳng định đa nhiệm hiệu quả là vượt quá khả năng của hầu hết chúng ta và gọi đó là một “huyền thoại” (myth),</span><span class=\"\"> tức là thực tế gần như không thể thực hiện được.</span></p>\n</li>\n</ul>\n</li>\n<li>\n<p data-path-to-node=\"2,1,0\"><strong class=\"\" data-path-to-node=\"2,1,0\" data-index-in-node=\"0\">15. Section B: iii (A distinction between situations when people can and can’t multi-task)</strong></p>\n<ul data-path-to-node=\"2,1,1\">\n<li>\n<p data-path-to-node=\"2,1,1,0,0\"><strong class=\"\" data-path-to-node=\"2,1,1,0,0\" data-index-in-node=\"0\">Vị trí:</strong><span class=\"\"> Đoạn B,</span><span class=\"\"> dòng 1–4.</span></p>\n</li>\n<li>\n<p data-path-to-node=\"2,1,1,1,0\"><strong class=\"\" data-path-to-node=\"2,1,1,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> “It is true that you can check your email while eating…</span><span class=\"\"> But </span><strong class=\"\" data-path-to-node=\"2,1,1,1,0\" data-index-in-node=\"73\">innate activities</strong><span class=\"\">…</span><span class=\"\"> do not require you to pay attention,</span><span class=\"\"> whereas </span><strong class=\"\" data-path-to-node=\"2,1,1,1,0\" data-index-in-node=\"139\">activities such as reading… do require attention</strong><span class=\"\">.</span><span class=\"\">“</span></p>\n</li>\n<li>\n<p data-path-to-node=\"2,1,1,2,0\"><strong class=\"\" data-path-to-node=\"2,1,1,2,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Tác giả phân biệt rõ hai tình huống:</span><span class=\"\"> những việc bản năng (đi bộ,</span><span class=\"\"> ăn) thì có thể làm cùng lúc,</span><span class=\"\"> nhưng những việc cần sự tập trung (đọc,</span><span class=\"\"> lái xe) thì không thể đa nhiệm hiệu quả.</span></p>\n</li>\n</ul>\n</li>\n<li>\n<p data-path-to-node=\"2,2,0\"><strong class=\"\" data-path-to-node=\"2,2,0\" data-index-in-node=\"0\">16. Section C: vi (The neurological reasons for struggling to manage more things)</strong></p>\n<ul data-path-to-node=\"2,2,1\">\n<li>\n<p data-path-to-node=\"2,2,1,0,0\"><strong class=\"\" data-path-to-node=\"2,2,1,0,0\" data-index-in-node=\"0\">Vị trí:</strong><span class=\"\"> Đoạn C,</span><span class=\"\"> dòng 5–8.</span></p>\n</li>\n<li>\n<p data-path-to-node=\"2,2,1,1,0\"><strong class=\"\" data-path-to-node=\"2,2,1,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> “…</span><span class=\"\">simply because we have only </span><strong class=\"\" data-path-to-node=\"2,2,1,1,0\" data-index-in-node=\"43\">two frontal lobes</strong><span class=\"\">…</span><span class=\"\"> the brain can switch back and forth between two tasks,</span><span class=\"\"> we might be in great trouble when we try to juggle more than two…</span><span class=\"\">“</span></p>\n</li>\n<li>\n<p data-path-to-node=\"2,2,1,2,0\"><strong class=\"\" data-path-to-node=\"2,2,1,2,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Đoạn này giải thích dưới góc độ thần kinh học (neurological):</span><span class=\"\"> vì não chỉ có 2 thùy trán nên chỉ có thể xử lý tối đa 2 việc bằng cách chuyển đổi qua lại,</span><span class=\"\"> nhiều hơn sẽ gặp rắc rối.</span></p>\n</li>\n</ul>\n</li>\n<li>\n<p data-path-to-node=\"2,3,0\"><strong class=\"\" data-path-to-node=\"2,3,0\" data-index-in-node=\"0\">17. Section D: v (Multi-tasking and gender)</strong></p>\n<ul data-path-to-node=\"2,3,1\">\n<li>\n<p data-path-to-node=\"2,3,1,0,0\"><strong class=\"\" data-path-to-node=\"2,3,1,0,0\" data-index-in-node=\"0\">Vị trí:</strong><span class=\"\"> Đoạn D,</span><span class=\"\"> dòng 1–4.</span></p>\n</li>\n<li>\n<p data-path-to-node=\"2,3,1,1,0\"><strong class=\"\" data-path-to-node=\"2,3,1,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> “…</span><span class=\"\">whether there is a difference between the </span><strong class=\"\" data-path-to-node=\"2,3,1,1,0\" data-index-in-node=\"57\">sexes</strong><span class=\"\">…</span><span class=\"\"> claimed that </span><strong class=\"\" data-path-to-node=\"2,3,1,1,0\" data-index-in-node=\"79\">women</strong><span class=\"\"> are superior multi-taskers.</span><span class=\"\">“</span></p>\n</li>\n<li>\n<p data-path-to-node=\"2,3,1,2,0\"><strong class=\"\" data-path-to-node=\"2,3,1,2,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Toàn bộ đoạn này thảo luận về khả năng đa nhiệm giữa nam và nữ (gender/sexes),</span><span class=\"\"> bao gồm cả nghiên cứu hình ảnh não và các tình huống thực tế.</span></p>\n</li>\n</ul>\n</li>\n<li>\n<p data-path-to-node=\"2,4,0\"><strong class=\"\" data-path-to-node=\"2,4,0\" data-index-in-node=\"0\">18. Section E: i (Professions in which super-taskers are likely to be found)</strong></p>\n<ul data-path-to-node=\"2,4,1\">\n<li>\n<p data-path-to-node=\"2,4,1,0,0\"><strong class=\"\" data-path-to-node=\"2,4,1,0,0\" data-index-in-node=\"0\">Vị trí:</strong><span class=\"\"> Đoạn E,</span><span class=\"\"> dòng 4–7.</span></p>\n</li>\n<li>\n<p data-path-to-node=\"2,4,1,1,0\"><strong class=\"\" data-path-to-node=\"2,4,1,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> “…</span><strong class=\"\" data-path-to-node=\"2,4,1,1,0\" data-index-in-node=\"15\">pilots</strong><span class=\"\">…</span> <strong class=\"\" data-path-to-node=\"2,4,1,1,0\" data-index-in-node=\"25\">high-end chefs</strong><span class=\"\">…</span><span class=\"\"> and </span><strong class=\"\" data-path-to-node=\"2,4,1,1,0\" data-index-in-node=\"47\">elite doctors</strong><span class=\"\">…</span><span class=\"\"> might all be more likely to be super-taskers.</span><span class=\"\">“</span></p>\n</li>\n<li>\n<p data-path-to-node=\"2,4,1,2,0\"><strong class=\"\" data-path-to-node=\"2,4,1,2,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Đoạn này liệt kê các ngành nghề (professions) mà những người “siêu đa nhiệm” thường xuất hiện như phi công,</span><span class=\"\"> đầu bếp và bác sĩ cấp cứu.</span></p>\n</li>\n</ul>\n</li>\n<li>\n<p data-path-to-node=\"2,5,0\"><strong class=\"\" data-path-to-node=\"2,5,0\" data-index-in-node=\"0\">19. Section F: vii (The ability to multi-task is determined by people’s genes)</strong></p>\n<ul data-path-to-node=\"2,5,1\">\n<li>\n<p data-path-to-node=\"2,5,1,0,0\"><strong class=\"\" data-path-to-node=\"2,5,1,0,0\" data-index-in-node=\"0\">Vị trí:</strong><span class=\"\"> Đoạn F,</span><span class=\"\"> dòng 1–2.</span></p>\n</li>\n<li>\n<p data-path-to-node=\"2,5,1,1,0\"><strong class=\"\" data-path-to-node=\"2,5,1,1,0\" data-index-in-node=\"0\">Dẫn chứng:</strong><span class=\"\"> “The ability to multi-task probably comes down to the </span><strong class=\"\" data-path-to-node=\"2,5,1,1,0\" data-index-in-node=\"65\">DNA you inherit</strong><span class=\"\"> from your parents…</span><span class=\"\">“</span></p>\n</li>\n<li>\n<p data-path-to-node=\"2,5,1,2,0\"><strong class=\"\" data-path-to-node=\"2,5,1,2,0\" data-index-in-node=\"0\">Giải thích:</strong><span class=\"\"> Đoạn cuối khẳng định khả năng này do di truyền (DNA/genes) quyết định,</span><span class=\"\"> bạn sinh ra đã có cấu trúc não đó hoặc là không.</span></p>\n</li>\n</ul>\n</li>\n</ul>\n"}]', 0);
INSERT INTO public.questions VALUES ('1bee321a-03e8-4a18-a524-421346daf4c9', '2aa50052-743f-40ff-a7fb-9f01a9311253', 'fillup', 'Questions 1-10', '<p>Complete the table below.</p>
