INSERT INTO public.questions VALUES ('3587b930-97e2-4f6d-a171-e8e06f03e8e8', 'a63d3da7-d010-48c8-9791-1ef2d1b9d3a8', 'radio', 'Questions 1-5', '', '<p>Choose <strong>TRUE</strong> if the statement agrees with the information given in the text, choose <strong>FALSE</strong> if the statement contradicts the information, or choose <strong>NOT GIVEN</strong> if there is no information on this.</p>', 'true_false_not_given', '[{"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "In Robert FitzRoy’s time, weather forecasting was a respected skill"}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "When FitzRoy retired from the navy, he had already had a successful career at sea"}, {"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "FitzRoy faced competition from other applicants for the chief statistician’s job"}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "The British Parliament supported the idea of regular weather forecasts in 1854"}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": " Progress in technology made it a good time for publicly available weather forecasting to begin"}]', 'null', 'null', 'null', 'null', 0);
