INSERT INTO public.questions VALUES ('a7a7c7b4-ed9f-4a32-bc73-bcc5b5524e0d', 'd86e8bed-390a-471b-ba21-62b89b11ba5b', 'radio', 'Questions 11-16', '', '<p>Choose the correct letter, <strong>A</strong>, <strong>B </strong>or <strong>C</strong>.</p>', 'multiple_choice', '[{"correct": 1, "options": [{"option_text": "A 15 years ago"}, {"option_text": "B 30 years ago"}, {"option_text": "C 60 years ago"}], "question": "When was Eyesaver founded?"}, {"correct": 0, "options": [{"option_text": "A to offer common equipment"}, {"option_text": "B to offer medication to children with eye diseases"}, {"option_text": "C to offer operational help to people who had eye problems"}], "question": "What was the original aim of the program?"}, {"correct": 2, "options": [{"option_text": "A monthly donation"}, {"option_text": "B donation from rich people"}, {"option_text": "C money collected on the street"}], "question": "The main funding comes from"}, {"correct": 0, "options": [{"option_text": "A glasses for the patients"}, {"option_text": "B money donation"}, {"option_text": "C voluntary work"}], "question": "14 What does the speaker expect listeners to provide?"}, {"correct": 0, "options": [{"option_text": "A to show people their donation can make a difference"}, {"option_text": "B to show people how easily eye problems can be cured"}, {"option_text": "C to educate people about common eye diseases"}], "question": "What is the main purpose of this program?"}, {"correct": 1, "options": [{"option_text": "A computers"}, {"option_text": "B recordings"}, {"option_text": "C training"}], "question": "16 Eyesaver advertises for the program through"}]', 'null', 'null', 'null', '[{"content": "<h3 data-path-to-node=\"2\"><strong data-path-to-node=\"2\" data-index-in-node=\"0\">SECTION 2: EYESAVER CHARITY INTRODUCTION</strong></h3>\n<p data-path-to-node=\"3\"><strong data-path-to-node=\"3\" data-index-in-node=\"0\">Speaker:</strong> Hello everyone, thanks for attending tonight’s event. Let me start with the early history of our charity, Eyesaver.</p>\n<p data-path-to-node=\"4\">It was founded by a retired optometrist, Timothy Gains. I have spent much of my working life at Eyesaver. I am 60 years old now, and I started working for this organization 15 years ago when I left a corporate position to help people with eye problems.</p>\n<p id=\"p-rc_c2bd08e547ad031e-104\" data-path-to-node=\"5\">Now, our charity<span style=\"background-color: #f1c40f;\"> <strong data-path-to-node=\"5\" data-index-in-node=\"17\">(11) has been helping people for three decades [Answer: 30 years ago]</strong></span>. <span class=\"citation-1631 citation-1632 citation-end-1632\">You may know that we are now doing various other things to help people with eye problems. That includes medications for children with eye diseases and operational help to those in the public who have eye proble</span><span class=\"citation-1631 citation-end-1631\">ms.</span></p>\n<p id=\"p-rc_c2bd08e547ad031e-105\" data-path-to-node=\"6\"><span class=\"citation-1630 citation-end-1630\">But when Mr. Gains just foun</span>ded Eyesaver, he wanted the program to <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"6\" data-index-in-node=\"67\">(12) <span class=\"citation-1628 citation-1629\">be able to offer common eye equipment to those who needed it</span></strong></span><span style=\"background-color: #f1c40f;\">.</span></p>\n<p id=\"p-rc_c2bd08e547ad031e-106\" data-path-to-node=\"7\"><span class=\"citation-1626 citation-1627 citation-end-1627\">We receive occasional donations from corporations and charity groups now. We have over 1,500 volunteers who work on the streets with the little red donat</span><span class=\"citation-1626 citation-end-1626\">ion boxes, which many of you are familiar with, and</span> <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"7\" data-index-in-node=\"205\">(13) this is the main source of funding for us [Answer: money collected on the street]</strong></span>. <span class=\"citation-1625 citation-end-1625\">Besides, we are planning to work to secure donations from wealthy benefactors.</span></p>\n<p id=\"p-rc_c2bd08e547ad031e-107\" data-path-to-node=\"8\"><span class=\"citation-1624 citation-end-1624\">Many people are passionate about charity cause and have been inquiring how to donate money to us. I really appreciate that, but</span> <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"8\" data-index-in-node=\"128\">(14) <span class=\"citation-1621 citation-1622 citation-1623\">our main need is to collect glasses for our patients</span></strong></span><span class=\"citation-1621 citation-1622 citation-1623 citation-end-1623\">. Many of you have multiple pairs of old glasses in your possession, and we encourage you to gather these pairs which you no longer need and donate them to our cause.</span></p>\n<p id=\"p-rc_c2bd08e547ad031e-108\" data-path-to-node=\"9\"><span class=\"citation-1618 citation-1619 citation-1620 citation-end-1620\">In doing thi</span><span class=\"citation-1618 citation-1619 citation-end-1619\">s, you’ll be able to make sure that someone else can see better. Most of us cannot imagine a life in which we are unable to see well. This i</span><span class=\"citation-1618 citation-end-1618\">s why your eyeglass donations are so critical to our mission.</span></p>\n<p id=\"p-rc_c2bd08e547ad031e-109\" data-path-to-node=\"10\"><span class=\"citation-1617 citation-end-1617\">And as a side note, we offer full-time positions; let me know i</span>f you are interested. <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"10\" data-index-in-node=\"85\">(15) Our goal is to make people aware that even the smallest of donations can help change a person’s life [Answer: to show people their donation can make a difference]</strong></span>, <span class=\"citation-1615 citation-1616 citation-end-1616\">so your donation can be a turning point for them.</span></p>\n<p id=\"p-rc_c2bd08e547ad031e-110\" data-path-to-node=\"11\"><span class=\"citation-1613 citation-1614 citation-end-1614\">The other day, when I was talking to some people on the street, they were surprised to find out how easily some eye problems can be cured. And I’m proud to say that our next program wil</span><span class=\"citation-1613 citation-end-1613\">l aim at educating people about common eye diseases. We are able to prevent many fatal eye problems.</span></p>\n<p id=\"p-rc_c2bd08e547ad031e-111\" data-path-to-node=\"12\"><span class=\"citation-1612 citation-end-1612\">In order to publicize our charity progra</span>m, we surely need to do some advertising. When we first started our program, we used computers to create awareness for our cause. For instance, promoting seminars in which we informed people as to how they could help us to solve eye problems.</p>\n<p id=\"p-rc_c2bd08e547ad031e-112\" data-path-to-node=\"13\">But in recent years, the <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"13\" data-index-in-node=\"25\">(16) <span class=\"citation-1610 citation-1611\">main means of advertising our program is through audio recordings</span></strong></span><span class=\"citation-1610 citation-1611 citation-end-1611\">. We have found it cost-efficient and effective. It’s good to know that many of our staff are recommending our program to their friends and colleagues. But I am</span><span class=\"citation-1610 citation-end-1610\"> afraid that our training cannot show people the whole picture of our pr</span>ogram.</p>\n<hr data-path-to-node=\"14\">\n<h3 data-path-to-node=\"15\"><strong data-path-to-node=\"15\" data-index-in-node=\"0\">PARTNERSHIPS AND ROLES (Questions 17–20)</strong></h3>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">Speaker:</strong> Finally, I would like to tell you about some organizations which have played important roles in the development and success of Eyesaver.</p>\n<p data-path-to-node=\"17\">Our affiliation with the <strong data-path-to-node=\"17\" data-index-in-node=\"25\">National Vision Funding Group</strong> has <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"17\" data-index-in-node=\"59\">(17) allowed us to gain fame and to become even more significant [Answer: E – take the reputation to a higher level]</strong></span>, so many people around the country are coming for our services.</p>\n<p data-path-to-node=\"18\">Our association with the <strong data-path-to-node=\"18\" data-index-in-node=\"25\">Eye for the Future</strong> organization has allowed us to run cooperative ads by which we <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"18\" data-index-in-node=\"107\">(18) seek producers of equipment to work with us [Answer: D – help look for equipment manufacturers]</strong>.</span> Meanwhile, some of our staff has been sent to this organization for some special training. Their skills should be improved very soon.</p>\n<p data-path-to-node=\"19\">Also, we have had a long-time cooperation with <strong data-path-to-node=\"19\" data-index-in-node=\"47\">Sam’s Eyecare Institution</strong>. Our relationship with it has given us the <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"19\" data-index-in-node=\"206\">(19) opportunity to link with many different academic institutions, including colleges and universities [Answer: C – earn support from colleges]</strong></span> with good reputation.</p>\n<p id=\"p-rc_c2bd08e547ad031e-113\" data-path-to-node=\"20\">And we have a similar friendship with a group called <strong data-path-to-node=\"20\" data-index-in-node=\"53\">Youth Health</strong>. Our connection with that group <span style=\"background-color: #f1c40f;\"><strong data-path-to-node=\"20\" data-index-in-node=\"98\">(20) allows us to link directly with young kids [Answer: B – involve more children in need]</strong></span>, <span class=\"citation-1608 citation-1609 citation-end-1609\">since this is a crucial stage in their growth.</span></p>\n<p id=\"p-rc_c2bd08e547ad031e-114\" data-path-to-node=\"21\"><span class=\"citation-1606 citation-1607 citation-end-1607\">We plan to contact with some colleges and hope that with their help, more college students could get to know our program. So as you can see, we have all bases covered in linking with students, as we have affiliations directly with both administrators and the students themselves.</span></p>\n<p id=\"p-rc_c2bd08e547ad031e-115\" data-path-to-node=\"22\"><span class=\"citation-1604 citation-1605 citation-end-1605\">Thank you</span><span class=\"citation-1604 citation-end-1604\"> so much for your attention today as we try to stamp out eye problems. We will appreciate your donations, no matter how large or how small. We believe </span>with our efforts, the world will be a brighter and more beautiful place.</p>"}]', 0);
INSERT INTO public.questions VALUES ('aeaf746e-ce68-427f-b66d-f636862ae893', 'd86e8bed-390a-471b-ba21-62b89b11ba5b', 'matching', 'Questions 17-20', '', '<p>What role does each of the following organisations play for the development of Eyesaver?<br>Write the correct letter, <strong>A</strong>–<strong>F</strong></p>', 'summary_completion', 'null', 'null', '{"layoutType": "summary", "summaryText": "<p> </p>\n<p>National Vision Funding Group {take the reputation to a higher level}</p>\n<p> </p>\n<p>Eye for the Future {help look for equipment manufacturers}</p>\n<p> </p>\n<p>Sam''s Eyecare Institution {earn support from colleges}</p>\n<p> </p>\n<p>Youth Health {involve more children in need}</p>", "answerOptions": [{"optionText": "gain more donation"}, {"optionText": "involve more children in need"}, {"optionText": "earn support from colleges"}, {"optionText": "help look for equipment manufacturers"}, {"optionText": "take the reputation to a higher level"}, {"optionText": "recruit and support staff"}], "matchingItems": []}', 'null', 'null', 1);
INSERT INTO public.questions VALUES ('4582e6e6-791d-4f5a-af04-c044bdf369da', '7c053004-0893-412c-b6ae-3f1332110d93', 'fillup', 'Questions 1-10', '<p data-start="97" data-end="191">Write <strong data-start="130" data-end="172">NO MORE THAN TWO WORDS AND/OR A NUMBER</strong> for each answer.</p>
<p><strong><span style="font-size: 14pt;">Bakewell Travel: Customer Booking Request Form</span></strong></p>
<p data-start="252" data-end="288">Example</p>
<p data-start="252" data-end="288">Travelling to: Dubai</p>
<p data-start="290" data-end="314"><strong>Name</strong>: Sarah Carter</p>
<p data-start="316" data-end="354"><strong>Contact phone number</strong>: {07958847222}</p>
<p data-start="356" data-end="398">Best day to call: {Thursday} morning</p>
<p data-start="400" data-end="445">Number of people travelling: {7}</p>
<p data-start="447" data-end="488">Date of outward journey: {22 November|November 22|22nd November| November 22nd| 22nd of November}</p>
<p data-start="490" data-end="530">Day of return journey: 25 November</p>
<p data-start="532" data-end="567">Purpose of trip: a {wedding}</p>
<p data-start="569" data-end="631">Special requirements: one passenger can’t eat {cheese}</p>
<p data-start="638" data-end="659"><strong>Market Research</strong></p>
<p data-start="662" data-end="706">Number of trips in last 12 months: six</p>
<p data-start="709" data-end="747">Last country visited: {India}</p>
<p data-start="750" data-end="796">Purpose of last foreign trip: {business}</p>
<p data-start="799" data-end="849">Customer feedback on website: too {slow}</p>
<p data-start="852" data-end="891">Email address: carter.s@{speedtech} .com</p>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', 'null', 0);
INSERT INTO public.questions VALUES ('13c31704-8958-45b6-9ac7-fc08953e5158', '8f16efc8-db5b-430a-b56d-a12ef211ba87', 'matrix', 'Questions 31-39', '', '<p>Which paragraph contains the following information?</p>
<p>Write the correct letter, A–H, in boxes 31–39 on your answer sheet.</p>', 'choose_a_title', 'null', 'null', 'null', '{"layoutType": "simple", "matrixItems": [{"itemText": "the areas of study that help us understand risk", "correctCategoryLetter": "B"}, {"itemText": "reference to key actions that might benefit the world", "correctCategoryLetter": "F"}, {"itemText": "examples of statistical predictions that the majority of the public react to in the same way", "correctCategoryLetter": "C"}, {"itemText": "the variety of contexts in which risk occurs", "correctCategoryLetter": "A"}, {"itemText": "mention of a habit that has been proved to be very risky", "correctCategoryLetter": "B"}, {"itemText": "reference to market forces motivating change", "correctCategoryLetter": "E"}, {"itemText": "the writer''s current attitude towards risk", "correctCategoryLetter": "H"}, {"itemText": "a reason why some individuals avoid making a career change", "correctCategoryLetter": "D"}, {"itemText": "how some people over-react to information about risk", "correctCategoryLetter": "C"}], "matrixCategories": [{"categoryText": "A", "categoryLetter": "A"}, {"categoryText": "B", "categoryLetter": "B"}, {"categoryText": "C", "categoryLetter": "C"}, {"categoryText": "D", "categoryLetter": "D"}, {"categoryText": "E", "categoryLetter": "E"}, {"categoryText": "F", "categoryLetter": "F"}, {"categoryText": "G", "categoryLetter": "G"}, {"categoryText": "H", "categoryLetter": "H"}]}', 'null', 1);
INSERT INTO public.questions VALUES ('24e20dad-9479-4e66-a8f2-4e5c1fd30748', '8f16efc8-db5b-430a-b56d-a12ef211ba87', 'radio', 'Question 40', '', '<p>Choose the correct answers</p>', 'multiple_choice', '[{"correct": 1, "options": [{"option_text": "risk is something we must try to avoid."}, {"option_text": "experts should be truthful about risk to the public."}, {"option_text": "optimists are better able to deal with risk than pessimists."}, {"option_text": "it is important to take risks in order to fulfil social obligations."}], "question": "At the end of the passage the writer concludes that"}]', 'null', 'null', 'null', 'null', 2);
INSERT INTO public.questions VALUES ('5c403bf8-c222-4901-b907-58674a72771d', '712f7448-6aa3-48fd-907e-a9ce1bbba3b1', 'fillup', 'Questions 31-40', '<p>Complete the notes below.</p>
<p>Write <strong>ONE WORD ONLY</strong> for each answer.</p>
<p><span style="font-size: 14pt;"><strong>The Early History of Salt</strong></span></p>
<p><strong>Introduction</strong></p>
<ul>
<li>
<p>Salt is essential for human {health} .</p>
</li>
</ul>
<p><strong>Ancient Rome</strong></p>
<ul>
<li>
<p>The word {salary} comes from the Latin word''s solarium argetum, which was used to describle the payment to Roman soldiers.</p>
</li>
</ul>
<p><strong>Ancient Sweden</strong></p>
<ul>
<li>
<p>Animals were kept in the local {forest} at the right time of year.</p>
</li>
<li>
<p>Fresh meat was only available in {October} .</p>
</li>
<li>
<p>Salt has been used widely: we can tell from the diet of the {king} in Sweden.</p>
</li>
<li>
<p>{beer} Consumption increased rapidly because the food was much too salty.</p>
</li>
</ul>
<p><strong>Salt source</strong></p>
<ul>
<li>
<p>People mainly extract salt from oceans and {deserts} in the basins.</p>
</li>
<li>
<p>Salt from spring water is more {concentrated} . And purer compared to that from sea water</p>
</li>
</ul>
<p><strong>Salt distribution</strong></p>
<ul>
<li>
<p>In ancient Sweden</p>
</li>
</ul>
<p>           -Locals needed to protect the {shipping} By which they imported salt.</p>
<ul>
<li>
<p>In other ancient countries</p>
</li>
</ul>
<p>           - People carrying salt around were seen as a natural means of {transport}</p>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', 'null', 0);
INSERT INTO public.questions VALUES ('d08048a5-31a6-432e-ad4f-de79212787ec', 'cdff993e-886f-499a-8a5a-0a77c7abac27', 'fillup', 'Questions 1–8', '<p data-start="18" data-end="43">Complete the notes below.</p>
<p data-start="45" data-end="112">Choose <strong data-start="52" data-end="78">NO MORE THAN TWO WORDS</strong> from the passage for each answer.</p>
<table style="border-collapse: collapse; width: 99.999%;" border="1"><colgroup><col style="width: 99.8778%;"></colgroup>
<tbody>
<tr>
<td>
<p data-start="169" data-end="181"><span style="font-size: 14pt;"><strong>Stonehenge</strong></span></p>
<p data-start="183" data-end="198"><span style="font-size: 12pt;"><strong>Construction</strong></span></p>
<h3 data-start="200" data-end="212">Stage 1:</h3>
<p data-start="213" data-end="379">• the ditch and henge were dug, possibly using tools made from {deer|antlers}<br data-start="298" data-end="301">• {timber|posts} may have been arranged in deep pits inside the circle</p>
<h3 data-start="381" data-end="393">Stage 2:</h3>
<p data-start="394" data-end="521">• bluestones from the Preseli Hills were placed in standing position<br data-start="462" data-end="465">• theories about the transportation of the bluestones:</p>
<p data-start="523" data-end="672"> – archaeological:<br data-start="541" data-end="544">  ○ builders used {tree trunks} to make sledges and rollers<br data-start="612" data-end="615">  ○ {oxen} pulled them on giant baskets</p>
<p data-start="674" data-end="749"> – geological:<br data-start="688" data-end="691">  ○ they were brought from Wales by {glaciers}</p>
<h3 data-start="751" data-end="763">Stage 3:</h3>
<p data-start="764" data-end="826">• sandstone slabs were arranged into an outer crescent or ring</p>
<p data-start="828" data-end="839"><span style="font-size: 12pt;"><strong>Builders</strong></span></p>
<p data-start="841" data-end="930">• a theory arose in the 17th century that its builders were Celtic {druids}</p>
<p data-start="932" data-end="942"><span style="font-size: 12pt;"><strong>Purpose</strong></span></p>
<p data-start="944" data-end="1100">• many experts agree it has been used as a {burial} site<br data-start="1014" data-end="1017">• in the 1960s, it was suggested that it worked as a kind of {calendar}</p>
</td>
</tr>
</tbody>
</table>
<p data-start="45" data-end="112"> </p>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', 'null', 0);
INSERT INTO public.questions VALUES ('c905c5e7-1b57-402e-9283-48aa6f74d556', 'cdff993e-886f-499a-8a5a-0a77c7abac27', 'radio', 'Questions 9–13', '', '<p>Choose <strong>TRUE </strong>if the statement agrees with the information,<strong>FALSE </strong>if the statement contradicts the information,<strong>NOT GIVEN </strong>if there is no information on this</p>', 'true_false_not_given', '[{"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "During the third phase of construction, sandstone slabs were placed in both the outer areas and the middle of the Stonehenge site"}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "There is scientific proof that the bluestones stood in the same spot until approximately 1600 BCE"}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "John Aubrey’s claim about Stonehenge was supported by 20th-century findings"}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Objects discovered at Stonehenge seem to indicate that it was constructed by a number of different groups of people"}, {"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Criticism of Gerald Hawkins’ theory about Stonehenge has come mainly from other astronomers"}]', 'null', 'null', 'null', 'null', 1);
INSERT INTO public.questions VALUES ('1540999d-7a5c-4a01-a54a-45e4c56986fc', 'c0feb6ca-b22b-4248-8f94-f248a4c20adf', 'radio', 'Questions 14–19', '', '<p data-start="20" data-end="64">Choose the correct letter, <strong>A</strong>, <strong>B</strong>, <strong>C </strong>or <strong>D</strong>.</p>', 'multiple_choice', '[{"correct": 2, "options": [{"option_text": "A. It is difficult to predict how quickly AI will progress"}, {"option_text": "B. Much can be learned about the use of AI in chess machines"}, {"option_text": "C. The future is unlikely to see limitations on the capabilities of AI"}, {"option_text": "D. Experts disagree on which specialised tasks AI will be able to perform"}], "question": "What point does the writer make about AI in the first paragraph?"}, {"correct": 0, "options": [{"option_text": "A. explaining why machines will be able to outperform humans"}, {"option_text": "B. describing the characteristics that humans and machines share"}, {"option_text": "C. giving information about the development of machine intelligence"}, {"option_text": "D. indicating which aspects of humans are the most advanced"}], "question": "What is the writer doing in the second paragraph?"}, {"correct": 1, "options": [{"option_text": "A. to compare different visions of progress"}, {"option_text": "B. to illustrate that poorly defined objectives can go wrong"}, {"option_text": "C. to emphasise the need for cooperation"}, {"option_text": "D. to point out the financial advantages of a course of action"}], "question": "Why does the writer mention the story of King Midas?"}, {"correct": 3, "options": [{"option_text": "A. encouraging humans to behave in a more principled way"}, {"option_text": "B. deciding which values we want AI to share with us"}, {"option_text": "C. creating a better world for all creatures on the planet"}, {"option_text": "D. ensuring AI is more human-friendly than we are ourselves"}], "question": "What challenge does the writer refer to in the fourth paragraph?"}, {"correct": 2, "options": [{"option_text": "A. The safety of machines will become a key issue"}, {"option_text": "B. It is hard to know what impact machines will have on the world"}, {"option_text": "C. Machines will be superior to humans in certain respects"}, {"option_text": "D. Many humans will oppose machines having a wider role"}], "question": "What does the writer suggest about the future in the fifth paragraph?"}, {"correct": 3, "options": [{"option_text": "A. More intelligent machines will result in greater abuses of power"}, {"option_text": "B. Machine learning will share very few features with human learning"}, {"option_text": "C. There are a limited number of people with the knowledge to program machines"}, {"option_text": "D. Human shortcomings will make creating the machines we need more difficult"}], "question": "Which of the following best summarises the writer’s argument in the sixth paragraph?"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">14. C — The future is unlikely to see limitations on the capabilities of AI.</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"5,0,0\" data-index-in-node=\"26\">“But many experts believe this restriction is very temporary.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi hỏi về luận điểm của tác giả đối với AI ở đoạn 1. Bài viết chỉ ra rằng những thành tựu kinh ngạc hiện tại mới chỉ nằm ở AI hẹp (<em data-path-to-node=\"5,1,0\" data-index-in-node=\"148\">narrow AI</em>), nhưng các chuyên gia tin rằng sự hạn chế này chỉ là rất tạm thời (<em data-path-to-node=\"5,1,0\" data-index-in-node=\"226\">restriction is very temporary</em>), và tương lai sẽ tiến tới AI tổng hợp (AGI) đạt trình độ như con người. Điều này có nghĩa là tương lai khó mà thấy được những giới hạn kiểm soát năng lực của AI (<strong data-path-to-node=\"5,1,0\" data-index-in-node=\"419\">unlikely to see limitations</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">15. A — explaining why machines will be able to outperform humans</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"7,0,0\" data-index-in-node=\"26\">“Machines will be free of many of the physical constraints on human intelligence.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Trong đoạn 2, tác giả liệt kê các rào cản vật lý của con người: não chạy bằng tốc độ hóa sinh chậm chạp, kích thước bị giới hạn bởi đường sinh sản của người mẹ. Ngược lại, máy tính sẽ giải phóng được các giới hạn này (<em data-path-to-node=\"7,1,0\" data-index-in-node=\"230\">free of many of the physical constraints</em>). Vì vậy, mục đích của đoạn này là giải thích tại sao máy móc có thể vượt trội hơn con người (<strong data-path-to-node=\"7,1,0\" data-index-in-node=\"365\">outperform humans</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">16. B — to illustrate that poorly defined objectives can go wrong</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"9,0,0\" data-index-in-node=\"26\">“But the more powerful AI becomes, the more important it will be to specify its goals with great care.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Tác giả mượn câu chuyện Vua Midas ước mọi thứ chạm vào hóa vàng nhưng không hề muốn điều đó áp dụng cho bữa sáng của mình để làm ví dụ minh họa (<em data-path-to-node=\"9,1,0\" data-index-in-node=\"157\">to illustrate</em>). Câu chuyện này nhấn mạnh rằng nếu mục tiêu không được xác định rõ ràng, kỹ lưỡng (<em data-path-to-node=\"9,1,0\" data-index-in-node=\"255\">specify its goals with great care</em>) thì hậu quả sẽ vô cùng thảm khốc, tức là các mục tiêu mơ hồ, kém chuẩn xác có thể đi sai hướng (<strong data-path-to-node=\"9,1,0\" data-index-in-node=\"386\">poorly defined objectives can go wrong</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">17. D — ensuring AI is more human-friendly than we are ourselves</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"11,0,0\" data-index-in-node=\"26\">“If superintelligent machines don’t do a lot better than us, we’ll be in deep trouble.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Ở đoạn 4, tác giả chỉ ra thách thức là con người chúng ta vốn dĩ chưa thực sự thân thiện và còn làm nhiều điều tồi tệ với nhau. Do đó, nếu các cỗ máy siêu thông minh không làm tốt hơn hẳn chúng ta (<em data-path-to-node=\"11,1,0\" data-index-in-node=\"210\">do a lot better than us</em>), chúng sẽ khuếch đại những mặt tối của con người. Thách thức ở đây là phải đảm bảo AI thân thiện và đạo đức hơn chính bản thân chúng ta (<strong data-path-to-node=\"11,1,0\" data-index-in-node=\"372\">ensuring AI is more human-friendly than we are ourselves</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">18. C — Machines will be superior to humans in certain respects.</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"13,0,0\" data-index-in-node=\"26\">“For safety’s sake, then, we want the machines to be ethically as well as cognitively superhuman.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Ở đoạn 5, tác giả gợi ý về tương lai rằng chúng ta muốn máy móc phải đạt tới ngưỡng \"siêu nhân\" cả về mặt nhận thức lẫn đạo đức (<em data-path-to-node=\"13,1,0\" data-index-in-node=\"141\">ethically as well as cognitively superhuman</em>). Trạng thái \"superhuman\" (siêu nhân) này tương ứng với việc máy móc sẽ vượt trội hơn con người ở một số khía cạnh nhất định (<strong data-path-to-node=\"13,1,0\" data-index-in-node=\"311\">superior to humans in certain respects</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">19. D — Human shortcomings will make creating the machines we need more difficult.</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"15,0,0\" data-index-in-node=\"26\">“This won’t be easy, given that we are tribal creatures and conflicted about our ideals ourselves.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn 6 nói về bài toán \"khởi đầu\" (<em data-path-to-node=\"15,1,0\" data-index-in-node=\"47\">getting started</em>): để cài đặt cho máy, chúng ta phải nói cho chúng biết rõ về giá trị đạo đức cần tìm. Tuy nhiên việc này không dễ dàng (<em data-path-to-node=\"15,1,0\" data-index-in-node=\"183\">won''t be easy</em>) bởi chính con người là những sinh vật có tính bộ tộc và luôn mâu thuẫn về các lý tưởng của chính mình. Những thiếu sót, hạn chế này của con người (<strong data-path-to-node=\"15,1,0\" data-index-in-node=\"345\">Human shortcomings</strong>) khiến việc tạo ra chiếc máy chúng ta cần trở nên khó khăn hơn.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('9fa2a28b-1593-4554-99a3-a8beca6473ad', 'c0feb6ca-b22b-4248-8f94-f248a4c20adf', 'radio', 'Questions 20–23', '', '<p>Choose <strong data-start="2299" data-end="2306">YES</strong> – if the statement agrees with the claims of the writer, <strong data-start="2365" data-end="2371">NO</strong> – if the statement contradicts the claims of the writer, <strong data-start="2430" data-end="2443">NOT GIVEN</strong> – if it is impossible to say what the writer thinks about this</p>', 'yes_no_not_given', '[{"correct": 0, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Machines with the ability to make moral decisions may prevent us from promoting the interests of our communities"}, {"correct": 2, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Silicon police would need to exist in large numbers in order to be effective"}, {"correct": 1, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "Many people are comfortable with the prospect of their independence being restricted by machines"}, {"correct": 0, "options": [{"option_text": "YES"}, {"option_text": "NO"}, {"option_text": "NOT GIVEN"}], "question": "If we want to ensure machines act in our best interests, we all need to work together"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"18\"><strong data-path-to-node=\"18\" data-index-in-node=\"0\">20. YES</strong></p>\n<ul data-path-to-node=\"19\">\n<li>\n<p data-path-to-node=\"19,0,0\"><strong data-path-to-node=\"19,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"19,0,0\" data-index-in-node=\"26\">“We might lose our freedom to discriminate in favour of our own communities, for example.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"19,1,0\"><strong data-path-to-node=\"19,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi nói các cỗ máy có năng lực đưa ra quyết định đạo đức có thể ngăn cản chúng ta thúc đẩy lợi ích cục bộ của cộng đồng mình (<em data-path-to-node=\"19,1,0\" data-index-in-node=\"142\">prevent us from promoting the interests of our communities</em>). Điều này hoàn toàn trùng khớp với cảnh báo của tác giả ở đoạn 7: chúng ta có thể mất đi quyền tự do phân biệt đối xử để thiên vị cho cộng đồng riêng của mình (<strong data-path-to-node=\"19,1,0\" data-index-in-node=\"362\">lose our freedom to discriminate in favour of our own communities</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">21. NOT GIVEN</strong></p>\n<ul data-path-to-node=\"21\">\n<li>\n<p data-path-to-node=\"21,0,0\"><strong data-path-to-node=\"21,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"21,0,0\" data-index-in-node=\"26\">“But are we ready for ethical silicon police limiting our options?”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"21,1,0\"><strong data-path-to-node=\"21,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc có dùng hình ảnh ẩn dụ \"cảnh sát silicon\" (<em data-path-to-node=\"21,1,0\" data-index-in-node=\"63\">silicon police</em>) để nói về việc máy tính giám sát các lựa chọn đạo đức của con người ở đoạn 8, nhưng trong toàn bộ bài viết <strong data-path-to-node=\"21,1,0\" data-index-in-node=\"186\">không hề có thông tin</strong> nào nói về việc lực lượng cảnh sát này có cần phải tồn tại với số lượng lớn (<em data-path-to-node=\"21,1,0\" data-index-in-node=\"285\">exist in large numbers</em>) thì mới hiệu quả hay không.</p>\n</li>\n</ul>\n<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">22. NO</strong></p>\n<ul data-path-to-node=\"23\">\n<li>\n<p data-path-to-node=\"23,0,0\"><strong data-path-to-node=\"23,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"23,0,0\" data-index-in-node=\"26\">“...but few of us are likely to welcome such a future.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"23,1,0\"><strong data-path-to-node=\"23,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi khẳng định nhiều người cảm thấy thoải mái/sẵn sàng với viễn cảnh sự độc lập của họ bị máy móc hạn chế (<em data-path-to-node=\"23,1,0\" data-index-in-node=\"123\">comfortable with the prospect...</em>). Ngược lại, đoạn 8 khẳng định rất ít người trong chúng ta sẵn lòng chào đón một tương lai bị kiểm soát như vậy (<strong data-path-to-node=\"23,1,0\" data-index-in-node=\"269\">few of us are likely to welcome such a future</strong>). Thông tin mâu thuẫn trực tiếp nên đáp án là <strong data-path-to-node=\"23,1,0\" data-index-in-node=\"361\">NO</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">23. YES</strong></p>\n<ul data-path-to-node=\"25\">\n<li>\n<p data-path-to-node=\"25,0,0\"><strong data-path-to-node=\"25,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"25,0,0\" data-index-in-node=\"26\">“It is not yet clear whether this is possible, but if it is, it will require a cooperative spirit, and a willingness to set aside self-interest.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"25,1,0\"><strong data-path-to-node=\"25,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Để đảm bảo các nhà tư tưởng mới (AI) hành động tốt vì lợi ích của chúng ta, tác giả khẳng định việc này đòi hỏi một tinh thần hợp tác (<em data-path-to-node=\"25,1,0\" data-index-in-node=\"147\">require a cooperative spirit</em>) và sự sẵn lòng gạt bỏ lợi ích cá nhân sang một bên. Tinh thần hợp tác này tương ứng hoàn toàn với việc mọi người cần phải làm việc cùng nhau (<strong data-path-to-node=\"25,1,0\" data-index-in-node=\"319\">we all need to work together</strong>).</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('f48fb85b-7f9c-4d42-8e5b-034922acc8e2', 'c0feb6ca-b22b-4248-8f94-f248a4c20adf', 'matching', 'Questions 24–26', '', '<p data-start="2946" data-end="3009">Complete the summary using the list of phrases, <strong>A</strong>–<strong>F</strong>, below.</p>
<p data-start="3011" data-end="3082">Write the correct letter, <strong>A</strong>–<strong>F</strong></p>', 'summary_completion', 'null', 'null', '{"layoutType": "summary", "summaryText": "<h3 data-section-id=\"1pxib5\" data-start=\"3084\" data-end=\"3120\">Using AI in the UK health system</h3>\n<p data-start=\"3122\" data-end=\"3576\">AI currently has a limited role in the way {C. available resources} are allocated in the health service. The positive aspect of AI having a bigger role is that it would be more efficient and lead to patient benefits. However, such a change would result, for example, in certain {A. medical practitioners} not having their current level of {E. professional authority}. It is therefore important that AI goals are appropriate so that discriminatory practices could be avoided.</p>", "answerOptions": [{"optionText": "A. medical practitioners"}, {"optionText": "B. specialised tasks"}, {"optionText": "C. available resources"}, {"optionText": "D. reduced illness"}, {"optionText": "E. professional authority"}, {"optionText": "F. technology experts"}], "matchingItems": []}', 'null', '[{"content": "<p data-path-to-node=\"28\"><strong data-path-to-node=\"28\" data-index-in-node=\"0\">24. C (available resources) — {...in the way available resources are allocated...}</strong></p>\n<ul data-path-to-node=\"29\">\n<li>\n<p data-path-to-node=\"29,0,0\"><strong data-path-to-node=\"29,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"29,0,0\" data-index-in-node=\"26\">“AI already has some input into how resources are used in our National Health Service (NHS) here in the UK, for example.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"29,1,0\"><strong data-path-to-node=\"29,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đoạn văn tóm tắt viết AI có vai trò hạn chế trong cách cái gì đó được phân bổ (<em data-path-to-node=\"29,1,0\" data-index-in-node=\"91\">allocated</em>). Bài đọc chỉ ra AI có đóng góp vào cách mà các nguồn lực được sử dụng (<em data-path-to-node=\"29,1,0\" data-index-in-node=\"173\">how resources are used / resources are allocated</em>). Từ đồng nghĩa phù hợp trong bảng từ là <strong data-path-to-node=\"29,1,0\" data-index-in-node=\"263\">available resources</strong> (phương án C).</p>\n</li>\n</ul>\n<p data-path-to-node=\"30\"><strong data-path-to-node=\"30\" data-index-in-node=\"0\">25. A (medical practitioners) — {...in certain medical practitioners not having...}</strong></p>\n<ul data-path-to-node=\"31\">\n<li>\n<p data-path-to-node=\"31,0,0\"><strong data-path-to-node=\"31,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"31,0,0\" data-index-in-node=\"26\">“However, we’d be depriving some humans (e.g. senior doctors) of the control they presently enjoy.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"31,1,0\"><strong data-path-to-node=\"31,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Sự thay đổi này sẽ dẫn tới việc một số đối tượng cụ thể bị tước đi quyền kiểm soát. Bài đọc chỉ đích danh đối tượng này là các bác sĩ lâu năm (<em data-path-to-node=\"31,1,0\" data-index-in-node=\"155\">senior doctors</em>). Từ khái quát đại diện cho nhóm này trong bảng từ là <strong data-path-to-node=\"31,1,0\" data-index-in-node=\"224\">medical practitioners</strong> (nhân viên y tế / bác sĩ - phương án A).</p>\n</li>\n</ul>\n<p data-path-to-node=\"32\"><strong data-path-to-node=\"32\" data-index-in-node=\"0\">26. E (professional authority) — {...their current level of professional authority.}</strong></p>\n<ul data-path-to-node=\"33\">\n<li>\n<p data-path-to-node=\"33,0,0\"><strong data-path-to-node=\"33,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> &gt; <em data-path-to-node=\"33,0,0\" data-index-in-node=\"26\">“However, we’d be depriving some humans (e.g. senior doctors) of the control they presently enjoy.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"33,1,0\"><strong data-path-to-node=\"33,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Việc các bác sĩ bị mất đi quyền kiểm soát mà họ đang tận hưởng (<em data-path-to-node=\"33,1,0\" data-index-in-node=\"76\">control they presently enjoy</em>) tương ứng với việc họ không còn giữ được mức độ quyền lực chuyên môn như hiện tại nữa (<strong data-path-to-node=\"33,1,0\" data-index-in-node=\"193\">professional authority</strong> - phương án E).</p>\n</li>\n</ul>"}]', 2);
INSERT INTO public.questions VALUES ('ed5a1f5c-dd1c-4644-863f-a10f6944a4ea', '33ed1878-5748-4a41-8a68-970e8d200cc7', 'radio', 'Questions 27–33', '', '<p>Choose <strong data-start="152" data-end="160">TRUE</strong> if the statement agrees with the information, <strong data-start="208" data-end="217">FALSE</strong> if the statement contradicts the information, <strong data-start="265" data-end="278">NOT GIVEN</strong> if there is no information on this</p>', 'true_false_not_given', '[{"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "People first referred to Leonardo da Vinci as a genius 500 years ago"}, {"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "The current climate crisis is predicted to cause more deaths than the plague"}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Some of the challenges we face today can be compared to those of earlier times"}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Leonardo da Vinci’s ideal city was constructed in the 15th century"}, {"correct": 0, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Poor town planning is a major contributor to climate change"}, {"correct": 2, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "In Renaissance times, local people fought against the changes to Pienza and Ferrara"}, {"correct": 1, "options": [{"option_text": "TRUE"}, {"option_text": "FALSE"}, {"option_text": "NOT GIVEN"}], "question": "Leonardo da Vinci kept a neat, organised record of his designs"}]', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"4\"><strong data-path-to-node=\"4\" data-index-in-node=\"0\">27. NOT GIVEN</strong></p>\n<ul data-path-to-node=\"5\">\n<li>\n<p data-path-to-node=\"5,0,0\"><strong data-path-to-node=\"5,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> <em data-path-to-node=\"5,0,0\" data-index-in-node=\"24\">“The word ‘genius’ is universally associated with the name of Leonardo da Vinci... Five hundred years have passed since Leonardo died in his home...”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"5,1,0\"><strong data-path-to-node=\"5,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ nêu thông tin từ \"thiên tài\" được gắn liền phổ biến với tên tuổi của ông, và ông đã qua đời cách đây 500 năm. Văn bản <strong data-path-to-node=\"5,1,0\" data-index-in-node=\"142\">hoàn toàn không đề cập</strong> đến việc có phải con người <em data-path-to-node=\"5,1,0\" data-index-in-node=\"192\">lần đầu tiên</em> gọi ông là thiên tài vào đúng 500 năm trước (<em data-path-to-node=\"5,1,0\" data-index-in-node=\"250\">first referred... 500 years ago</em>) hay không.</p>\n</li>\n</ul>\n<p data-path-to-node=\"6\"><strong data-path-to-node=\"6\" data-index-in-node=\"0\">28. NOT GIVEN</strong></p>\n<ul data-path-to-node=\"7\">\n<li>\n<p data-path-to-node=\"7,0,0\"><strong data-path-to-node=\"7,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> <em data-path-to-node=\"7,0,0\" data-index-in-node=\"24\">“Today, the world is on the cusp of a climate crisis, which is predicted to cause widespread displacement, extinctions and death, if left unaddressed.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"7,1,0\"><strong data-path-to-node=\"7,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc có nhắc đến dịch bệnh trong quá khứ làm chết 200 triệu người và dự báo cuộc khủng hoảng khí hậu hiện tại sẽ gây ra chết chóc, tuyệt chủng. Tuy nhiên, bài viết <strong data-path-to-node=\"7,1,0\" data-index-in-node=\"179\">hoàn toàn không có sự so sánh</strong> xem biến đổi khí hậu được dự báo sẽ gây ra <em data-path-to-node=\"7,1,0\" data-index-in-node=\"252\">nhiều cái chết hơn</em> (<em data-path-to-node=\"7,1,0\" data-index-in-node=\"272\">cause more deaths</em>) dịch bệnh hay không.</p>\n</li>\n</ul>\n<p data-path-to-node=\"8\"><strong data-path-to-node=\"8\" data-index-in-node=\"0\">29. TRUE</strong></p>\n<ul data-path-to-node=\"9\">\n<li>\n<p data-path-to-node=\"9,0,0\"><strong data-path-to-node=\"9,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> <em data-path-to-node=\"9,0,0\" data-index-in-node=\"24\">“Then, as now, radical solutions were called for to revolutionise the way people lived and safeguard humanity against catastrophe.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"9,1,0\"><strong data-path-to-node=\"9,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi nói một số thách thức chúng ta đối mặt ngày nay có thể so sánh với thời kỳ trước (<em data-path-to-node=\"9,1,0\" data-index-in-node=\"102\">compared to those of earlier times</em>). Từ khóa \"Then, as now\" (Quá khứ cũng như hiện tại) trong bài đọc khẳng định trực tiếp sự tương đồng giữa hai thời kỳ khi cả hai đều cần đến các giải pháp triệt để nhằm bảo vệ nhân loại trước thảm họa.</p>\n</li>\n</ul>\n<p data-path-to-node=\"10\"><strong data-path-to-node=\"10\" data-index-in-node=\"0\">30. FALSE</strong></p>\n<ul data-path-to-node=\"11\">\n<li>\n<p data-path-to-node=\"11,0,0\"><strong data-path-to-node=\"11,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> <em data-path-to-node=\"11,0,0\" data-index-in-node=\"24\">“Following a typical Renaissance trend, he began to work on an ‘ideal city’ project, which – due to its excessive costs – would remain unfulfilled.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"11,1,0\"><strong data-path-to-node=\"11,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi khẳng định thành phố lý tưởng của Leonardo đã được xây dựng/thi công vào thế kỷ 15 (<em data-path-to-node=\"11,1,0\" data-index-in-node=\"104\">was constructed</em>). Ngược lại, bài đọc viết rõ dự án này \"remain unfulfilled\" (vẫn mãi không được thực hiện/không được hoàn thành) vì chi phí quá đắt đỏ. Thông tin mâu thuẫn trực tiếp nên chọn <strong data-path-to-node=\"11,1,0\" data-index-in-node=\"295\">FALSE</strong>.</p>\n</li>\n</ul>\n<p data-path-to-node=\"12\"><strong data-path-to-node=\"12\" data-index-in-node=\"0\">31. TRUE</strong></p>\n<ul data-path-to-node=\"13\">\n<li>\n<p data-path-to-node=\"13,0,0\"><strong data-path-to-node=\"13,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> <em data-path-to-node=\"13,0,0\" data-index-in-node=\"24\">“Yet given that unsustainable urban models are a key cause of global climate change today...”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"13,1,0\"><strong data-path-to-node=\"13,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi nói quy hoạch thị trấn kém (<em data-path-to-node=\"13,1,0\" data-index-in-node=\"48\">Poor town planning</em>) là tác nhân chính gây ra biến đổi khí hậu. Điều này trùng khớp hoàn toàn với bài đọc: các mô hình đô thị thiếu bền vững (<em data-path-to-node=\"13,1,0\" data-index-in-node=\"189\">unsustainable urban models</em>) chính là nguyên nhân cốt lõi (<em data-path-to-node=\"13,1,0\" data-index-in-node=\"247\">a key cause</em>) dẫn đến biến đổi khí hậu toàn cầu ngày nay.</p>\n</li>\n</ul>\n<p data-path-to-node=\"14\"><strong data-path-to-node=\"14\" data-index-in-node=\"0\">32. NOT GIVEN</strong></p>\n<ul data-path-to-node=\"15\">\n<li>\n<p id=\"p-rc_3f8e6a1b19cfdbce-21\" data-path-to-node=\"15,0,0\"><strong data-path-to-node=\"15,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> <em data-path-to-node=\"15,0,0\" data-index-in-node=\"24\">“The rigour <span class=\"citation-131 citation-end-131\">and method behind the conscious conception of a city had been largely missing in Western thought until the moment when prominent Renaissance men pushed forward large-scale urban projects in Italy, such as the reconfiguration of the town of Pienza and the expansion of the city of Ferrara.”<sup class=\"superscript\" data-turn-source-index=\"1\"><!----></sup></span></em></p>\n<div class=\"source-inline-chip-container luminous-sources ng-star-inserted\"><button class=\"button multiple-button ng-star-inserted\" aria-label=\"View source details. Opens side panel.\"><!----><!----><!----><!----></button><!----><!----><!----><!----></div>\n<!----><!----><!----><!----><!----><!----><!----><!---->\n<p> </p>\n</li>\n<li>\n<p data-path-to-node=\"15,1,0\"><strong data-path-to-node=\"15,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Bài đọc chỉ đề cập đến việc các vĩ nhân thời Phục Hưng đã thúc đẩy các dự án đô thị quy mô lớn tại Pienza và Ferrara để làm nguồn cảm hứng cho Leonardo, chứ <strong data-path-to-node=\"15,1,0\" data-index-in-node=\"169\">hoàn toàn không có thông tin</strong> về việc người dân địa phương lúc đó có phản đối hay chiến đấu chống lại (<em data-path-to-node=\"15,1,0\" data-index-in-node=\"271\">fought against</em>) những thay đổi này hay không.</p>\n</li>\n</ul>\n<p data-path-to-node=\"16\"><strong data-path-to-node=\"16\" data-index-in-node=\"0\">33. FALSE</strong></p>\n<ul data-path-to-node=\"17\">\n<li>\n<p data-path-to-node=\"17,0,0\"><strong data-path-to-node=\"17,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> <em data-path-to-node=\"17,0,0\" data-index-in-node=\"24\">“It is not easy to identify a coordination of Leonardo’s ideal city because of his disordered way of working with notes and sketches.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"17,1,0\"><strong data-path-to-node=\"17,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu hỏi nói Leonardo da Vinci ghi chép các thiết kế của mình một cách gọn gàng, ngăn nắp (<em data-path-to-node=\"17,1,0\" data-index-in-node=\"102\">neat, organised record</em>). Ngược lại, bài đọc khẳng định ông có cách làm việc rất bừa bãi, lộn xộn (<strong data-path-to-node=\"17,1,0\" data-index-in-node=\"200\">disordered way of working</strong>) với các ghi chú và bản phác thảo, khiến việc xác định các sơ đồ không hề dễ dàng. Thông tin bị trái ngược hoàn toàn nên chọn <strong data-path-to-node=\"17,1,0\" data-index-in-node=\"352\">FALSE</strong>.</p>\n</li>\n</ul>"}]', 0);
INSERT INTO public.questions VALUES ('42b0e01b-b025-4de4-a8a3-5cb8b9d3d6ed', '33ed1878-5748-4a41-8a68-970e8d200cc7', 'fillup', 'Questions 34–40', '<p data-start="902" data-end="929">Complete the summary below.</p>
<p data-start="931" data-end="989">Choose <strong>ONE WORD ONLY</strong> from the passage for each answer.</p>
<table style="border-collapse: collapse; width: 99.9592%; border: 1px solid #000000;" border="1"><colgroup><col style="width: 99.8776%;"></colgroup>
<tbody>
<tr>
<td style="border-color: #000000;">
<div class="text-base my-auto mx-auto [--thread-content-margin:var(--thread-content-margin-xs,calc(var(--spacing)*4))] @w-sm/main:[--thread-content-margin:var(--thread-content-margin-sm,calc(var(--spacing)*6))] @w-lg/main:[--thread-content-margin:var(--thread-content-margin-lg,calc(var(--spacing)*16))] px-(--thread-content-margin)">
<div class="[--thread-content-max-width:40rem] @w-lg/main:[--thread-content-max-width:48rem] mx-auto max-w-(--thread-content-max-width) flex-1 group/turn-messages focus-visible:outline-hidden relative flex w-full min-w-0 flex-col agent-turn">
<div class="flex max-w-full flex-col gap-4 grow">
<div class="min-h-8 text-message relative flex w-full flex-col items-end gap-2 text-start break-words whitespace-normal outline-none keyboard-focused:focus-ring [.text-message+&amp;]:mt-1" dir="auto" data-message-author-role="assistant" data-message-id="47e2ea8c-e174-4a4a-b30b-9297c47b97d9" data-message-model-slug="gpt-5-5">
<div class="flex w-full flex-col gap-1 empty:hidden">
<div class="markdown prose dark:prose-invert wrap-break-word w-full light markdown-new-styling">
<p style="text-align: left;" data-section-id="12o1u00" data-start="1052" data-end="1086"><span style="font-size: 14pt;"><strong>Leonardo da Vinci’s ideal city</strong></span></p>
<p style="text-align: left;" data-section-id="12o1u00" data-start="1052" data-end="1086">A collection of Leonardo da Vinci’s paperwork reveals his design of a new city beside the Ticino River. This was to provide better {transport} for trade and a less polluted environment. Although Leonardo da Vinci’s city shared many of the ideals of his time, some of his innovations were considered unconventional in their design. They included features that can be seen in some tower blocks today, such as {staircases} on the exterior of a building.</p>
<p data-start="1551" data-end="1883">Leonardo da Vinci wasn’t only an architect. His expertise in {engineering} was evident in his plans for artificial canals within his ideal city. He also believed that the height of houses should relate to the width of streets in case earthquakes occurred. The design of many cities in Italy today follows this {rule}.</p>
<p data-start="1885" data-end="2297" data-is-last-node="" data-is-only-node="">While some cities from {Roman} times have aspects that can also be found in Leonardo’s designs, his ideas weren’t put into practice until long after his death. {Paris} is one example of a city that was redesigned in the 19th century in the way that Leonardo had envisaged. His ideas are also relevant to today’s world, where building {outwards} no longer seems to be the best approach.</p>
</div>
</div>
</div>
</div>
<div class="z-0 flex min-h-[46px] justify-start"> </div>
</div>
</div>
</td>
</tr>
</tbody>
</table>
<p data-start="931" data-end="989"> </p>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p data-path-to-node=\"20\"><strong data-path-to-node=\"20\" data-index-in-node=\"0\">34. transport — {...provide better transport for trade...}</strong></p>\n<ul data-path-to-node=\"21\">\n<li>\n<p data-path-to-node=\"21,0,0\"><strong data-path-to-node=\"21,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> <em data-path-to-node=\"21,0,0\" data-index-in-node=\"24\">“The designed city for the easy transport of goods and clean urban spaces, and he wanted a comfortable and spacious city...”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"21,1,0\"><strong data-path-to-node=\"21,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Thành phố được thiết kế dọc sông Ticino nhằm mục đích phục vụ cho việc vận chuyển hàng hóa dễ dàng (<em data-path-to-node=\"21,1,0\" data-index-in-node=\"112\">easy transport of goods</em>), tức là cung cấp hệ thống giao thông vận tải tốt hơn (<strong data-path-to-node=\"21,1,0\" data-index-in-node=\"191\">transport</strong>) cho giao thương buôn bán.</p>\n</li>\n</ul>\n<p data-path-to-node=\"22\"><strong data-path-to-node=\"22\" data-index-in-node=\"0\">35. staircases — {...such as staircases on the exterior of a building.}</strong></p>\n<ul data-path-to-node=\"23\">\n<li>\n<p data-path-to-node=\"23,0,0\"><strong data-path-to-node=\"23,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> <em data-path-to-node=\"23,0,0\" data-index-in-node=\"24\">“Leonardo wanted the city to be built on several levels, linked with vertical outdoor staircases.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"23,1,0\"><strong data-path-to-node=\"23,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Cụm từ \"on the exterior of a building\" (ở bên ngoài tòa nhà) đồng nghĩa với tính từ \"outdoor\" (ngoài trời). Đặc điểm cải tiến xuất hiện ở bên ngoài các tòa nhà dạng tháp ngày nay chính là những hệ thống cầu thang (<strong data-path-to-node=\"23,1,0\" data-index-in-node=\"226\">staircases</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"24\"><strong data-path-to-node=\"24\" data-index-in-node=\"0\">36. engineering — {His expertise in engineering was evident...}</strong></p>\n<ul data-path-to-node=\"25\">\n<li>\n<p data-path-to-node=\"25,0,0\"><strong data-path-to-node=\"25,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> <em data-path-to-node=\"25,0,0\" data-index-in-node=\"24\">“But the true originality of Leonardo’s vision was its fusion of architecture and engineering.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"25,1,0\"><strong data-path-to-node=\"25,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Câu tóm tắt cần một danh từ chỉ lĩnh vực chuyên môn của Leonardo ngoài kiến trúc, được thể hiện qua các kế hoạch thủy lực làm kênh nhân tạo. Bài đọc viết tầm nhìn của ông là sự kết hợp giữa kiến trúc (<em data-path-to-node=\"25,1,0\" data-index-in-node=\"213\">architecture</em>) và kỹ thuật (<strong data-path-to-node=\"25,1,0\" data-index-in-node=\"240\">engineering</strong>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"26\"><strong data-path-to-node=\"26\" data-index-in-node=\"0\">37. rule — {The design of many cities in Italy today follows this rule.}</strong></p>\n<ul data-path-to-node=\"27\">\n<li>\n<p data-path-to-node=\"27,0,0\"><strong data-path-to-node=\"27,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> <em data-path-to-node=\"27,0,0\" data-index-in-node=\"24\">“Leonardo also thought that the width of the streets ought to match the average height of the adjacent houses: a rule still followed in many contemporary cities across Italy...”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"27,1,0\"><strong data-path-to-node=\"27,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Quy định về tỷ lệ giữa chiều rộng đường phố và chiều cao nhà ở để giảm thiểu thiệt hại động đất là một quy tắc (<strong data-path-to-node=\"27,1,0\" data-index-in-node=\"124\">rule</strong>) mà đến nay nhiều thành phố đương đại ở Ý vẫn đang tuân theo (<em data-path-to-node=\"27,1,0\" data-index-in-node=\"191\">still followed</em>).</p>\n</li>\n</ul>\n<p data-path-to-node=\"28\"><strong data-path-to-node=\"28\" data-index-in-node=\"0\">38. Roman — {While some cities from Roman times have aspects...}</strong></p>\n<ul data-path-to-node=\"29\">\n<li>\n<p data-path-to-node=\"29,0,0\"><strong data-path-to-node=\"29,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> <em data-path-to-node=\"29,0,0\" data-index-in-node=\"24\">“Although some of these features existed in Roman cities, before Leonardo’s drawings there had never been a multi-level, compact modern city...”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"29,1,0\"><strong data-path-to-node=\"29,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Từ \"times\" (thời kỳ/thời đại) trong câu hỏi kết hợp với tính từ cần điền tương ứng với cụm từ các thành phố thời La Mã (<strong data-path-to-node=\"29,1,0\" data-index-in-node=\"132\">Roman</strong> <em data-path-to-node=\"29,1,0\" data-index-in-node=\"138\">cities</em>) trong bài đọc.</p>\n</li>\n</ul>\n<p data-path-to-node=\"30\"><strong data-path-to-node=\"30\" data-index-in-node=\"0\">39. Paris — {Paris is one example of a city that was redesigned in the 19th century...}</strong></p>\n<ul data-path-to-node=\"31\">\n<li>\n<p data-path-to-node=\"31,0,0\"><strong data-path-to-node=\"31,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> <em data-path-to-node=\"31,0,0\" data-index-in-node=\"24\">“...is an idea that can be found in Georges-Eugène Haussmann’s renovation of Paris under Emperor Napoleon III between 1853 and 1870.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"31,1,0\"><strong data-path-to-node=\"31,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Thành phố được cải tạo, thiết kế lại vào thế kỷ 19 (<em data-path-to-node=\"31,1,0\" data-index-in-node=\"64\">renovation... between 1853 and 1870</em>) dựa trên các ý tưởng phân tầng chức năng của Leonardo chính là thủ đô <strong data-path-to-node=\"31,1,0\" data-index-in-node=\"171\">Paris</strong> của Pháp.</p>\n</li>\n</ul>\n<p data-path-to-node=\"32\"><strong data-path-to-node=\"32\" data-index-in-node=\"0\">40. outwards — {...where building outwards no longer seems to be the best approach.}</strong></p>\n<ul data-path-to-node=\"33\">\n<li>\n<p data-path-to-node=\"33,0,0\"><strong data-path-to-node=\"33,0,0\" data-index-in-node=\"0\">Dẫn chứng câu tốt nhất:</strong> <em data-path-to-node=\"33,0,0\" data-index-in-node=\"24\">“Many scholars think that the compact city, built upwards instead of outwards... could help modern cities become more efficient and sustainable.”</em></p>\n</li>\n<li>\n<p data-path-to-node=\"33,1,0\"><strong data-path-to-node=\"33,1,0\" data-index-in-node=\"0\">Giải thích:</strong> Đối với quy hoạch đô thị ngày nay, các chuyên gia tin rằng mô hình thành phố nén, xây dựng phát triển theo chiều cao (<em data-path-to-node=\"33,1,0\" data-index-in-node=\"130\">built upwards</em>) thay vì mở rộng diện tích theo chiều ngang (<strong data-path-to-node=\"33,1,0\" data-index-in-node=\"189\">outwards</strong>) mới là hướng đi bền vững. Do đó, việc xây dựng phát triển mở rộng ra bên ngoài không còn là phương án tốt nhất.</p>\n</li>\n</ul>"}]', 1);
INSERT INTO public.questions VALUES ('4cf02696-45af-4269-bb23-22db3b4d4b8b', '5b6759f5-54de-4ef5-8eb3-49eea466d24f', 'fillup', 'Questions 1–10', '<h3 data-start="52" data-end="69">Questions 1–5</h3>
<p data-start="71" data-end="96">Complete the notes below.</p>
<p data-start="98" data-end="138">Write <strong data-start="104" data-end="121">ONE WORD ONLY</strong> for each answer.</p>
<p data-start="140" data-end="171"><span style="font-size: 14pt;"><strong>Working at Milo’s Restaurants</strong></span></p>
<p data-start="173" data-end="184"><span style="font-size: 12pt;"><strong>Benefits</strong></span></p>
<p data-start="186" data-end="353">• {training} provided for all staff<br data-start="233" data-end="236">• {discount} during weekdays at all Milo’s Restaurants<br data-start="302" data-end="305">• {taxi} provided after midnight</p>
<p data-start="355" data-end="378"><span style="font-size: 12pt;"><strong>Person specification</strong></span></p>
<p data-start="380" data-end="551">• must be prepared to work well in a team<br data-start="421" data-end="424">• must care about maintaining a high standard of {service}<br data-start="495" data-end="498">• must have a qualification in {English}</p>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', 'null', 0);
