INSERT INTO public.questions VALUES ('00a17efd-399e-4ddf-ad69-e1cbd08d3d22', '9245ed59-49da-4a3f-845d-b295db748fb2', 'fillup', 'Questions 1–10', '<p data-path-to-node="4">Complete the notes below.</p>
<p data-path-to-node="5">Write <strong data-path-to-node="5" data-index-in-node="6">ONE WORD AND/OR A NUMBER</strong> for each answer.</p>
<table style="border-collapse: collapse; width: 99.9592%; height: 2px; border-spacing: 2px; border: 2px solid #000000;" border="1"><colgroup><col style="width: 99.8776%;"></colgroup>
<tbody>
<tr>
<td style="border-width: 2px; padding: 2px; border-color: #000000;">
<p style="text-align: left;" data-path-to-node="6"><span style="font-size: 14pt;"><strong>Hinchingbrooke Country Park</strong></span></p>
<p id="p-rc_8b481fd97cac63b5-515" data-path-to-node="7"><strong data-path-to-node="7" data-index-in-node="0">The park</strong></p>
<ul>
<li data-path-to-node="7">
<p>Area: {69|sixty-nine} hectares</p>
</li>
<li data-path-to-node="7">
<p>Habitats: wetland, grassland and woodland</p>
</li>
<li data-path-to-node="7">
<p>Wetland: lakes, ponds and a {cream}</p>
</li>
<li data-path-to-node="7">
<p><span class="citation-63774 citation-end-63774">Wildlife includes birds, insects and animals<sup class="superscript" data-turn-source-index="1"><!----></sup></span></p>
</li>
</ul>
<p class="source-inline-chip-container ng-star-inserted"><!----><!----></p>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>
<p id="p-rc_8b481fd97cac63b5-516" data-path-to-node="8"><strong data-path-to-node="8" data-index-in-node="0"><span class="citation-63773 citation-end-63773">Subjects studied in educational visits include<sup class="superscript" data-turn-source-index="2"><!----></sup></span></strong></p>
<ul>
<li data-path-to-node="8">
<p><span class="citation-63771 citation-63772">Science: Children look at {data}</span><span class="citation-63771 citation-63772 citation-end-63772"> about plants, etc.<sup class="superscript" data-turn-source-index="3"><!----></sup></span><span class="citation-63771 citation-end-63771"><sup class="superscript" data-turn-source-index="4"><!----></sup></span></p>
</li>
<li data-path-to-node="8">
<p><span class="citation-63769 citation-63770">Geography: includes learning to use a {map}</span><span class="citation-63769 citation-63770 citation-end-63770"> and compass<sup class="superscript" data-turn-source-index="5"><!----></sup></span><span class="citation-63769 citation-end-63769"><sup class="superscript" data-turn-source-index="6"><!----></sup></span></p>
</li>
<li data-path-to-node="8">
<p><span class="citation-63767 citation-63768 citation-end-63768">History: changes i<sup class="superscript" data-turn-source-index="7"><!----></sup></span><span class="citation-63767 citation-end-63767">n land use<sup class="superscript" data-turn-source-index="8"><!----></sup></span></p>
</li>
<li data-path-to-node="8">
<p><span class="citation-63766">Leisure and tourism: </span><span class="citation-63764 citation-63765 citation-63766">mostly concentrates on the park''s {visitors}</span></p>
</li>
<li data-path-to-node="8">
<p><span class="citation-63761 citation-63762 citation-63763">Music: Children make {sounds}</span><span class="citation-63761 citation-63762 citation-63763 citation-end-63763"> with natural materials, and experiment with rhythm and <sup class="superscript" data-turn-source-index="12"><!----></sup></span><span class="citation-63761 citation-63762 citation-end-63762">speed.<sup class="superscript" data-turn-source-index="13"><!----></sup></span><span class="citation-63761 citation-end-63761"><sup class="superscript" data-turn-source-index="14"><!----></sup></span></p>
</li>
</ul>
<p class="source-inline-chip-container ng-star-inserted"><!----><!----></p>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>
<p id="p-rc_8b481fd97cac63b5-517" data-path-to-node="9"><strong data-path-to-node="9" data-index-in-node="0"><span class="citation-63759 citation-63760 citation-end-63760">Benefits of outdoor educational visits<sup class="superscript" data-turn-source-index="15"><!----></sup></span><span class="citation-63759 citation-end-63759"><sup class="superscript" data-turn-source-index="16"><!----></sup></span></strong></p>
<ul>
<li data-path-to-node="9">
<p><span class="citation-63757 citation-63758">They give children a feeling of {freedom}</span><span class="citation-63757 citation-63758 citation-end-63758"> that they may not have elsewhere.<sup class="superscript" data-turn-source-index="17"><!----></sup></span><span class="citation-63757 citation-end-63757"><sup class="superscript" data-turn-source-index="18"><!----></sup></span></p>
</li>
<li data-path-to-node="9">
<p><span class="citation-63755 citation-63756 citation-end-63756">Children learn<sup class="superscript" data-turn-source-index="19"><!----></sup></span><span class="citation-63755"> new {skills}</span><span class="citation-63755 citation-end-63755"> and gain self-confidence.<sup class="superscript" data-turn-source-index="20"><!----></sup></span></p>
</li>
</ul>
<p class="source-inline-chip-container ng-star-inserted"><!----><!----></p>
<p><!----><!----><!----><!----><!----><!----><!----><!----></p>
<p data-path-to-node="10"><strong data-path-to-node="10" data-index-in-node="0">Practical issues</strong></p>
<ul>
<li data-path-to-node="10">
<p>Cost per child:  £ {4.95} </p>
</li>
<li data-path-to-node="10">
<p>Adults, such as {leaders} , free</p>
</li>
</ul>
</td>
</tr>
</tbody>
</table>
<p data-path-to-node="5"> </p>', NULL, 'summary_completion', 'null', 'null', 'null', 'null', '[{"content": "<p>1</p>"}]', 0);
INSERT INTO public.questions VALUES ('d384d2b3-d267-4991-9aa1-44e7145c6901', '1dc15091-ab94-4d1f-acbe-273cf45ed36b', 'checkbox', 'Questions 11 and 12', '', '<p data-start="51" data-end="75">Choose <strong>TWO </strong>letters, <strong>A</strong>–<strong>E</strong>.</p>
<p data-start="77" data-end="165">What are the <strong>TWO </strong>main reasons why this site has been chosen for the housing development?</p>', 'multiple_choice', 'null', '[{"correct": false, "option_text": "It has suitable geographical features"}, {"correct": true, "option_text": "It has suitable geographical features"}, {"correct": false, "option_text": "It has good connections with the airport"}, {"correct": false, "option_text": "The land is of little agricultural value"}, {"correct": true, "option_text": "It will be convenient for workers"}]', 'null', 'null', 'null', 0);
INSERT INTO public.questions VALUES ('29e32e11-12b7-4342-b2f0-1bd5b4cf876b', '1dc15091-ab94-4d1f-acbe-273cf45ed36b', 'checkbox', 'Questions 13 and 14', '', '<p data-start="415" data-end="439">Choose <strong>TWO </strong>letters, <strong>A</strong>–<strong>E</strong>.</p>
<p data-start="441" data-end="536">Which <strong>TWO</strong> aspects of the planned housing development have people given positive feedback about?</p>', 'multiple_choice', 'null', '[{"correct": false, "option_text": "the facilities for cyclists"}, {"correct": true, "option_text": "the impact on the environment"}, {"correct": true, "option_text": "the encouragement of good relations between residents"}, {"correct": false, "option_text": "the low cost of all the accommodation"}, {"correct": false, "option_text": "the rural location"}]', 'null', 'null', 'null', 1);
